@api_router.get("/predios/{predio_id}/construcciones")
async def get_construcciones_predio(predio_id: str, current_user: dict = Depends(get_current_user)):
    """Obtiene las construcciones asociadas a un predio"""
    if current_user['role'] == UserRole.USUARIO:
        raise HTTPException(status_code=403, detail="No tiene permiso")
    
    # Obtener el predio para conocer su código
    predio = await db.predios.find_one({"id": predio_id, "deleted": {"$ne": True}}, {"_id": 0, "codigo_predial_nacional": 1, "codigo_gdb": 1})
    if not predio:
        raise HTTPException(status_code=404, detail="Predio no encontrado")
    
    codigo = predio.get("codigo_gdb") or predio.get("codigo_predial_nacional")
    if not codigo:
        return {"construcciones": [], "total": 0}
    
    # Buscar construcciones con match flexible
    construcciones = await db.gdb_construcciones.find({
        "$or": [
            {"codigo_predio": codigo},
            {"codigo_predio": {"$regex": f"^{codigo[:20]}"}}  # Match por prefijo (20 dígitos)
        ]
    }, {"_id": 0}).to_list(100)
    
    return {
        "construcciones": construcciones,
        "total": len(construcciones)
    }


@api_router.get("/gdb/construcciones/{codigo_predio}")
async def get_construcciones_by_codigo(codigo_predio: str, current_user: dict = Depends(get_current_user)):
    """Obtiene las construcciones por código de predio - match EXACTO"""
    if current_user['role'] == UserRole.USUARIO:
        raise HTTPException(status_code=403, detail="No tiene permiso")
    
    # Buscar con match EXACTO solamente
    # El código de la construcción debe coincidir exactamente con el código del predio
    construcciones = await db.gdb_construcciones.find({
        "codigo_predio": codigo_predio
    }, {"_id": 0}).to_list(100)
    
    return {
        "construcciones": construcciones,
        "total": len(construcciones)
    }


@api_router.post("/predios")
async def create_predio(predio_data: PredioCreate, current_user: dict = Depends(get_current_user)):
    """Crea un nuevo predio"""
    # Usuario, Comunicaciones y Empresa no pueden crear predios
    if current_user['role'] in [UserRole.USUARIO, UserRole.COMUNICACIONES, UserRole.EMPRESA]:
        raise HTTPException(status_code=403, detail="No tiene permiso para crear predios")
    
    r1 = predio_data.r1
    r2 = predio_data.r2
    
    # Obtener siguiente número de terreno
    terreno, terreno_num = await get_next_terreno_number(
        r1.municipio, r1.zona, r1.sector, r1.manzana_vereda
    )
    
    # Generar código predial nacional
    codigo_predial = await generate_codigo_predial(
        r1.municipio, r1.zona, r1.sector, r1.manzana_vereda,
        terreno, r1.condicion_predio, r1.predio_horizontal
    )
    
    # Verificar que no exista
    existing = await db.predios.find_one({"codigo_predial_nacional": codigo_predial})
    if existing:
        raise HTTPException(status_code=400, detail="Ya existe un predio con este código predial")
    
    # Verificar que no sea un código eliminado
    eliminado = await db.predios_eliminados.find_one({"codigo_predial_nacional": codigo_predial})
    if eliminado:
        # Verificar si tiene aprobación de reaparición
        aprobacion = await db.predios_reapariciones_aprobadas.find_one({
            "codigo_predial_nacional": codigo_predial,
            "estado": "aprobado"
        })
        
        if not aprobacion:
            # Verificar si ya hay solicitud pendiente
            solicitud_pendiente = await db.predios_reapariciones_solicitudes.find_one({
                "codigo_predial_nacional": codigo_predial,
                "estado": "pendiente"
            })
            
            error_detail = {
                "error": "PREDIO_ELIMINADO",
                "mensaje": f"Este código predial fue ELIMINADO en vigencia {eliminado.get('vigencia_eliminacion')}",
                "codigo_predial": codigo_predial,
                "municipio": eliminado.get("municipio"),
                "vigencia_eliminacion": eliminado.get("vigencia_eliminacion"),
                "puede_solicitar_reaparicion": solicitud_pendiente is None,
                "tiene_solicitud_pendiente": solicitud_pendiente is not None,
                "instrucciones": "Use el endpoint /api/predios/reapariciones/solicitar para solicitar la reaparición con justificación técnica" if not solicitud_pendiente else "Ya existe una solicitud pendiente de aprobación"
            }
            raise HTTPException(status_code=400, detail=error_detail)
    
    # Generar código homologado - Primero intentar de la colección de códigos cargados
    codigo_homologado = await asignar_codigo_homologado(r1.municipio, None)  # Se actualizará con el ID real después
    
    if codigo_homologado:
        # Obtener el último número de predio para mantener secuencia
        last_predio = await db.predios.find_one(
            {"municipio": r1.municipio, "deleted": {"$ne": True}},
            sort=[("numero_predio", -1)]
        )
        if last_predio:
            num_predio = last_predio.get("numero_predio", 0)
            if isinstance(num_predio, str):
                try:
                    num_predio = int(num_predio)
                except (ValueError, TypeError):
                    num_predio = 0
            numero_predio = num_predio + 1
        else:
            numero_predio = 1
    else:
        # Fallback: generar código aleatorio si no hay códigos cargados
        codigo_homologado, numero_predio = await generate_codigo_homologado(r1.municipio)
    
    # Obtener código Código Nacional Catastral
    divipola = MUNICIPIOS_DIVIPOLA[r1.municipio]
    
    # Crear el predio
    predio = {
        "id": str(uuid.uuid4()),
        "departamento": divipola["departamento"],
        "municipio": r1.municipio,
        "municipio_codigo": divipola["municipio"],
        "numero_predio": numero_predio,
        "codigo_predial_nacional": codigo_predial,
        "codigo_homologado": codigo_homologado,
        "zona": r1.zona,
        "sector": r1.sector,
        "manzana_vereda": r1.manzana_vereda,
        "terreno": terreno,
        "terreno_num": terreno_num,
        "condicion_predio": r1.condicion_predio,
        "predio_horizontal": r1.predio_horizontal,
        
        # R1 - Información jurídica
        "tipo_registro": 1,
        "nombre_propietario": r1.nombre_propietario,
        "tipo_documento": r1.tipo_documento,
        "numero_documento": r1.numero_documento,
        "estado_civil": r1.estado_civil,
        "direccion": r1.direccion,
        "comuna": r1.comuna,
        "destino_economico": r1.destino_economico,
        "area_terreno": r1.area_terreno,
        "area_construida": r1.area_construida,
        "avaluo": r1.avaluo,
        "tipo_mutacion": r1.tipo_mutacion,
        "numero_resolucion": r1.numero_resolucion,
        "fecha_resolucion": r1.fecha_resolucion,
        
        # R2 - Información física (si se proporciona)
        "r2": r2.model_dump() if r2 else None,
        
        # Metadata
        "vigencia": datetime.now().strftime("%m%d%Y"),
        "created_by": current_user['id'],
        "created_by_name": current_user['full_name'],
        "created_at": datetime.now(COLOMBIA_TZ).isoformat(),
        "updated_at": datetime.now(COLOMBIA_TZ).isoformat(),
        "deleted": False,
        
        # Historial
        "historial": [{
            "accion": "Predio creado",
            "usuario": current_user['full_name'],
            "usuario_id": current_user['id'],
            "fecha": datetime.now(COLOMBIA_TZ).isoformat()
        }]
    }
    
    await db.predios.insert_one(predio)
    
    # Actualizar la asignación del código homologado con el ID real del predio
    if codigo_homologado:
        await db.codigos_homologados.update_one(
            {'codigo': codigo_homologado, 'municipio': r1.municipio},
            {'$set': {'predio_id': predio['id']}}
        )
    
    # Remover _id antes de retornar
    predio.pop("_id", None)
    
    # Broadcast WebSocket para sincronización en tiempo real
    await ws_manager.broadcast({
        "type": "predio_actualizado",
        "action": "create",
        "predio_id": predio['id'],
        "municipio": predio.get('municipio', ''),
        "codigo_predial": predio.get('codigo_predial_nacional', ''),
        "created_by": current_user['full_name'],
        "timestamp": datetime.now(COLOMBIA_TZ).isoformat()
    }, exclude_user=current_user['id'])
    
    return predio

@api_router.patch("/predios/{predio_id}")
async def update_predio(predio_id: str, update_data: PredioUpdate, current_user: dict = Depends(get_current_user)):
    """Actualiza un predio existente"""
    # Usuario, Comunicaciones y Empresa no pueden modificar predios directamente
    if current_user['role'] in [UserRole.USUARIO, UserRole.COMUNICACIONES, UserRole.EMPRESA]:
        raise HTTPException(status_code=403, detail="No tiene permiso para modificar predios")
    
    predio = await db.predios.find_one({"id": predio_id, "deleted": {"$ne": True}}, {"_id": 0})
    if not predio:
        raise HTTPException(status_code=404, detail="Predio no encontrado")
    
    # Filtrar campos no nulos
    update_dict = {k: v for k, v in update_data.model_dump().items() if v is not None}
    
    if not update_dict:
        return predio
    
    # Si se actualiza área (terreno o construida), activar sincronización automática R2→R1
    campos_area = ['area_terreno', 'area_construida', 'zonas', 'construcciones', 'zonas_fisicas', 'r2_registros']
    if any(campo in update_dict for campo in campos_area):
        update_dict["area_editada_en_plataforma"] = True
    
    # Agregar metadata de actualización
    update_dict["updated_at"] = datetime.now(COLOMBIA_TZ).isoformat()
    
    # Agregar al historial
    historial_entry = {
        "accion": "Predio modificado",
        "usuario": current_user['full_name'],
        "usuario_id": current_user['id'],
        "campos_modificados": list(update_dict.keys()),
        "fecha": datetime.now(COLOMBIA_TZ).isoformat()
    }
    
    await db.predios.update_one(
        {"id": predio_id},
        {
            "$set": update_dict,
            "$push": {"historial": historial_entry}
        }
    )
    
    # Retornar predio actualizado
    updated_predio = await db.predios.find_one({"id": predio_id}, {"_id": 0})
    
    # Broadcast WebSocket para sincronización en tiempo real
    await ws_manager.broadcast({
        "type": "predio_actualizado",
        "action": "update",
        "predio_id": predio_id,
        "municipio": updated_predio.get('municipio', ''),
        "codigo_predial": updated_predio.get('codigo_predial_nacional', ''),
        "campos_modificados": list(update_dict.keys()),
        "updated_by": current_user['full_name'],
        "timestamp": datetime.now(COLOMBIA_TZ).isoformat()
    }, exclude_user=current_user['id'])
    
    return updated_predio

@api_router.delete("/predios/{predio_id}")
async def delete_predio(predio_id: str, current_user: dict = Depends(get_current_user)):
    """Elimina un predio (soft delete)"""
    if current_user['role'] not in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR]:
        raise HTTPException(status_code=403, detail="Solo coordinadores y administradores pueden eliminar predios")
    
    predio = await db.predios.find_one({"id": predio_id, "deleted": {"$ne": True}}, {"_id": 0})
    if not predio:
        raise HTTPException(status_code=404, detail="Predio no encontrado")
    
    # Soft delete - NO eliminamos físicamente para evitar reutilizar códigos
    historial_entry = {
        "accion": "Predio eliminado",
        "usuario": current_user['full_name'],
        "usuario_id": current_user['id'],
        "fecha": datetime.now(COLOMBIA_TZ).isoformat()
    }
    
    await db.predios.update_one(
        {"id": predio_id},
        {
            "$set": {
                "deleted": True,
                "deleted_at": datetime.now(COLOMBIA_TZ).isoformat(),
                "deleted_by": current_user['id'],
                "deleted_by_name": current_user['full_name']
            },
            "$push": {"historial": historial_entry}
        }
    )
    
    # Broadcast WebSocket para sincronización en tiempo real
    await ws_manager.broadcast({
        "type": "predio_actualizado",
        "action": "delete",
        "predio_id": predio_id,
        "municipio": predio.get('municipio', ''),
        "codigo_predial": predio.get('codigo_predial_nacional', ''),
        "deleted_by": current_user['full_name'],
        "timestamp": datetime.now(COLOMBIA_TZ).isoformat()
    }, exclude_user=current_user['id'])
    
    return {"message": "Predio eliminado exitosamente"}


# ===== ENDPOINT SIMPLIFICADO PARA CREAR PREDIOS DESDE M5 =====

class PredioM5Create(BaseModel):
    """Modelo simplificado para crear predios desde M5 - Inscripción"""
    codigo_predial_nacional: str  # Código completo de 30 dígitos
    municipio: str  # Nombre del municipio
    matricula_inmobiliaria: Optional[str] = None
    direccion: str
    destino_economico: str = "H"
    area_terreno: float = 0
    area_construida: float = 0
    avaluo_catastral: float = 0
    propietarios: List[dict]  # Lista de propietarios
    es_predio_nuevo: bool = True
    origen: Optional[str] = "M5_inscripcion"

@api_router.post("/predios/m5/crear")
async def crear_predio_m5(
    predio_data: PredioM5Create,
    current_user: dict = Depends(get_current_user)
):
    """
    Crea un predio nuevo de forma simplificada desde el modal de M5.
    Este endpoint usa un formato plano más simple que el endpoint principal.
    """
    if current_user['role'] == UserRole.USUARIO:
        raise HTTPException(status_code=403, detail="No tiene permiso para crear predios")
    
    # Validar código predial de 30 dígitos
    if len(predio_data.codigo_predial_nacional) != 30:
        raise HTTPException(status_code=400, detail=f"El código predial debe tener 30 dígitos, recibido: {len(predio_data.codigo_predial_nacional)}")
    
    # Extraer partes del código predial
    codigo = predio_data.codigo_predial_nacional
    prefijo_municipio = codigo[:5]
    
    # Obtener información del municipio desde el código
    municipio_info = MUNICIPIOS_POR_CODIGO.get(prefijo_municipio)
    if not municipio_info:
        # Intentar buscar por nombre del municipio
        divipola = MUNICIPIOS_DIVIPOLA.get(predio_data.municipio)
        if not divipola:
            raise HTTPException(status_code=400, detail=f"Municipio no válido: {predio_data.municipio}")
        municipio_nombre = predio_data.municipio
    else:
        municipio_nombre = municipio_info.get("nombre", predio_data.municipio)
    
    # Verificar que el código no existe
    existing = await db.predios.find_one({"codigo_predial_nacional": codigo, "deleted": {"$ne": True}})
    if existing:
        raise HTTPException(status_code=400, detail="Ya existe un predio con este código predial")
    
    # Generar código homologado
    codigo_homologado = await asignar_codigo_homologado(municipio_nombre, None)
    if not codigo_homologado:
        codigo_homologado, _ = await generate_codigo_homologado(municipio_nombre)
    
    # Obtener siguiente número de predio
    last_predio = await db.predios.find_one(
        {"municipio": municipio_nombre, "deleted": {"$ne": True}},
        sort=[("numero_predio", -1)]
    )
    if last_predio:
        num_predio = last_predio.get("numero_predio", 0)
        if isinstance(num_predio, str):
            try:
                num_predio = int(num_predio)
            except (ValueError, TypeError):
                num_predio = 0
        numero_predio = num_predio + 1
    else:
        numero_predio = 1
    
    # Extraer partes del código para la estructura del predio
    zona = codigo[5:7]
    sector = codigo[7:9]
    comuna = codigo[9:11]
    barrio = codigo[11:13]
    manzana_vereda = codigo[13:17]
    terreno = codigo[17:21]
    condicion = codigo[21:22]
    edificio = codigo[22:24]
    piso = codigo[24:26]
    unidad = codigo[26:30]
    
    # Obtener datos del primer propietario
    prop_principal = predio_data.propietarios[0] if predio_data.propietarios else {}
    
    # Crear el predio
    predio = {
        "id": str(uuid.uuid4()),
        "municipio": municipio_nombre,
        "numero_predio": numero_predio,
        "codigo_predial_nacional": codigo,
        "codigo_homologado": codigo_homologado,
        "zona": zona,
        "sector": sector,
        "comuna": comuna,
        "barrio": barrio,
        "manzana_vereda": manzana_vereda,
        "terreno": terreno,
        "terreno_num": int(terreno) if terreno.isdigit() else 1,
        "condicion_predio": condicion + "000",  # Padding para compatibilidad
        "predio_horizontal": edificio + piso + unidad,
        
        # Datos R1
        "tipo_registro": 1,
        "nombre_propietario": prop_principal.get("nombre_propietario", ""),
        "tipo_documento": prop_principal.get("tipo_documento", "C"),
        "numero_documento": prop_principal.get("numero_documento", ""),
        "estado_civil": prop_principal.get("estado_civil", ""),
        "direccion": predio_data.direccion,
        "destino_economico": predio_data.destino_economico,
        "area_terreno": predio_data.area_terreno,
        "area_construida": predio_data.area_construida,
        "avaluo": predio_data.avaluo_catastral,
        "matricula_inmobiliaria": predio_data.matricula_inmobiliaria,
        
        # Lista completa de propietarios
        "propietarios": predio_data.propietarios,
        
        # Metadata
        "vigencia": datetime.now().year,
        "es_predio_nuevo": True,
        "origen": predio_data.origen or "M5_inscripcion",
        "created_at": datetime.now(COLOMBIA_TZ).isoformat(),
        "created_by": current_user["id"],
        "created_by_name": current_user["full_name"],
        "deleted": False,
        "historial": [{
            "accion": "Predio creado desde M5 - Inscripción",
            "usuario": current_user["full_name"],
            "usuario_id": current_user["id"],
            "fecha": datetime.now(COLOMBIA_TZ).isoformat()
        }]
    }
    
    await db.predios.insert_one(predio)
    
    # Eliminar _id antes de retornar
    predio.pop("_id", None)
    
    return {
        "id": predio["id"],
        "codigo_predial_nacional": predio["codigo_predial_nacional"],
        "codigo_homologado": predio["codigo_homologado"],
        "numero_predio": predio["numero_predio"],
        "message": "Predio creado exitosamente"
    }


# ===== FLUJO DE TRABAJO PARA PREDIOS NUEVOS (CONSERVACIÓN) =====

@api_router.post("/predios-nuevos")
async def crear_predio_nuevo(
    predio_data: PredioNuevoCreate,
    current_user: dict = Depends(get_current_user)
):
    """
    Crea un nuevo predio con flujo de trabajo de digitalización.
    El predio queda en estado 'creado' y se asigna a un gestor de apoyo.
    """
    if current_user['role'] == UserRole.USUARIO:
        raise HTTPException(status_code=403, detail="No tiene permiso para crear predios")
    
    r1 = predio_data.r1
    r2 = predio_data.r2
    
    # Verificar que el gestor de apoyo existe y es gestor
    gestor_apoyo = await db.users.find_one({"id": predio_data.gestor_apoyo_id}, {"_id": 0})
    if not gestor_apoyo:
        raise HTTPException(status_code=400, detail="El gestor de apoyo no existe")
    if gestor_apoyo.get('role') not in ['gestor', 'coordinador', 'administrador']:
        raise HTTPException(status_code=400, detail="El usuario asignado no tiene rol de gestor")
    
    # Construir código predial nacional usando los datos que el usuario especificó
    divipola = MUNICIPIOS_DIVIPOLA.get(r1.municipio)
    if not divipola:
        raise HTTPException(status_code=400, detail=f"Municipio {r1.municipio} no válido")
    
    prefijo = divipola["departamento"] + divipola["municipio"]
    
    # Construir el código completo de 30 dígitos con los valores del usuario
    # Estructura: prefijo(5) + zona(2) + sector(2) + comuna(2) + barrio(2) + manzana_vereda(4) + terreno(4) + condicion(1) + predio_horizontal(8: edificio2+piso2+unidad4)
    codigo_predial = (
        f"{prefijo}"
        f"{r1.zona.zfill(2)}"
        f"{r1.sector.zfill(2)}"
        f"{r1.comuna.zfill(2)}"
        f"{r1.barrio.zfill(2)}"
        f"{r1.manzana_vereda.zfill(4)}"
        f"{r1.terreno.zfill(4)}"
        f"{r1.condicion_predio.zfill(1)}"
        f"{r1.predio_horizontal.zfill(8)}"
    )
    
    # Asegurar que el código tenga exactamente 30 dígitos
    codigo_predial = codigo_predial[:30].ljust(30, '0')
    
    # Extraer el número de terreno para guardarlo
    terreno = r1.terreno.zfill(4)
    terreno_num = int(terreno) if terreno.isdigit() else 1
    
    # Verificar que no exista
    existing = await db.predios.find_one({"codigo_predial_nacional": codigo_predial})
    if existing:
        raise HTTPException(status_code=400, detail="Ya existe un predio con este código predial")
    
    # Verificar que no sea un código eliminado sin aprobación
    eliminado = await db.predios_eliminados.find_one({"codigo_predial_nacional": codigo_predial})
    if eliminado:
        aprobacion = await db.predios_reapariciones_aprobadas.find_one({
            "codigo_predial_nacional": codigo_predial,
            "estado": "aprobado"
        })
        if not aprobacion:
            raise HTTPException(status_code=400, detail={
                "error": "PREDIO_ELIMINADO",
                "mensaje": "Este código predial fue ELIMINADO. Debe solicitar reaparición."
            })
    
    # Generar código homologado - Primero intentar de la colección de códigos cargados del Excel
    codigo_homologado = await asignar_codigo_homologado(r1.municipio, None)
    
    if codigo_homologado:
        # Obtener el último número de predio para mantener secuencia
        last_predio = await db.predios.find_one(
            {"municipio": r1.municipio, "deleted": {"$ne": True}},
            sort=[("numero_predio", -1)]
        )
        if last_predio:
            num_predio = last_predio.get("numero_predio", 0)
            if isinstance(num_predio, str):
                try:
                    num_predio = int(num_predio)
                except (ValueError, TypeError):
                    num_predio = 0
            numero_predio = num_predio + 1
        else:
            numero_predio = 1
    else:
        # Fallback: generar código aleatorio si no hay códigos cargados en el Excel
        codigo_homologado, numero_predio = await generate_codigo_homologado(r1.municipio)
    
    # Obtener código Divipola
    divipola = MUNICIPIOS_DIVIPOLA[r1.municipio]
    
    # Construir radicado completo si se proporcionó número
    radicado_completo = None
    radicado_fecha = None
    if predio_data.radicado_numero:
        # Buscar la petición con este radicado para obtener la fecha
        peticion = await db.petitions.find_one({
            "radicado": {"$regex": f"-{predio_data.radicado_numero}-", "$options": "i"}
        }, {"_id": 0})
        if peticion:
            fecha_rad = peticion.get('created_at') or peticion.get('fecha_radicacion')
            if fecha_rad:
                if isinstance(fecha_rad, str):
                    fecha_obj = datetime.fromisoformat(fecha_rad.replace('Z', '+00:00'))
                else:
                    fecha_obj = fecha_rad
                radicado_fecha = fecha_obj.strftime("%d-%m-%Y")
        radicado_completo = f"RASMGC-{predio_data.radicado_numero}-{radicado_fecha or datetime.now().strftime('%d-%m-%Y')}"
    
    # Crear el predio nuevo
    predio_nuevo = {
        "id": str(uuid.uuid4()),
        "departamento": divipola["departamento"],
        "municipio": r1.municipio,
        "municipio_codigo": divipola["municipio"],
        "numero_predio": numero_predio,
        "codigo_predial_nacional": codigo_predial,
        "codigo_homologado": codigo_homologado,
        "zona": r1.zona,
        "sector": r1.sector,
        "manzana_vereda": r1.manzana_vereda,
        "terreno": terreno,
        "terreno_num": terreno_num,
        "condicion_predio": r1.condicion_predio,
        "predio_horizontal": r1.predio_horizontal,
        
        # R1 - Información jurídica
        "tipo_registro": 1,
        "nombre_propietario": r1.nombre_propietario,
        "tipo_documento": r1.tipo_documento,
        "numero_documento": r1.numero_documento,
        "estado_civil": r1.estado_civil,
        "direccion": r1.direccion,
        "comuna": r1.comuna,
        "destino_economico": r1.destino_economico,
        "area_terreno": r1.area_terreno,
        "area_construida": r1.area_construida,
        "avaluo": r1.avaluo,
        "tipo_mutacion": r1.tipo_mutacion,
        "numero_resolucion": r1.numero_resolucion,
        "fecha_resolucion": r1.fecha_resolucion,
        
        # R2 - Información física
        "r2": r2.model_dump() if r2 else None,
        
        # === FLUJO DE TRABAJO ===
        "es_predio_nuevo": True,
        "estado_flujo": PredioNuevoEstado.CREADO,
        
        # Gestor creador
        "gestor_creador_id": current_user['id'],
        "gestor_creador_nombre": current_user['full_name'],
        "gestor_creador_email": current_user.get('email'),
        
        # Gestor de apoyo (digitalización)
        "gestor_apoyo_id": predio_data.gestor_apoyo_id,
        "gestor_apoyo_nombre": gestor_apoyo['full_name'],
        "gestor_apoyo_email": gestor_apoyo.get('email'),
        
        # Relaciones
        "radicado_relacionado": radicado_completo,
        "radicado_numero": predio_data.radicado_numero,
        "peticiones_relacionadas": predio_data.peticiones_ids or [],
        
        # Observaciones
        "observaciones": predio_data.observaciones,
        
        # Metadata
        "vigencia": datetime.now().year,
        "created_at": datetime.now(COLOMBIA_TZ).isoformat(),
        "updated_at": datetime.now(COLOMBIA_TZ).isoformat(),
        "deleted": False,
        
        # Historial de trazabilidad
        "historial_flujo": [{
            "fecha": datetime.now(COLOMBIA_TZ).isoformat(),
            "accion": "Predio creado",
            "estado_anterior": None,
            "estado_nuevo": PredioNuevoEstado.CREADO,
            "usuario_id": current_user['id'],
            "usuario_nombre": current_user['full_name'],
            "observaciones": f"Predio creado y asignado a {gestor_apoyo['full_name']} para digitalización"
        }]
    }
    
    # Guardar en colección de predios en proceso
    await db.predios_nuevos.insert_one(predio_nuevo)
    
    # Crear notificación para el gestor de apoyo
    notificacion = {
        "id": str(uuid.uuid4()),
        "user_id": predio_data.gestor_apoyo_id,
        "tipo": "predio_asignado",
        "titulo": "Nuevo predio asignado para digitalización",
        "mensaje": f"Se te ha asignado el predio {codigo_predial} para digitalización de base gráfica.",
        "predio_id": predio_nuevo['id'],
        "codigo_predial": codigo_predial,
        "leida": False,
        "created_at": datetime.now(COLOMBIA_TZ).isoformat()
    }
    await db.notifications.insert_one(notificacion)
    
    predio_nuevo.pop("_id", None)
    return predio_nuevo


@api_router.get("/predios-nuevos")
async def listar_predios_nuevos(
    estado: Optional[str] = None,
    municipio: Optional[str] = None,
    skip: int = 0,
    limit: int = 50,
    current_user: dict = Depends(get_current_user)
):
    """
    Lista predios nuevos en proceso según el rol del usuario.
    - Gestores: ven predios que crearon o que les asignaron
    - Coordinadores: ven todos los predios en revisión
    """
    if current_user['role'] == UserRole.USUARIO:
        raise HTTPException(status_code=403, detail="No tiene permiso")
    
    query = {}
    
    # Filtrar por estado
    if estado:
        query["estado_flujo"] = estado
    
    # Filtrar por municipio
    if municipio:
        query["municipio"] = municipio
    
    # Filtrar según rol
    if current_user['role'] == UserRole.GESTOR:
        # Gestores ven predios que crearon, que les asignaron, o devueltos a ellos
        query["$or"] = [
            {"gestor_creador_id": current_user['id']},
            {"gestor_apoyo_id": current_user['id']}
        ]
    elif current_user['role'] == UserRole.COORDINADOR:
        # Coordinadores ven TODOS los predios (pueden aprobar por defecto)
        # Solo filtramos por municipio si el coordinador tiene municipios asignados
        user_municipios = current_user.get('municipios', [])
        if user_municipios:
            query["municipio"] = {"$in": user_municipios}
        # Si no tiene municipios asignados, ve todos
    # Administradores ven todo
    
    # Obtener predios
    cursor = db.predios_nuevos.find(query, {"_id": 0}).sort("created_at", -1).skip(skip).limit(limit)
    predios = await cursor.to_list(length=limit)
    
    # Contar total
    total = await db.predios_nuevos.count_documents(query)
    
    return {
        "predios": predios,
        "total": total,
        "skip": skip,
        "limit": limit
    }


@api_router.get("/predios-nuevos/pendientes")
async def predios_nuevos_pendientes(current_user: dict = Depends(get_current_user)):
    """
    Lista predios pendientes de acción para el usuario actual.
    """
    if current_user['role'] == UserRole.USUARIO:
        raise HTTPException(status_code=403, detail="No tiene permiso")
    
    pendientes = {
        "digitalizacion": [],  # Pendientes para gestor de apoyo
        "revision": [],        # Pendientes para coordinador
        "devueltos": []        # Devueltos al gestor/apoyo
    }
    
    user_id = current_user['id']
    
    # Predios en digitalización asignados a este usuario
    cursor = db.predios_nuevos.find({
        "gestor_apoyo_id": user_id,
        "estado_flujo": {"$in": [PredioNuevoEstado.CREADO, PredioNuevoEstado.DIGITALIZACION]}
    }, {"_id": 0})
    pendientes["digitalizacion"] = await cursor.to_list(length=100)
    
    # Predios en revisión (para coordinadores con permiso)
    user_permisos = await db.user_permissions.find_one({"user_id": user_id})
    puede_aprobar = (
        current_user['role'] in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR] or
        (user_permisos and user_permisos.get('permissions', {}).get('aprobar_cambios'))
    )
    
    if puede_aprobar:
        cursor = db.predios_nuevos.find({
            "estado_flujo": PredioNuevoEstado.REVISION
        }, {"_id": 0})
        pendientes["revision"] = await cursor.to_list(length=100)
    
    # Predios devueltos a este usuario
    cursor = db.predios_nuevos.find({
        "estado_flujo": PredioNuevoEstado.DEVUELTO,
        "$or": [
            {"gestor_creador_id": user_id},
            {"gestor_apoyo_id": user_id}
        ]
    }, {"_id": 0})
    pendientes["devueltos"] = await cursor.to_list(length=100)
    
    return pendientes


@api_router.get("/predios-nuevos/{predio_id}")
async def obtener_predio_nuevo(predio_id: str, current_user: dict = Depends(get_current_user)):
    """Obtiene un predio nuevo por ID"""
    if current_user['role'] == UserRole.USUARIO:
        raise HTTPException(status_code=403, detail="No tiene permiso")
    
    predio = await db.predios_nuevos.find_one({"id": predio_id}, {"_id": 0})
    if not predio:
        raise HTTPException(status_code=404, detail="Predio no encontrado")
    
    return predio


@api_router.post("/predios-nuevos/{predio_id}/accion")
async def ejecutar_accion_predio_nuevo(
    predio_id: str,
    accion_data: PredioNuevoAccion,
    current_user: dict = Depends(get_current_user)
):
    """
    Ejecuta una acción en el flujo de trabajo del predio.
    Acciones: enviar_revision, aprobar, devolver, rechazar
    """
    if current_user['role'] == UserRole.USUARIO:
        raise HTTPException(status_code=403, detail="No tiene permiso")
    
    predio = await db.predios_nuevos.find_one({"id": predio_id}, {"_id": 0})
    if not predio:
        raise HTTPException(status_code=404, detail="Predio no encontrado")
    
    estado_actual = predio['estado_flujo']
    accion = accion_data.accion
    user_id = current_user['id']
    
    # Validar permisos según acción
    if accion == "enviar_revision":
        # Solo el gestor de apoyo puede enviar a revisión
        if predio['gestor_apoyo_id'] != user_id and current_user['role'] not in [UserRole.COORDINADOR, UserRole.ADMINISTRADOR]:
            raise HTTPException(status_code=403, detail="Solo el gestor de apoyo asignado puede enviar a revisión")
        
        if estado_actual not in [PredioNuevoEstado.CREADO, PredioNuevoEstado.DIGITALIZACION, PredioNuevoEstado.DEVUELTO]:
            raise HTTPException(status_code=400, detail=f"No se puede enviar a revisión desde estado '{estado_actual}'")
        
        nuevo_estado = PredioNuevoEstado.REVISION
        mensaje_notif = f"El predio {predio['codigo_predial_nacional']} ha sido enviado para revisión"
    
    elif accion == "rechazar_asignacion":
        # Solo el gestor de apoyo asignado puede rechazar su asignación
        if predio['gestor_apoyo_id'] != user_id:
            raise HTTPException(status_code=403, detail="Solo el gestor de apoyo asignado puede rechazar esta asignación")
        
        if estado_actual not in [PredioNuevoEstado.CREADO, PredioNuevoEstado.DIGITALIZACION, PredioNuevoEstado.DEVUELTO]:
            raise HTTPException(status_code=400, detail=f"No se puede rechazar la asignación desde estado '{estado_actual}'")
        
        nuevo_estado = PredioNuevoEstado.CREADO  # Vuelve a estado creado sin asignación
        mensaje_notif = f"La asignación del predio {predio['codigo_predial_nacional']} ha sido rechazada por {current_user['full_name']}"
        
    elif accion in ["aprobar", "devolver", "rechazar"]:
        # Verificar permiso de aprobar cambios
        user_permisos = await db.user_permissions.find_one({"user_id": user_id})
        puede_aprobar = (
            current_user['role'] in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR] or
            (user_permisos and user_permisos.get('permissions', {}).get('aprobar_cambios'))
        )
        
        if not puede_aprobar:
            raise HTTPException(status_code=403, detail="No tiene permiso para aprobar/devolver/rechazar predios")
        
        if estado_actual != PredioNuevoEstado.REVISION:
            raise HTTPException(status_code=400, detail="El predio debe estar en revisión para esta acción")
        
        if accion == "aprobar":
            nuevo_estado = PredioNuevoEstado.APROBADO
            mensaje_notif = f"El predio {predio['codigo_predial_nacional']} ha sido APROBADO"
        elif accion == "devolver":
            nuevo_estado = PredioNuevoEstado.DEVUELTO
            mensaje_notif = f"El predio {predio['codigo_predial_nacional']} ha sido DEVUELTO para corrección"
        else:  # rechazar
            nuevo_estado = PredioNuevoEstado.RECHAZADO
            mensaje_notif = f"El predio {predio['codigo_predial_nacional']} ha sido RECHAZADO"
    else:
        raise HTTPException(status_code=400, detail=f"Acción no válida: {accion}")
    
    # Crear entrada de historial
    historial_entry = {
        "fecha": datetime.now(COLOMBIA_TZ).isoformat(),
        "accion": accion,
        "estado_anterior": estado_actual,
        "estado_nuevo": nuevo_estado,
        "usuario_id": user_id,
        "usuario_nombre": current_user['full_name'],
        "observaciones": accion_data.observaciones
    }
    
    # Actualizar predio
    update_data = {
        "estado_flujo": nuevo_estado,
        "updated_at": datetime.now(COLOMBIA_TZ).isoformat()
    }
    
    # Si se aprueba, agregar datos de aprobación
    if accion == "aprobar":
        update_data["aprobado_por_id"] = user_id
        update_data["aprobado_por_nombre"] = current_user['full_name']
        update_data["fecha_aprobacion"] = datetime.now(COLOMBIA_TZ).isoformat()
    
    # Si se rechaza la asignación, quitar el gestor de apoyo asignado
    if accion == "rechazar_asignacion":
        update_data["gestor_apoyo_id"] = None
        update_data["gestor_apoyo_nombre"] = None
        update_data["comentario_devolucion"] = accion_data.observaciones
    
    await db.predios_nuevos.update_one(
        {"id": predio_id},
        {
            "$set": update_data,
            "$push": {"historial_flujo": historial_entry}
        }
    )
    
    # Si se aprueba, mover a la colección principal de predios
    if accion == "aprobar":
        predio_actualizado = await db.predios_nuevos.find_one({"id": predio_id}, {"_id": 0})
        
        # Preparar datos para colección principal
        predio_aprobado = {**predio_actualizado}
        predio_aprobado["historial"] = predio_aprobado.pop("historial_flujo", [])
        predio_aprobado["historial"].append({
            "accion": "Predio aprobado e integrado",
            "usuario": current_user['full_name'],
            "usuario_id": user_id,
            "fecha": datetime.now(COLOMBIA_TZ).isoformat()
        })
        
        # Normalizar vigencia al año actual (formato consistente con colección principal)
        vigencia_actual = datetime.now(COLOMBIA_TZ).year
        predio_aprobado["vigencia"] = vigencia_actual
        
        # Asegurar que tenga los campos necesarios para R1/R2
        if "r1" not in predio_aprobado or not predio_aprobado.get("r1"):
            predio_aprobado["r1"] = {
                "numero_orden": "1",
                "calificacion_no_certificada": "0",
                "tipo_predio": predio_aprobado.get("tipo_predio", ""),
                "numero_predial_anterior": "",
                "complemento_nom_predio": "",
                "area_total_terreno": predio_aprobado.get("area_terreno", 0),
                "valor_referencia": predio_aprobado.get("avaluo", 0),
                "tipo_avaluo_catastral": "1"
            }
        
        # Preparar propietarios en formato R1
        if predio_aprobado.get("propietarios"):
            predio_aprobado["r1_registros"] = []
            for i, prop in enumerate(predio_aprobado["propietarios"]):
                r1_registro = {
                    "numero_orden": str(i + 1),
                    "calificacion_no_certificada": "0",
                    "tipo_documento": prop.get("tipo_documento", "C"),
                    "numero_documento": prop.get("numero_documento", ""),
                    "nombre_propietario": prop.get("nombre_propietario", ""),
                    "estado_civil": prop.get("estado_civil", ""),
                    "direccion": predio_aprobado.get("direccion", ""),
                    "destino_economico": predio_aprobado.get("destino_economico", ""),
                    "area_terreno": predio_aprobado.get("area_terreno", 0),
                    "area_construida": predio_aprobado.get("area_construida", 0),
                    "avaluo": predio_aprobado.get("avaluo", 0),
                    "codigo_homologado": predio_aprobado.get("codigo_homologado", "")
                }
                predio_aprobado["r1_registros"].append(r1_registro)
        
        # Preparar zonas físicas en formato R2
        if predio_aprobado.get("zonas_fisicas"):
            predio_aprobado["r2_registros"] = []
            # Obtener matrícula del R2 o del nivel superior
            matricula = predio_aprobado.get("matricula_inmobiliaria", "")
            if not matricula and predio_aprobado.get("r2"):
                matricula = predio_aprobado["r2"].get("matricula_inmobiliaria", "")
            
            for i, zona in enumerate(predio_aprobado["zonas_fisicas"]):
                r2_registro = {
                    "numero_orden": str(i + 1),
                    "tipo_construccion": zona.get("tipo_construccion", "C"),
                    "numero_pisos": zona.get("pisos", 0),
                    "numero_habitaciones": zona.get("habitaciones", 0),
                    "numero_banios": zona.get("banos", 0),
                    "numero_locales": zona.get("locales", 0),
                    "anio_construccion": zona.get("anio_construccion", ""),
                    "area_construida": zona.get("area_construida", 0),
                    "area_terreno": zona.get("area_terreno", 0),
                    "puntaje": zona.get("puntaje", 0),
                    "zona_fisica": zona.get("zona_fisica", ""),
                    "zona_economica": zona.get("zona_economica", ""),
                    "matricula_inmobiliaria": matricula
                }
                predio_aprobado["r2_registros"].append(r2_registro)
            
            # Asegurar que la matrícula también esté a nivel superior del predio
            if matricula:
                predio_aprobado["matricula_inmobiliaria"] = matricula
                
        elif predio_aprobado.get("r2"):
            # Si tiene r2 pero no zonas_fisicas, crear r2_registros desde r2
            r2 = predio_aprobado["r2"]
            matricula = r2.get("matricula_inmobiliaria", "")
            
            predio_aprobado["r2_registros"] = [{
                "numero_orden": r2.get("numero_orden", "1"),
                "tipo_construccion": r2.get("tipo_construccion", "C"),
                "numero_pisos": r2.get("pisos_1", 0),
                "numero_habitaciones": r2.get("habitaciones_1", 0),
                "numero_banios": r2.get("banos_1", 0),
                "numero_locales": r2.get("locales_1", 0),
                "anio_construccion": r2.get("anio_construccion", ""),
                "area_construida": r2.get("area_construida_1", 0),
                "area_terreno": r2.get("area_terreno_1", 0),
                "puntaje": r2.get("puntaje_1", 0),
                "zona_fisica": r2.get("zona_fisica_1", ""),
                "zona_economica": r2.get("zona_economica_1", ""),
                "matricula_inmobiliaria": matricula
            }]
            
            # Asegurar que la matrícula también esté a nivel superior del predio
            if matricula:
                predio_aprobado["matricula_inmobiliaria"] = matricula
        
        # Insertar en colección principal
        await db.predios.insert_one(predio_aprobado)
        
        # BUGFIX: También insertar en predios_actualizacion para que aparezca en el Visor de Mapas
        predio_para_visor = {
            "id": predio_aprobado["id"],
            "codigo_predial_nacional": predio_aprobado.get("codigo_predial_nacional"),
            "codigo_predial": predio_aprobado.get("codigo_predial_nacional"),
            "numero_predial": predio_aprobado.get("codigo_predial_nacional"),
            "codigo_homologado": predio_aprobado.get("codigo_homologado", ""),
            "municipio": predio_aprobado.get("municipio"),
            "vigencia": predio_aprobado.get("vigencia", datetime.now(COLOMBIA_TZ).year),
            "direccion": predio_aprobado.get("direccion", ""),
            "destino_economico": predio_aprobado.get("destino_economico", ""),
            "area_terreno": predio_aprobado.get("area_terreno", 0),
            "area_construida": predio_aprobado.get("area_construida", 0),
            "avaluo_catastral": predio_aprobado.get("avaluo", 0),
            "nombre_propietario": predio_aprobado.get("propietarios", [{}])[0].get("nombre_propietario", "") if predio_aprobado.get("propietarios") else "",
            "propietarios": predio_aprobado.get("propietarios", []),
            "matricula_inmobiliaria": predio_aprobado.get("matricula_inmobiliaria", ""),
            "estado_visita": "pendiente",
            "es_predio_nuevo": True,
            "created_at": datetime.now(COLOMBIA_TZ).isoformat(),
            "updated_at": datetime.now(COLOMBIA_TZ).isoformat(),
            "creado_por": predio_aprobado.get("gestor_creador_id"),
            "creado_por_nombre": predio_aprobado.get("gestor_creador_nombre"),
            "aprobado_por": current_user["id"],
            "aprobado_por_nombre": current_user["full_name"]
        }
        await db.predios_actualizacion.insert_one(predio_para_visor)
        
        # Eliminar de predios_nuevos
        await db.predios_nuevos.delete_one({"id": predio_id})
    
    # Crear notificaciones
    destinatarios = set()
    if predio['gestor_creador_id'] and predio['gestor_creador_id'] != user_id:
        destinatarios.add(predio['gestor_creador_id'])
    if predio.get('gestor_apoyo_id') and predio['gestor_apoyo_id'] != user_id:
        destinatarios.add(predio['gestor_apoyo_id'])
    
    # Si se envía a revisión, notificar también a coordinadores y usuarios con permiso de aprobar
    if accion == "enviar_revision":
        municipio_predio = predio.get('municipio')
        
        # Obtener coordinadores y administradores
        coordinadores_cursor = db.users.find({
            "role": {"$in": [UserRole.COORDINADOR, UserRole.ADMINISTRADOR]},
            "deleted": {"$ne": True}
        }, {"id": 1, "municipios": 1})
        
        async for coord in coordinadores_cursor:
            # Si el coordinador tiene municipios asignados, verificar que incluya el del predio
            coord_municipios = coord.get('municipios', [])
            if not coord_municipios or municipio_predio in coord_municipios:
                if coord['id'] != user_id:
                    destinatarios.add(coord['id'])
        
        # Obtener gestores con permiso de aprobar cambios
        permisos_cursor = db.user_permissions.find({
            "permissions.aprobar_cambios": True
        }, {"user_id": 1})
        
        async for perm in permisos_cursor:
            if perm['user_id'] != user_id:
                # Verificar que el usuario esté activo
                usuario = await db.users.find_one({"id": perm['user_id'], "deleted": {"$ne": True}})
                if usuario:
                    # Si tiene municipios asignados, verificar que incluya el del predio
                    user_municipios = usuario.get('municipios', [])
                    if not user_municipios or municipio_predio in user_municipios:
                        destinatarios.add(perm['user_id'])
        
        logger.info(f"Predio {predio['codigo_predial_nacional']} enviado a revisión. Notificando a {len(destinatarios)} usuarios aprobadores.")
    
    for dest_id in destinatarios:
        if dest_id:  # Verificar que el ID no sea None
            notif = {
                "id": str(uuid.uuid4()),
                "user_id": dest_id,
                "tipo": f"predio_{accion}",
                "titulo": mensaje_notif,
                "mensaje": accion_data.observaciones or mensaje_notif,
                "predio_id": predio_id,
                "codigo_predial": predio['codigo_predial_nacional'],
                "leida": False,
                "created_at": datetime.now(COLOMBIA_TZ).isoformat()
            }
            await db.notifications.insert_one(notif)
    
    # Retornar predio actualizado
    if accion == "aprobar":
        predio_final = await db.predios.find_one({"id": predio_id}, {"_id": 0})
    else:
        predio_final = await db.predios_nuevos.find_one({"id": predio_id}, {"_id": 0})
    
    return {
        "success": True,
        "mensaje": mensaje_notif,
        "predio": predio_final
    }


@api_router.get("/predios-nuevos/buscar-radicado/{numero}")
async def buscar_radicado(numero: str, current_user: dict = Depends(get_current_user)):
    """
    Busca un radicado por su número y retorna la fecha.
    """
    if current_user['role'] == UserRole.USUARIO:
        raise HTTPException(status_code=403, detail="No tiene permiso")
    
    # Buscar petición con este número de radicado
    peticion = await db.petitions.find_one({
        "radicado": {"$regex": f"-{numero}-", "$options": "i"}
    }, {"_id": 0, "radicado": 1, "created_at": 1, "fecha_radicacion": 1, "solicitante": 1, "tipo_tramite": 1})
    
    if not peticion:
        return {
            "encontrado": False,
            "mensaje": "No se encontró petición con este número de radicado"
        }
    
    fecha_rad = peticion.get('created_at') or peticion.get('fecha_radicacion')
    if isinstance(fecha_rad, str):
        fecha_obj = datetime.fromisoformat(fecha_rad.replace('Z', '+00:00'))
    else:
        fecha_obj = fecha_rad
    
    return {
        "encontrado": True,
        "radicado_completo": peticion.get('radicado'),
        "fecha": fecha_obj.strftime("%d-%m-%Y") if fecha_obj else None,
        "solicitante": peticion.get('solicitante'),
        "tipo_tramite": peticion.get('tipo_tramite')
    }


@api_router.patch("/predios-nuevos/{predio_id}")
async def actualizar_predio_nuevo(
    predio_id: str,
    update_data: dict,
    current_user: dict = Depends(get_current_user)
):
    """
    Actualiza un predio nuevo (solo en estados editables).
    """
    if current_user['role'] == UserRole.USUARIO:
        raise HTTPException(status_code=403, detail="No tiene permiso")
    
    predio = await db.predios_nuevos.find_one({"id": predio_id}, {"_id": 0})
    if not predio:
        raise HTTPException(status_code=404, detail="Predio no encontrado")
    
    # Solo se puede editar en estados: creado, digitalizacion, devuelto
    if predio['estado_flujo'] not in [PredioNuevoEstado.CREADO, PredioNuevoEstado.DIGITALIZACION, PredioNuevoEstado.DEVUELTO]:
        raise HTTPException(status_code=400, detail="No se puede editar el predio en este estado")
    
    # Verificar que sea el gestor creador o de apoyo
    if predio['gestor_creador_id'] != current_user['id'] and predio['gestor_apoyo_id'] != current_user['id']:
        if current_user['role'] not in [UserRole.COORDINADOR, UserRole.ADMINISTRADOR]:
            raise HTTPException(status_code=403, detail="Solo el gestor creador o de apoyo puede editar")
    
    # Campos protegidos que no se pueden cambiar
    campos_protegidos = ['id', 'codigo_predial_nacional', 'gestor_creador_id', 'created_at', 'historial_flujo']
    for campo in campos_protegidos:
        update_data.pop(campo, None)
    
    update_data["updated_at"] = datetime.now(COLOMBIA_TZ).isoformat()
    
    # Agregar entrada al historial
    historial_entry = {
        "fecha": datetime.now(COLOMBIA_TZ).isoformat(),
        "accion": "Predio actualizado",
        "estado_anterior": predio['estado_flujo'],
        "estado_nuevo": predio['estado_flujo'],
        "usuario_id": current_user['id'],
        "usuario_nombre": current_user['full_name'],
        "observaciones": f"Campos modificados: {', '.join(update_data.keys())}"
    }
    
    await db.predios_nuevos.update_one(
        {"id": predio_id},
        {
            "$set": update_data,
            "$push": {"historial_flujo": historial_entry}
        }
    )
    
    predio_actualizado = await db.predios_nuevos.find_one({"id": predio_id}, {"_id": 0})
    return predio_actualizado


@api_router.delete("/predios-nuevos/{predio_id}")
async def eliminar_predio_nuevo(
    predio_id: str,
    request: Request,
    current_user: dict = Depends(get_current_user)
):
    """
    Elimina una solicitud de predio nuevo.
    Solo el gestor creador puede eliminar su propia solicitud.
    Solo se puede eliminar en estados: creado, digitalizacion, devuelto.
    """
    predio = await db.predios_nuevos.find_one({"id": predio_id}, {"_id": 0})
    if not predio:
        raise HTTPException(status_code=404, detail="Predio no encontrado")
    
    # Solo el gestor creador puede eliminar
    if predio['gestor_creador_id'] != current_user['id']:
        raise HTTPException(status_code=403, detail="Solo el gestor creador puede eliminar esta solicitud")
    
    # Solo se puede eliminar en estados editables
    if predio['estado_flujo'] not in [PredioNuevoEstado.CREADO, PredioNuevoEstado.DIGITALIZACION, PredioNuevoEstado.DEVUELTO]:
        raise HTTPException(status_code=400, detail="No se puede eliminar el predio en este estado. Solo se puede eliminar en estados: creado, digitalizacion o devuelto")
    
    # Obtener motivo del body
    try:
        body = await request.json()
        motivo = body.get('motivo', '')
    except:
        motivo = ''
    
    if not motivo:
        raise HTTPException(status_code=400, detail="Debe proporcionar un motivo para eliminar la solicitud")
    
    # Guardar registro de eliminación para auditoría
    registro_eliminacion = {
        "id": str(uuid.uuid4()),
        "predio_id": predio_id,
        "codigo_predial_nacional": predio.get('codigo_predial_nacional'),
        "municipio": predio.get('municipio'),
        "direccion": predio.get('direccion'),
        "gestor_creador_id": predio.get('gestor_creador_id'),
        "gestor_creador_nombre": predio.get('gestor_creador_nombre'),
        "eliminado_por_id": current_user['id'],
        "eliminado_por_nombre": current_user['full_name'],
        "motivo": motivo,
        "datos_predio": predio,
        "fecha_eliminacion": datetime.now(COLOMBIA_TZ).isoformat()
    }
    
    await db.predios_nuevos_eliminados.insert_one(registro_eliminacion)
    
    # Eliminar el predio
    await db.predios_nuevos.delete_one({"id": predio_id})
    
    logger.info(f"Predio nuevo {predio_id} eliminado por {current_user['full_name']}. Motivo: {motivo}")
    
    return {"message": "Solicitud eliminada correctamente", "motivo": motivo}


# ===== SISTEMA DE APROBACIÓN DE PREDIOS =====

@api_router.post("/predios/cambios/proponer")
async def proponer_cambio_predio(
    cambio: CambioPendienteCreate,
    current_user: dict = Depends(get_current_user)
):
    """
    Propone un cambio en un predio (crear, modificar, eliminar).
    Solo gestores y atención pueden proponer. Coordinadores aprueban directamente.
    Opcionalmente puede asignar un gestor de apoyo para modificaciones.
    """
    # Verificar permisos - Usuarios, Comunicaciones y Empresa no pueden proponer cambios
    if current_user['role'] in [UserRole.USUARIO, UserRole.COMUNICACIONES, UserRole.EMPRESA]:
        raise HTTPException(status_code=403, detail="No tiene permiso para proponer cambios en predios")
    
    # Coordinadores y administradores aprueban directamente (a menos que asignen gestor de apoyo)
    aprueba_directo = current_user['role'] in [UserRole.COORDINADOR, UserRole.ADMINISTRADOR]
    
    # Si se asigna gestor de apoyo, NO aprueba directo, va al flujo de apoyo
    usa_gestor_apoyo = cambio.gestor_apoyo_id is not None and cambio.tipo_cambio == "modificacion"
    if usa_gestor_apoyo:
        aprueba_directo = False
        # Verificar que el gestor de apoyo existe y tiene rol válido
        gestor_apoyo = await db.users.find_one({"id": cambio.gestor_apoyo_id}, {"_id": 0})
        if not gestor_apoyo:
            raise HTTPException(status_code=400, detail="El gestor de apoyo no existe")
        if gestor_apoyo.get('role') not in ['gestor', 'coordinador', 'administrador', 'atencion_usuario']:
            raise HTTPException(status_code=400, detail="El usuario asignado no tiene rol de gestor")
    
    # Obtener información del radicado si se proporcionó
    radicado_info = None
    if cambio.radicado_id:
        radicado_info = await db.petitions.find_one({"id": cambio.radicado_id}, {"_id": 0, "radicado": 1, "tipo_tramite": 1})
    
    # Obtener datos actuales del predio para modificaciones y eliminaciones
    predio_actual_data = None
    if cambio.tipo_cambio in ["modificacion", "eliminacion"] and cambio.predio_id:
        predio_existente = await db.predios.find_one({"id": cambio.predio_id}, {"_id": 0})
        if predio_existente:
            predio_actual_data = {
                "codigo_predial_nacional": predio_existente.get("codigo_predial_nacional"),
                "codigo_homologado": predio_existente.get("codigo_homologado"),
                "municipio": predio_existente.get("municipio"),
                "direccion": predio_existente.get("direccion"),
                "nombre_propietario": predio_existente.get("nombre_propietario"),
                "propietarios": predio_existente.get("propietarios", []),
                "area_terreno": predio_existente.get("area_terreno"),
                "area_construida": predio_existente.get("area_construida"),
                "avaluo": predio_existente.get("avaluo"),
                "destino_economico": predio_existente.get("destino_economico"),
                "zona": predio_existente.get("zona"),
                "vigencia": predio_existente.get("vigencia"),
            }
            # Para eliminaciones, también incluir datos actuales en datos_propuestos si están vacíos
            if cambio.tipo_cambio == "eliminacion":
                datos_prop = cambio.datos_propuestos or {}
                if not datos_prop.get("municipio"):
                    datos_prop["municipio"] = predio_existente.get("municipio")
                if not datos_prop.get("direccion"):
                    datos_prop["direccion"] = predio_existente.get("direccion")
                if not datos_prop.get("nombre_propietario"):
                    datos_prop["nombre_propietario"] = predio_existente.get("nombre_propietario")
                if not datos_prop.get("area_terreno"):
                    datos_prop["area_terreno"] = predio_existente.get("area_terreno")
                if not datos_prop.get("area_construida"):
                    datos_prop["area_construida"] = predio_existente.get("area_construida")
                if not datos_prop.get("avaluo"):
                    datos_prop["avaluo"] = predio_existente.get("avaluo")
                if not datos_prop.get("codigo_predial_nacional"):
                    datos_prop["codigo_predial_nacional"] = predio_existente.get("codigo_predial_nacional")
                if not datos_prop.get("codigo_homologado"):
                    datos_prop["codigo_homologado"] = predio_existente.get("codigo_homologado")
                if not datos_prop.get("propietarios"):
                    datos_prop["propietarios"] = predio_existente.get("propietarios", [])
                cambio.datos_propuestos = datos_prop
    
    # Determinar estado inicial según el flujo
    if aprueba_directo:
        estado_inicial = PredioEstadoAprobacion.APROBADO
    elif usa_gestor_apoyo:
        estado_inicial = "en_digitalizacion"  # Nuevo estado para flujo de apoyo
    else:
        estado_inicial = f"pendiente_{cambio.tipo_cambio}"
    
    # Para eliminaciones, el radicado puede venir en datos_propuestos
    radicado_de_datos_propuestos = None
    if cambio.tipo_cambio == "eliminacion" and cambio.datos_propuestos:
        radicado_de_datos_propuestos = cambio.datos_propuestos.get("radicado") or cambio.datos_propuestos.get("radicado_eliminacion")
    
    # Prioridad: radicado_info (de petición vinculada) > cambio.radicado_numero > radicado de datos_propuestos
    radicado_numero_final = radicado_info['radicado'] if radicado_info else (cambio.radicado_numero or radicado_de_datos_propuestos)
    
    cambio_doc = {
        "id": str(uuid.uuid4()),
        "predio_id": cambio.predio_id,
        "tipo_cambio": cambio.tipo_cambio,
        "datos_propuestos": cambio.datos_propuestos,
        "predio_actual": predio_actual_data,  # Guardar datos actuales para comparación
        "justificacion": cambio.justificacion,
        "radicado_id": cambio.radicado_id,
        "radicado_numero": radicado_numero_final,
        "estado": estado_inicial,
        "propuesto_por": current_user['id'],
        "propuesto_por_nombre": current_user['full_name'],
        "propuesto_por_rol": current_user['role'],
        "fecha_propuesta": datetime.now(COLOMBIA_TZ).isoformat(),
        "aprobado_por": current_user['id'] if aprueba_directo else None,
        "aprobado_por_nombre": current_user['full_name'] if aprueba_directo else None,
        "fecha_aprobacion": datetime.now(COLOMBIA_TZ).isoformat() if aprueba_directo else None,
        "comentario_aprobacion": "Aprobación directa por coordinador/administrador" if aprueba_directo else None
    }
    
    # Agregar datos del gestor de apoyo si se usa ese flujo
    if usa_gestor_apoyo:
        cambio_doc["gestor_apoyo_id"] = cambio.gestor_apoyo_id
        cambio_doc["gestor_apoyo_nombre"] = gestor_apoyo.get('full_name')
        cambio_doc["observaciones_apoyo"] = cambio.observaciones_apoyo
        cambio_doc["fecha_asignacion_apoyo"] = datetime.now(COLOMBIA_TZ).isoformat()
    
    # Si aprueba directo, guardar también los datos_anteriores
    if aprueba_directo and predio_actual_data:
        cambio_doc["datos_anteriores"] = predio_actual_data
    
    # Si aprueba directo, aplicar el cambio inmediatamente
    if aprueba_directo:
        resultado = await aplicar_cambio_predio(cambio_doc, current_user)
        cambio_doc["resultado"] = resultado
        
        # === GENERAR RESOLUCIÓN PDF AUTOMÁTICAMENTE PARA APROBACIÓN DIRECTA ===
        try:
            resolucion_data = await generar_resolucion_final(cambio_doc, current_user)
            if resolucion_data:
                cambio_doc["resolucion"] = resolucion_data
                # Actualizar el documento con los datos de resolución
                await db.predios_cambios.update_one(
                    {"id": cambio_doc["id"]},
                    {"$set": {"resolucion": resolucion_data}}
                )
                
                # Actualizar el historial del predio con el pdf_path de la resolución
                if cambio_doc.get("predio_id") and resolucion_data.get("pdf_path"):
                    await db.predios.update_one(
                        {"id": cambio_doc["predio_id"], "historial.cambio_id": cambio_doc["id"]},
                        {"$set": {
                            "historial.$.pdf_path": resolucion_data.get("pdf_path"),
                            "historial.$.numero_resolucion": resolucion_data.get("numero_resolucion"),
                            "historial.$.tipo_mutacion": resolucion_data.get("tipo_mutacion")
                        }}
                    )
                
                logging.info(f"Resolución generada (aprobación directa): {resolucion_data.get('numero_resolucion')}")
        except Exception as e:
            logging.error(f"Error generando resolución automática (aprobación directa): {str(e)}")
    
    # Guardar el cambio en la colección de cambios
    await db.predios_cambios.insert_one(cambio_doc)
    
    # Notificar al gestor de apoyo si fue asignado
    if usa_gestor_apoyo:
        predio_codigo = predio_actual_data.get('codigo_predial_nacional', 'N/A') if predio_actual_data else 'N/A'
        try:
            await crear_notificacion(
                usuario_id=cambio.gestor_apoyo_id,
                titulo="Modificación de predio asignada",
                mensaje=f"{current_user['full_name']} te ha asignado la modificación del predio {predio_codigo}",
                tipo="modificacion_asignada"
            )
        except Exception as e:
            logging.error(f"Error enviando notificación de asignación: {e}")
    
    # Construir mensaje de respuesta
    if aprueba_directo:
        mensaje = "Cambio aplicado directamente"
    elif usa_gestor_apoyo:
        mensaje = f"Modificación asignada a {gestor_apoyo.get('full_name')} para completar"
    else:
        mensaje = "Cambio propuesto, pendiente de aprobación"
    
    return {
        "id": cambio_doc["id"],
        "estado": cambio_doc["estado"],
        "mensaje": mensaje,
        "requiere_aprobacion": not aprueba_directo,
        "asignado_gestor_apoyo": usa_gestor_apoyo
    }


@api_router.get("/predios/cambios/pendientes")
async def get_cambios_pendientes(
    skip: int = 0,
    limit: int = 50,
    current_user: dict = Depends(get_current_user)
):
    """Lista todos los cambios pendientes de aprobación (coordinadores/admin o usuarios con permiso)"""
    # Verificar si es coordinador/admin o tiene permiso de aprobar cambios
    user_permissions = current_user.get('permissions', [])
    has_approve_permission = 'approve_changes' in user_permissions
    
    if current_user['role'] not in [UserRole.COORDINADOR, UserRole.ADMINISTRADOR] and not has_approve_permission:
        raise HTTPException(status_code=403, detail="No tiene permiso para ver cambios pendientes")
    
    query = {
        "estado": {"$in": [
            PredioEstadoAprobacion.PENDIENTE_CREACION,
            PredioEstadoAprobacion.PENDIENTE_MODIFICACION,
            PredioEstadoAprobacion.PENDIENTE_ELIMINACION
        ]}
    }
    
    total = await db.predios_cambios.count_documents(query)
    cambios = await db.predios_cambios.find(query, {"_id": 0}).sort("fecha_propuesta", -1).skip(skip).limit(limit).to_list(limit)
    
    # Enriquecer con datos del predio actual si existe (para comparación)
    for cambio in cambios:
        if cambio.get("predio_id"):
            # Obtener TODOS los campos del predio actual para permitir comparación
            predio = await db.predios.find_one(
                {"id": cambio["predio_id"]}, 
                {"_id": 0, "historial": 0}  # Excluir historial para reducir tamaño
            )
            
            # Si no se encuentra (puede estar eliminado), buscar incluyendo eliminados
            if not predio:
                predio = await db.predios.find_one(
                    {"id": cambio["predio_id"], "deleted": True}, 
                    {"_id": 0, "historial": 0}
                )
            
            # Si aún no se encuentra, buscar en predios_eliminados por código
            if not predio and cambio.get("datos_propuestos", {}).get("codigo_predial_nacional"):
                predio = await db.predios_eliminados.find_one(
                    {"codigo_predial_nacional": cambio["datos_propuestos"]["codigo_predial_nacional"]},
                    {"_id": 0}
                )
            
            cambio["predio_actual"] = predio
    
    return {
        "total": total,
        "cambios": cambios
    }


# ===== GENERACIÓN AUTOMÁTICA DE RESOLUCIONES =====

def obtener_datos_r1_r2(predio: dict) -> dict:
    """
    Obtiene datos de R1 y R2 del predio para los cuadros de cancelación/inscripción.
    Prioridad: r1_registros/r2_registros > campos directos del predio
    
    R1 contiene: codigo_homologado, direccion, destino_economico, area_terreno, area_construida, avaluo
    R2 contiene: matricula_inmobiliaria
    """
    if not predio:
        return {
            'codigo_homologado': '',
            'direccion': '',
            'destino_economico': '',
            'area_terreno': 0,
            'area_construida': 0,
            'avaluo': 0,
            'matricula_inmobiliaria': ''
        }
    
    r1 = predio.get('r1_registros', [])
    r2 = predio.get('r2_registros', [])
    
    r1_data = r1[0] if r1 else {}
    r2_data = r2[0] if r2 else {}
    
    return {
        # Datos de R1 (con fallback a campos directos)
        'codigo_homologado': r1_data.get('codigo_homologado') or predio.get('codigo_homologado', ''),
        'direccion': r1_data.get('direccion') or predio.get('direccion', ''),
        'destino_economico': r1_data.get('destino_economico') or predio.get('destino_economico', ''),
        'area_terreno': r1_data.get('area_terreno') or predio.get('area_terreno', 0),
        'area_construida': r1_data.get('area_construida') or predio.get('area_construida', 0),
        'avaluo': r1_data.get('avaluo') or predio.get('avaluo', 0),
        
        # Datos de R2 (con fallback a campo directo)
        'matricula_inmobiliaria': r2_data.get('matricula_inmobiliaria') or predio.get('matricula_inmobiliaria', '')
    }

async def generar_resolucion_final(cambio: dict, aprobador: dict) -> dict:
    """
    Genera un PDF de resolución final para un cambio aprobado.
    Retorna los datos de la resolución generada o None si no aplica.
    """
    try:
        # === VERIFICAR SI EL PREDIO ESTÁ BLOQUEADO ===
        predio_id = cambio.get("predio_id")
        if predio_id:
            bloqueo_check = await verificar_predio_bloqueado(predio_id)
            if bloqueo_check.get("bloqueado"):
                bloqueo_info = bloqueo_check.get("info", {})
                raise Exception(
                    f"El predio está bloqueado por proceso legal. "
                    f"Motivo: {bloqueo_info.get('motivo', 'No especificado')}. "
                    f"Bloqueado por: {bloqueo_info.get('bloqueado_por_nombre', 'Desconocido')}"
                )
        
        # Determinar si el cambio requiere resolución (por ahora solo M1 para cambios de propietario)
        tipo_cambio = cambio.get("tipo_cambio", "")
        datos_propuestos = cambio.get("datos_propuestos", {})
        
        # Por ahora generamos resolución M1 para cambios de propietario/modificaciones
        if tipo_cambio not in ["modificacion", "creacion"]:
            logging.info(f"Tipo de cambio '{tipo_cambio}' no requiere resolución automática")
            return None
        
        # Obtener predio actual para datos completos
        predio = None
        if cambio.get("predio_id"):
            predio = await db.predios.find_one({"id": cambio["predio_id"]}, {"_id": 0})
        
        # Combinar datos del predio con datos propuestos
        if predio:
            datos_predio = {**predio, **datos_propuestos}
        else:
            datos_predio = datos_propuestos
        
        # Obtener código de municipio del código predial nacional
        codigo = datos_predio.get("codigo_predial_nacional", "")
        codigo_municipio = codigo[0:5] if len(codigo) >= 5 else "54003"
        depto = codigo[0:2] if len(codigo) >= 2 else "54"
        mpio = codigo[2:5] if len(codigo) >= 5 else "003"
        
        # Obtener configuración de numeración POR MUNICIPIO
        año_actual = datetime.now().year
        config_municipios = await db.resolucion_configuracion_municipios.find_one({"id": "config_municipios"})
        numero_inicial = config_municipios.get(codigo_municipio, 0) if config_municipios else 0
        
        # Contar resoluciones existentes este año PARA ESTE MUNICIPIO
        count_resoluciones = await db.resoluciones.count_documents({
            "año": año_actual,
            "codigo_municipio": codigo_municipio
        })
        siguiente_numero = numero_inicial + count_resoluciones + 1
        
        # Formato número de resolución
        numero_resolucion = f"RES-{depto}-{mpio}-{str(siguiente_numero).zfill(4)}-{año_actual}"
        fecha_resolucion = datetime.now().strftime("%d-%m-%Y")
        
        # Obtener plantilla M1
        plantilla = await db.resolucion_plantillas.find_one({"tipo": "M1"}, {"_id": 0})
        plantilla_textos = {}
        if plantilla:
            plantilla_textos = {
                "firmante_nombre": plantilla.get("firmante_nombre", "DALGIE ESPERANZA TORRADO RIZO"),
                "firmante_cargo": plantilla.get("firmante_cargo", "SUBDIRECTORA FINANCIERA Y ADMINISTRATIVA"),
            }
        
        # Extraer propietarios anteriores del predio original
        propietarios_anteriores = []
        datos_anteriores = {}
        predio_original = None
        if cambio.get("predio_id"):
            predio_original = await db.predios.find_one({"id": cambio.get("predio_id")}, {"_id": 0})
        # Fallback: buscar por código predial si no se encontró por id (vigencia más reciente primero)
        if not predio_original and codigo:
            predio_original = await db.predios.find_one(
                {"codigo_predial_nacional": codigo},
                {"_id": 0},
                sort=[("vigencia", -1)]
            )
        if predio_original:
            # Obtener datos de R1/R2 para la sección CANCELACIÓN
            datos_r1_r2_anterior = obtener_datos_r1_r2(predio_original)
            
            # Buscar matrícula en múltiples fuentes
            matricula_cancelacion = datos_r1_r2_anterior.get("matricula_inmobiliaria") or ""
            if not matricula_cancelacion:
                matricula_cancelacion = predio_original.get("matricula_inmobiliaria") or ""
            if not matricula_cancelacion:
                r2_regs = predio_original.get("r2_registros", [])
                if r2_regs and len(r2_regs) > 0:
                    matricula_cancelacion = r2_regs[0].get("matricula_inmobiliaria") or ""
            
            datos_anteriores = {
                "area_terreno": str(datos_r1_r2_anterior.get("area_terreno") or 0),
                "area_construida": str(datos_r1_r2_anterior.get("area_construida") or 0),
                "avaluo": f"${datos_r1_r2_anterior.get('avaluo', 0):,.0f}".replace(",", ".") if datos_r1_r2_anterior.get('avaluo') else "$0",
                "direccion": datos_r1_r2_anterior.get("direccion") or "",
                "destino_economico": datos_r1_r2_anterior.get("destino_economico") or "A",
                "codigo_homologado": datos_r1_r2_anterior.get("codigo_homologado") or "",
                "matricula_inmobiliaria": matricula_cancelacion,
            }
            if predio_original.get("propietarios"):
                for p in predio_original["propietarios"]:
                    propietarios_anteriores.append({
                        "nombre": p.get("nombre_propietario", ""),
                        "tipo_documento": p.get("tipo_documento", "CC"),
                        "documento": formatear_documento(p.get("numero_documento", "")),
                        "estado_civil": validar_estado_civil(p.get("estado_civil", "")),
                    })
            elif predio_original.get("nombre_propietario"):
                propietarios_anteriores.append({
                    "nombre": predio_original["nombre_propietario"],
                    "tipo_documento": predio_original.get("tipo_documento", "CC"),
                    "documento": formatear_documento(predio_original.get("numero_documento", "")),
                    "estado_civil": validar_estado_civil(predio_original.get("estado_civil", "")),
                })

        # Fallback: si no se encontraron propietarios anteriores del predio, buscar en la solicitud de mutación
        if not propietarios_anteriores and cambio.get("id"):
            solicitud_mut = await db.solicitudes_mutacion.find_one({"id": cambio["id"]}, {"_id": 0, "propietarios_anteriores": 1})
            if solicitud_mut and solicitud_mut.get("propietarios_anteriores"):
                for p in solicitud_mut["propietarios_anteriores"]:
                    propietarios_anteriores.append({
                        "nombre": p.get("nombre_propietario", p.get("nombre", "")),
                        "tipo_documento": p.get("tipo_documento", "CC"),
                        "documento": formatear_documento(p.get("numero_documento", p.get("documento", ""))),
                        "estado_civil": validar_estado_civil(p.get("estado_civil", "")),
                    })

        # Extraer propietarios nuevos de datos propuestos
        propietarios_nuevos = []
        if datos_propuestos.get("propietarios"):
            for p in datos_propuestos["propietarios"]:
                propietarios_nuevos.append({
                    "nombre": p.get("nombre_propietario", ""),
                    "tipo_documento": p.get("tipo_documento", "CC"),
                    "documento": formatear_documento(p.get("numero_documento", "")),
                    "estado_civil": validar_estado_civil(p.get("estado_civil", "")),
                })
        elif datos_propuestos.get("nombre_propietario"):
            propietarios_nuevos.append({
                "nombre": datos_propuestos["nombre_propietario"],
                "tipo_documento": datos_propuestos.get("tipo_documento", "CC"),
                "documento": formatear_documento(datos_propuestos.get("numero_documento", "")),
                "estado_civil": validar_estado_civil(datos_propuestos.get("estado_civil", "")),
            })
        
        # Si no hay cambio en propietarios, usar los mismos
        if not propietarios_nuevos and propietarios_anteriores:
            propietarios_nuevos = propietarios_anteriores
        
        # Obtener usuario que propuso el cambio
        elaboro = cambio.get("creado_por_nombre", "")
        if not elaboro:
            proponente = await db.users.find_one({"id": cambio.get("propuesto_por")}, {"_id": 0, "full_name": 1})
            elaboro = proponente.get("full_name", "") if proponente else ""
        
        # Generar código de verificación para el QR (igual que certificado catastral)
        codigo_verificacion_res = generar_codigo_verificacion_resolucion()
        
        # Importar y generar PDF
        from resolucion_pdf_generator import generate_resolucion_pdf
        
        # Para la sección INSCRIPCIÓN, usar datos_propuestos (datos nuevos del formulario)
        # Si no hay datos_propuestos, usar datos de R1/R2 (datos_anteriores) como fuente confiable
        # ya que en M1 los datos físicos no cambian, solo los propietarios.
        # Fallback final: campos top-level del predio combinado (datos_predio)

        # Usar la matrícula de cancelación si no hay una nueva en el formulario
        matricula_inscripcion = datos_propuestos.get("matricula_inmobiliaria") or datos_anteriores.get("matricula_inmobiliaria") or datos_predio.get("matricula_inmobiliaria") or ""

        datos_inscripcion = {
            "area_terreno": datos_propuestos.get("area_terreno") or datos_anteriores.get("area_terreno") or datos_predio.get("area_terreno") or 0,
            "area_construida": datos_propuestos.get("area_construida") or datos_anteriores.get("area_construida") or datos_predio.get("area_construida") or 0,
            "avaluo": datos_propuestos.get("avaluo") or datos_anteriores.get("avaluo") or datos_predio.get("avaluo") or 0,
            "direccion": datos_propuestos.get("direccion") or datos_anteriores.get("direccion") or datos_predio.get("direccion") or "",
            "destino_economico": datos_propuestos.get("destino_economico") or datos_anteriores.get("destino_economico") or datos_predio.get("destino_economico") or "A",
            "codigo_homologado": datos_propuestos.get("codigo_homologado") or datos_anteriores.get("codigo_homologado") or datos_predio.get("codigo_homologado") or "",
            "matricula_inmobiliaria": matricula_inscripcion,
        }
        
        pdf_bytes = generate_resolucion_pdf(
            numero_resolucion=numero_resolucion,
            fecha_resolucion=fecha_resolucion,
            municipio=datos_predio.get("municipio", ""),
            tipo_tramite="Mutación Primera",
            radicado=cambio.get("radicado", datos_predio.get("radicado", f"RASMGC-{datetime.now().strftime('%Y%m%d')}")),
            codigo_catastral_anterior=codigo[:15] if len(codigo) >= 15 else codigo,
            npn=codigo,
            # Datos de INSCRIPCIÓN (nuevos) - vienen del formulario, no de R1/R2
            matricula_inmobiliaria=matricula_inscripcion,
            direccion=datos_inscripcion.get("direccion") or "",
            avaluo=f"${datos_inscripcion.get('avaluo', 0):,.0f}".replace(",", ".") if datos_inscripcion.get('avaluo') else "$0",
            vigencia_fiscal=f"01/01/{año_actual}",
            area_terreno=str(datos_inscripcion.get("area_terreno") or 0),
            area_construida=str(datos_inscripcion.get("area_construida") or 0),
            destino_economico=datos_inscripcion.get("destino_economico") or "A",
            codigo_homologado=datos_inscripcion.get("codigo_homologado") or "",
            propietarios_anteriores=propietarios_anteriores,
            propietarios_nuevos=propietarios_nuevos,
            elaboro=elaboro,
            aprobo=aprobador.get("full_name", ""),
            plantilla=plantilla_textos,
            # Datos anteriores para la sección CANCELACIÓN (sí vienen de R1/R2)
            area_terreno_anterior=datos_anteriores.get("area_terreno"),
            area_construida_anterior=datos_anteriores.get("area_construida"),
            avaluo_anterior=datos_anteriores.get("avaluo"),
            direccion_anterior=datos_anteriores.get("direccion"),
            destino_economico_anterior=datos_anteriores.get("destino_economico"),
            codigo_homologado_anterior=datos_anteriores.get("codigo_homologado"),
            matricula_anterior=datos_anteriores.get("matricula_inmobiliaria"),
            # Código de verificación para QR idéntico al certificado catastral
            codigo_verificacion=codigo_verificacion_res,
            verificacion_base_url=VERIFICACION_BASE_URL,
        )
        
        # Crear directorio si no existe
        resoluciones_dir = "/app/uploads/resoluciones"
        import os
        os.makedirs(resoluciones_dir, exist_ok=True)

        # Guardar el PDF - Nombre simplificado: RES-XX-XXX-XXXX-XXXX.pdf
        filename = f"{numero_resolucion.replace('/', '-')}.pdf"
        filepath = f"{resoluciones_dir}/{filename}"
        with open(filepath, "wb") as f:
            f.write(pdf_bytes)
        
        # Registrar la resolución en la base de datos
        tipo_resolucion = cambio.get("tipo_mutacion") or cambio.get("tipo") or "M1"
        resolucion_doc = {
            "id": str(uuid.uuid4()),
            "numero_resolucion": numero_resolucion,
            "tipo": tipo_resolucion,
            "tipo_mutacion": tipo_resolucion,
            "año": año_actual,
            "consecutivo": siguiente_numero,
            "codigo_municipio": codigo_municipio,  # Para filtrar por municipio
            "cambio_id": cambio.get("id"),
            "predio_id": cambio.get("predio_id"),
            "codigo_predial": codigo,
            "radicado": cambio.get("radicado") or cambio.get("radicado_numero", ""),
            "municipio": datos_predio.get("municipio", ""),
            "pdf_path": f"/api/resoluciones/descargar/{filename}",
            "codigo_verificacion": codigo_verificacion_res,  # Código QR igual que certificado
            "aprobado_por": aprobador.get("id"),
            "aprobado_por_nombre": aprobador.get("full_name", ""),
            "elaborado_por": cambio.get("propuesto_por"),
            "elaborado_por_nombre": elaboro,
            "creado_por_id": cambio.get("propuesto_por"),
            "fecha_generacion": datetime.now(COLOMBIA_TZ).isoformat(),
            "fecha_resolucion": datetime.now(COLOMBIA_TZ).strftime("%Y-%m-%d"),
            "created_at": datetime.now(COLOMBIA_TZ).isoformat()
        }
        
        await db.resoluciones.insert_one(resolucion_doc.copy())
        
        # Registrar en log de actividades
        await registrar_log_actividad(
            accion="generar_resolucion",
            categoria="resoluciones",
            descripcion=f"Generó resolución {numero_resolucion} tipo M1 para {codigo}",
            usuario_id=aprobador.get("id"),
            usuario_nombre=aprobador.get("full_name"),
            usuario_rol=aprobador.get("role"),
            municipio=datos_predio.get("municipio", ""),
            detalles={
                "tipo_mutacion": "M1",
                "codigo_predial": codigo,
                "radicado": cambio.get("radicado", ""),
                "numero_resolucion": numero_resolucion
            }
        )
        
        # === GUARDAR EN CERTIFICADOS_VERIFICABLES PARA QUE EL QR FUNCIONE ===
        hora_colombia = datetime.now(COLOMBIA_TZ)
        
        verificacion_doc = {
            "id": str(uuid.uuid4()),
            "codigo_verificacion": codigo_verificacion_res,
            "tipo_documento": "resolucion",
            "tipo": "RESOLUCION_M1",
            "numero_resolucion": numero_resolucion,
            "predio_id": cambio.get("predio_id"),
            "codigo_predial": codigo,
            "municipio": datos_predio.get("municipio", ""),
            "direccion": datos_predio.get("direccion", "Sin dirección"),
            "matricula_inmobiliaria": datos_r1_r2_anterior.get("matricula_inmobiliaria") if predio_original else datos_predio.get("matricula_inmobiliaria", ""),
            "propietarios": [datos_predio.get("nombre_propietario", "")] if datos_predio.get("nombre_propietario") else [],
            "area_terreno": str(datos_predio.get("area_terreno", datos_predio.get("area_terreno_r1", 0))),
            "avaluo_catastral": f"${datos_predio.get('avaluo', 0):,.0f}".replace(",", "."),
            "fecha_generacion": hora_colombia.isoformat(),
            "fecha_vencimiento": (hora_colombia + timedelta(days=365)).isoformat(),  # 1 año de validez
            "estado": "activo",
            "generado_por": aprobador.get("id"),
            "generado_por_nombre": aprobador.get("full_name", ""),
            "pdf_path": f"/api/resoluciones/descargar/{filename}",
            "created_at": hora_colombia.isoformat()
        }
        await db.certificados_verificables.insert_one(verificacion_doc.copy())
        
        logging.info(f"Resolución {numero_resolucion} generada y guardada en {filepath}")
        
        # === APLICAR CAMBIOS Y AGREGAR HISTORIAL DE RESOLUCIÓN AL PREDIO ===
        try:
            predio_id = cambio.get("predio_id")
            if predio_id:
                historial_entry = {
                    "tipo": "M1",
                    "tipo_mutacion": "M1",
                    "fecha": datetime.now(COLOMBIA_TZ).isoformat(),
                    "resolucion": numero_resolucion,
                    "numero_resolucion": numero_resolucion,
                    "fecha_resolucion": datetime.now(COLOMBIA_TZ).strftime("%Y-%m-%d"),
                    "radicado": cambio.get("radicado", cambio.get("radicado_numero", "")),
                    "pdf_path": f"/api/resoluciones/descargar/{filename}",
                    "generado_por": aprobador.get("full_name", ""),
                    "descripcion": "Cambio de propietario",
                    "propietarios_anteriores": propietarios_anteriores,
                    "propietarios_nuevos": propietarios_nuevos,
                    "aprobado_por": aprobador.get("full_name", "")
                }

                # Convertir propietarios_nuevos al formato de la colección predios
                propietarios_para_predio = []
                for p in propietarios_nuevos:
                    propietarios_para_predio.append({
                        "nombre_propietario": p.get("nombre", p.get("nombre_propietario", "")),
                        "tipo_documento": p.get("tipo_documento", "CC"),
                        "numero_documento": formatear_documento(p.get("documento", p.get("numero_documento", ""))),
                        "estado_civil": validar_estado_civil(p.get("estado_civil", "")),
                        "derecho": p.get("derecho", ""),
                    })

                # Si no hay propietarios formateados, usar los originales de datos_propuestos
                if not propietarios_para_predio and datos_propuestos.get("propietarios"):
                    propietarios_para_predio = datos_propuestos["propietarios"]

                update_set = {
                    "ultima_actualizacion": datetime.now(COLOMBIA_TZ).isoformat(),
                    "updated_at": datetime.now(COLOMBIA_TZ).isoformat(),
                }

                # Aplicar propietarios nuevos al predio
                if propietarios_para_predio:
                    update_set["propietarios"] = propietarios_para_predio
                    logging.info(f"✅ Aplicando {len(propietarios_para_predio)} propietarios nuevos al predio {predio_id}")

                # Intentar actualizar por id, si no funciona, por codigo_predial_nacional
                result = await db.predios.update_one(
                    {"id": predio_id},
                    {
                        "$push": {"historial_resoluciones": historial_entry},
                        "$set": update_set
                    }
                )
                if result.matched_count == 0 and codigo:
                    # Fallback: buscar por código predial en la vigencia más reciente
                    predio_fallback = await db.predios.find_one(
                        {"codigo_predial_nacional": codigo},
                        {"_id": 0, "id": 1, "vigencia": 1},
                        sort=[("vigencia", -1)]
                    )
                    if predio_fallback:
                        result = await db.predios.update_one(
                            {"id": predio_fallback["id"]},
                            {
                                "$push": {"historial_resoluciones": historial_entry},
                                "$set": update_set
                            }
                        )
                        logging.info(f"✅ Predio actualizado por codigo_predial_nacional: {codigo} (vigencia {predio_fallback.get('vigencia')}, id={predio_fallback['id']})")
                    else:
                        logging.warning(f"⚠️ No se encontró predio ni por id={predio_id} ni por codigo={codigo}")
                else:
                    logging.info(f"✅ Historial de resolución M1 y propietarios actualizados en predio {predio_id}")
        except Exception as hist_error:
            logging.error(f"Error agregando historial M1 al predio: {str(hist_error)}")
        
        # === ENVIAR CORREO CON LA RESOLUCIÓN AL PROPIETARIO/SOLICITANTE ===
        try:
            # Buscar si hay una petición asociada para obtener el correo del solicitante
            peticion = None
            radicado = cambio.get("radicado", cambio.get("radicado_numero", ""))
            if radicado:
                peticion = await db.petitions.find_one({"radicado": radicado}, {"_id": 0})
            
            # Determinar correo del solicitante: primero petición, luego solicitud de mutación
            email_solicitante = None
            nombre_solicitante = "Estimado usuario"

            if peticion and peticion.get("correo"):
                email_solicitante = peticion.get("correo")
                nombre_solicitante = peticion.get("nombre_completo", nombre_solicitante)

            # Fallback: buscar en la solicitud de mutación asociada
            if not email_solicitante and cambio.get("id"):
                sol_mutacion = await db.solicitudes_mutacion.find_one({"id": cambio["id"]}, {"_id": 0, "solicitante": 1, "correo_solicitante": 1})
                if sol_mutacion:
                    sol_data = sol_mutacion.get("solicitante", {})
                    email_solicitante = sol_mutacion.get("correo_solicitante") or sol_data.get("correo") or sol_data.get("email")
                    nombre_solicitante = sol_data.get("nombre", sol_data.get("nombre_completo", nombre_solicitante))

            if email_solicitante:
                # Generar el contenido del correo
                email_body = get_resolucion_aprobada_email(
                    numero_resolucion=numero_resolucion,
                    radicado=radicado,
                    nombre_solicitante=nombre_solicitante,
                    municipio=datos_predio.get("municipio", ""),
                    codigo_predio=codigo,
                    tipo_mutacion="M1"
                )

                # Enviar correo con el PDF adjunto
                await send_email(
                    to_email=email_solicitante,
                    subject=f"Resolución Aprobada - {numero_resolucion}",
                    body=email_body,
                    attachment_path=filepath,
                    attachment_name=f"{numero_resolucion.replace('/', '-')}.pdf"
                )

                logging.info(f"Correo de resolución enviado a {email_solicitante}")
            else:
                logging.info(f"No se encontró correo de solicitante para enviar resolución {numero_resolucion}")

            # === FINALIZAR LA PETICIÓN ===
            if peticion:
                await db.petitions.update_one(
                    {"radicado": radicado},
                    {
                        "$set": {
                            "status": "completado",
                            "estado": "finalizado",
                            "estado_tramite": "Finalizado",
                            "resolucion_numero": numero_resolucion,
                            "resolucion_pdf": f"/api/resoluciones/descargar/{filename}",
                            "fecha_finalizacion": datetime.now(COLOMBIA_TZ).isoformat(),
                            "updated_at": datetime.now(COLOMBIA_TZ).isoformat()
                        },
                        "$push": {
                            "archivos_staff": {
                                "id": f"res-{str(uuid.uuid4())[:8]}",
                                "filename": filename,
                                "original_name": f"Resolución {numero_resolucion}.pdf",
                                "path": filepath,
                                "uploaded_by": "sistema",
                                "uploaded_by_name": "Sistema - Resolución aprobada",
                                "uploaded_by_role": "sistema",
                                "upload_date": datetime.now(COLOMBIA_TZ).isoformat(),
                                "es_documento_final": True,
                                "es_resolucion": True,
                                "numero_resolucion": numero_resolucion,
                                "pdf_url": f"/api/resoluciones/descargar/{filename}"
                            }
                        }
                    }
                )
                logging.info(f"Petición {radicado} finalizada con resolución {numero_resolucion}")

        except Exception as email_error:
            logging.error(f"Error enviando correo de resolución: {str(email_error)}")
            # No interrumpir el flujo si falla el envío de correo
        
        import base64 as b64mod
        pdf_base64 = b64mod.b64encode(pdf_bytes).decode('utf-8')

        return {
            "id": resolucion_doc['id'],
            "numero_resolucion": numero_resolucion,
            "pdf_url": f"/api/resoluciones/descargar/{filename}",
            "pdf_path": f"/api/resoluciones/descargar/{filename}",
            "pdf_base64": pdf_base64,
            "consecutivo": siguiente_numero,
            "tipo_mutacion": "M1",
            "fecha_generacion": datetime.now(COLOMBIA_TZ).isoformat()
        }

    except Exception as e:
        logging.error(f"Error en generar_resolucion_final: {str(e)}")
        import traceback
        traceback.print_exc()
        return None


# ========================================
# FUNCIONES INTERNAS PARA GENERAR RESOLUCIONES M2/M3
# ========================================

async def _generar_resolucion_m2_interno(solicitud: dict, aprobador: dict) -> dict:
    """
    Genera resolución M2 (Desenglobe) y aplica los cambios a los predios.
    Usado internamente cuando se aprueba una solicitud de mutación M2.
    """
    try:
        from resolucion_m2_pdf_generator import generate_resolucion_m2_pdf
        
        # Obtener datos de la solicitud
        municipio = solicitud.get('municipio', '')
        radicado = solicitud.get('radicado', '')
        predios_cancelados = solicitud.get('predios_cancelados', [])
        predios_inscritos = solicitud.get('predios_inscritos', [])
        solicitante = solicitud.get('solicitante') or {"nombre": "No especificado", "documento": ""}
        
        # === VERIFICAR SI ALGÚN PREDIO ESTÁ BLOQUEADO ===
        for predio_data in predios_cancelados:
            predio_id = predio_data.get('id') or predio_data.get('predio_id')
            if predio_id:
                bloqueo_check = await verificar_predio_bloqueado(predio_id)
                if bloqueo_check.get("bloqueado"):
                    bloqueo_info = bloqueo_check.get("info", {})
                    raise Exception(
                        f"El predio {predio_data.get('codigo_predial_nacional', predio_id)} está bloqueado. "
                        f"Motivo: {bloqueo_info.get('motivo', 'No especificado')}. "
                        f"Contacte al coordinador."
                    )
        
        # Obtener nombre del municipio
        municipio_nombre = MUNICIPIOS_POR_CODIGO.get(municipio, {}).get('nombre', municipio)
        
        # Generar número de resolución
        resultado_resolucion = await obtener_siguiente_numero_resolucion(municipio)
        numero_resolucion = resultado_resolucion.get("numero_resolucion", f"RES-XX-XXX-0000-{datetime.now().year}")
        fecha_resolucion = resultado_resolucion.get("fecha_resolucion", datetime.now().strftime("%d/%m/%Y"))
        
        # Generar código de verificación para QR
        codigo_verificacion_m2 = generar_codigo_verificacion_resolucion()
        
        # Preparar datos para el PDF
        pdf_data = {
            "numero_resolucion": numero_resolucion,
            "fecha_resolucion": fecha_resolucion,
            "municipio": municipio_nombre,
            "radicado": radicado,
            "predios_cancelados": predios_cancelados,
            "predios_inscritos": predios_inscritos,
            "solicitante": solicitante,
            "observaciones": solicitud.get('observaciones', ''),
            "elaborado_por": solicitud.get('creado_por_nombre') or aprobador.get("full_name", ""),
            "revisado_por": aprobador.get("full_name", ""),
            "codigo_verificacion": codigo_verificacion_m2
        }
        
        # Crear directorio si no existe
        resoluciones_dir = "/app/uploads/resoluciones"
        os.makedirs(resoluciones_dir, exist_ok=True)
        
        # Generar nombre del archivo - Simplificado: RES-XX-XXX-XXXX-XXXX.pdf
        filename = f"{numero_resolucion.replace('/', '-').replace(' ', '_')}.pdf"
        filepath = os.path.join(resoluciones_dir, filename)
        
        # Generar PDF - llamar con parámetros individuales
        pdf_bytes = generate_resolucion_m2_pdf(
            numero_resolucion=numero_resolucion,
            fecha_resolucion=fecha_resolucion,
            municipio=municipio_nombre,
            subtipo=solicitud.get('subtipo', 'desengloble'),
            radicado=radicado,
            solicitante=solicitante,
            predios_cancelados=predios_cancelados,
            predios_inscritos=predios_inscritos,
            elaboro=solicitud.get('creado_por_nombre') or aprobador.get("full_name", ""),
            aprobo=aprobador.get("full_name", ""),
            texto_considerando=solicitud.get('texto_considerando')
        )
        with open(filepath, 'wb') as f:
            f.write(pdf_bytes)
        
        # ========================================
        # APLICAR CAMBIOS A LOS PREDIOS
        # ========================================
        
        # 1. Procesar predios cancelados según tipo_cancelacion
        for predio_cancelado in predios_cancelados:
            predio_id = predio_cancelado.get('id')
            npn_cancelado = predio_cancelado.get('npn') or predio_cancelado.get('codigo_predial_nacional') or predio_cancelado.get('codigo_predial')
            tipo_cancelacion = predio_cancelado.get('tipo_cancelacion', 'total')
            
            # Buscar el predio por ID o por NPN
            query_predio = {"id": predio_id} if predio_id else {"codigo_predial_nacional": npn_cancelado}
            predio_original = await db.predios.find_one(query_predio, {"_id": 0})
            
            if not predio_original:
                logging.warning(f"No se encontró el predio a cancelar: id={predio_id}, npn={npn_cancelado}")
                continue
            
            predio_id_real = predio_original.get('id')
            
            if tipo_cancelacion == 'total':
                # Cancelación TOTAL: mover a predios_eliminados y marcar como eliminado
                predio_eliminado = {
                    **predio_original,
                    "motivo_eliminacion": f"Desenglobe - Resolución {numero_resolucion}",
                    "fecha_eliminacion": datetime.now(COLOMBIA_TZ).isoformat(),
                    "eliminado_en": datetime.now(COLOMBIA_TZ).isoformat(),
                    "eliminado_por": aprobador.get('id'),
                    "eliminado_por_nombre": aprobador.get('full_name'),
                    "resolucion_eliminacion": numero_resolucion,
                    "solicitud_id": solicitud.get('id'),
            "creado_por_id": solicitud.get('creado_por_id'),
                    "vigencia_origen": predio_original.get('vigencia', datetime.now().year),
                    "vigencia_eliminacion": datetime.now().year
                }
                await db.predios_eliminados.insert_one(predio_eliminado)
                
                # Marcar como deleted en predios
                await db.predios.update_one(
                    {"id": predio_id_real},
                    {"$set": {
                        "deleted": True,
                        "status": "cancelado",
                        "motivo_eliminacion": f"Desenglobe - Resolución {numero_resolucion}",
                        "fecha_eliminacion": datetime.now(COLOMBIA_TZ).isoformat()
                    }}
                )
                logging.info(f"Predio {npn_cancelado} cancelado TOTALMENTE (moved to predios_eliminados)")
            
            elif tipo_cancelacion == 'parcial':
                # Cancelación PARCIAL: actualizar predio con nuevos datos
                update_data = {
                    "area_terreno": predio_cancelado.get('nueva_area_terreno', predio_cancelado.get('area_terreno')),
                    "area_construida": predio_cancelado.get('nueva_area_construida', predio_cancelado.get('area_construida')),
                    "avaluo": predio_cancelado.get('nuevo_avaluo', predio_cancelado.get('avaluo')),
                    "area_editada_en_plataforma": True,
                    "updated_at": datetime.now(COLOMBIA_TZ).isoformat(),
                    "historial": (predio_original.get("historial") or []) + [{
                        "accion": "Cancelación parcial por Desenglobe (M2)",
                        "tipo_cambio": "desenglobe_parcial",
                        "usuario": aprobador.get('full_name'),
                        "usuario_id": aprobador.get('id'),
                        "fecha": datetime.now(COLOMBIA_TZ).isoformat(),
                        "numero_resolucion": numero_resolucion,
                        "area_anterior": predio_original.get('area_terreno'),
                        "area_nueva": predio_cancelado.get('nueva_area_terreno')
                    }]
                }
                
                # Si hay propietarios editados, actualizarlos
                if predio_cancelado.get('propietarios'):
                    update_data["propietarios"] = predio_cancelado['propietarios']
                
                await db.predios.update_one(
                    {"id": predio_id_real},
                    {"$set": update_data}
                )
                logging.info(f"Predio {npn_cancelado} actualizado PARCIALMENTE (área ajustada)")
        
        # 2. Crear predios inscritos
        for predio_nuevo in predios_inscritos:
            predio_doc = {
                **predio_nuevo,
                "id": predio_nuevo.get('id') or str(uuid.uuid4()),
                "status": "aprobado",
                "estado_aprobacion": PredioEstadoAprobacion.APROBADO,
                "deleted": False,
                "created_at": datetime.now(COLOMBIA_TZ).isoformat(),
                "updated_at": datetime.now(COLOMBIA_TZ).isoformat(),
                "tipo_mutacion": "Mutación Segunda (Desenglobe)",
                "numero_resolucion": numero_resolucion,
                "fecha_resolucion": fecha_resolucion,
                "solicitud_id": solicitud.get('id'),
            "creado_por_id": solicitud.get('creado_por_id'),
                "historial": [{
                    "accion": "Predio creado por Desenglobe (M2)",
                    "tipo_cambio": "desenglobe",
                    "usuario": aprobador.get('full_name'),
                    "usuario_id": aprobador.get('id'),
                    "fecha": datetime.now(COLOMBIA_TZ).isoformat(),
                    "numero_resolucion": numero_resolucion
                }]
            }
            
            # Verificar si el predio ya existe
            existente = await db.predios.find_one({"id": predio_doc['id']}, {"_id": 0})
            if existente:
                await db.predios.update_one(
                    {"id": predio_doc['id']},
                    {"$set": predio_doc}
                )
            else:
                await db.predios.insert_one(predio_doc)
        
        # Guardar resolución en la colección
        resolucion_doc = {
            "id": str(uuid.uuid4()),
            "numero_resolucion": numero_resolucion,
            "fecha_resolucion": fecha_resolucion,
            "tipo": "M2",
            "tipo_mutacion": "M2",
            "subtipo": solicitud.get('subtipo', 'desenglobe'),
            "municipio": municipio_nombre,
            "codigo_municipio": municipio,
            "radicado": radicado,
            "solicitud_id": solicitud.get('id'),
            "creado_por_id": solicitud.get('creado_por_id'),
            "predios_cancelados": [p.get('codigo_predial_nacional') for p in predios_cancelados],
            "predios_inscritos": [p.get('codigo_predial_nacional') for p in predios_inscritos],
            "pdf_path": f"/api/resoluciones/descargar/{filename}",
            "generado_por": aprobador.get('id'),
            "generado_por_nombre": aprobador.get('full_name'),
            "elaborado_por": solicitud.get('creado_por_id'),
            "elaborado_por_nombre": solicitud.get('creado_por_nombre', ''),
            "aprobado_por": aprobador.get('id'),
            "aprobado_por_nombre": aprobador.get('full_name', ''),
            "fecha_generacion": datetime.now(COLOMBIA_TZ).isoformat(),
            "created_at": datetime.now(COLOMBIA_TZ).isoformat(),
            "año": datetime.now().year,
            "codigo_verificacion": codigo_verificacion_m2
        }
        await db.resoluciones.insert_one(resolucion_doc)
        
        # Registrar en certificados_verificables para que el QR funcione
        verificable_m2 = {
            "codigo_verificacion": codigo_verificacion_m2,
            "tipo": "RESOLUCION_M2",
            "subtipo": solicitud.get('subtipo', 'desenglobe').upper(),
            "numero_resolucion": numero_resolucion,
            "municipio": municipio_nombre,
            "fecha_resolucion": fecha_resolucion,
            "radicado": radicado,
            "solicitante": solicitante,
            "predios_cancelados": len(predios_cancelados),
            "predios_inscritos": len(predios_inscritos),
            "pdf_url": f"/api/resoluciones/descargar/{filename}",
            "generado_por": aprobador.get('full_name'),
            "fecha_generacion": datetime.now(COLOMBIA_TZ).isoformat()
        }
        await db.certificados_verificables.insert_one(verificable_m2)
        
        # Registrar en log de actividades
        await registrar_log_actividad(
            accion="generar_resolucion",
            categoria="resoluciones",
            descripcion=f"Generó resolución {numero_resolucion} tipo M2 (Desenglobe) para {municipio_nombre}",
            usuario_id=aprobador.get("id"),
            usuario_nombre=aprobador.get("full_name"),
            usuario_rol=aprobador.get("role"),
            municipio=municipio_nombre,
            detalles={
                "tipo_mutacion": "M2",
                "subtipo": "desenglobe",
                "numero_resolucion": numero_resolucion,
                "predios_cancelados": len(predios_cancelados),
                "predios_inscritos": len(predios_inscritos)
            }
        )
        
        # === FINALIZAR PETICIÓN Y ENVIAR CORREO ===
        if radicado:
            peticion = await db.petitions.find_one({"radicado": radicado}, {"_id": 0})
            if peticion:
                await db.petitions.update_one(
                    {"radicado": radicado},
                    {
                        "$set": {
                            "status": "completado",
                            "estado": "finalizado",
                            "estado_tramite": "Finalizado",
                            "resolucion_numero": numero_resolucion,
                            "resolucion_pdf": f"/api/resoluciones/descargar/{filename}",
                            "fecha_finalizacion": datetime.now(COLOMBIA_TZ).isoformat(),
                            "updated_at": datetime.now(COLOMBIA_TZ).isoformat()
                        },
                        "$push": {
                            "archivos_staff": {
                                "id": f"res-{str(uuid.uuid4())[:8]}",
                                "filename": filename,
                                "original_name": f"Resolución {numero_resolucion}.pdf",
                                "path": filepath,
                                "uploaded_by": "sistema",
                                "uploaded_by_name": "Sistema - Resolución aprobada",
                                "uploaded_by_role": "sistema",
                                "upload_date": datetime.now(COLOMBIA_TZ).isoformat(),
                                "es_documento_final": True,
                                "es_resolucion": True,
                                "numero_resolucion": numero_resolucion,
                                "pdf_url": f"/api/resoluciones/descargar/{filename}"
                            }
                        }
                    }
                )
                logging.info(f"Petición {radicado} finalizada con resolución M2 {numero_resolucion}")

        # Enviar correo al solicitante
        try:
            email_solicitante = None
            nombre_solicitante = "Estimado usuario"

            # Primero buscar en petición
            if radicado:
                peticion_email = await db.petitions.find_one({"radicado": radicado}, {"_id": 0, "correo": 1, "nombre_completo": 1})
                if peticion_email and peticion_email.get("correo"):
                    email_solicitante = peticion_email["correo"]
                    nombre_solicitante = peticion_email.get("nombre_completo", nombre_solicitante)

            # Fallback: solicitud de mutación
            if not email_solicitante:
                sol_data = solicitud.get("solicitante", {})
                email_solicitante = solicitud.get("correo_solicitante") or sol_data.get("correo") or sol_data.get("email")
                nombre_solicitante = sol_data.get("nombre", sol_data.get("nombre_completo", nombre_solicitante))

            if email_solicitante:
                email_body = get_resolucion_aprobada_email(
                    numero_resolucion=numero_resolucion,
                    radicado=radicado,
                    nombre_solicitante=nombre_solicitante,
                    municipio=municipio_nombre,
                    codigo_predio=predios_cancelados[0].get('codigo_predial_nacional', '') if predios_cancelados else '',
                    tipo_mutacion="Desenglobe (M2)"
                )

                await send_email(
                    to_email=email_solicitante,
                    subject=f"Resolución de Desenglobe Aprobada - {numero_resolucion}",
                    body=email_body,
                    attachment_path=filepath,
                    attachment_name=f"{numero_resolucion.replace('/', '-')}.pdf"
                )
                logging.info(f"✅ Correo de resolución M2 enviado a {email_solicitante}")
            else:
                logging.info(f"No se encontró correo de solicitante para resolución M2 {numero_resolucion}")
        except Exception as email_error:
            logging.error(f"Error enviando correo M2: {str(email_error)}")
        
        return {
            "success": True,
            "id": resolucion_doc['id'],
            "numero_resolucion": numero_resolucion,
            "pdf_url": f"/api/resoluciones/descargar/{filename}",
            "pdf_path": f"/api/resoluciones/descargar/{filename}",
            "predios_creados": len(predios_inscritos),
            "predios_cancelados": len(predios_cancelados)
        }
        
    except Exception as e:
        logging.error(f"Error en _generar_resolucion_m2_interno: {str(e)}")
        import traceback
        traceback.print_exc()
        raise


async def _generar_resolucion_m3_interno(solicitud: dict, aprobador: dict) -> dict:
    """
    Genera resolución M3 (Cambio destino / Incorporación construcción) y aplica los cambios.
    Usado internamente cuando se aprueba una solicitud de mutación M3.
    """
    try:
        from resolucion_m3_pdf_generator import generate_resolucion_m3_pdf
        
        # Obtener datos de la solicitud
        municipio = solicitud.get('municipio', '')
        radicado = solicitud.get('radicado', '')
        predio_id = solicitud.get('predio_id', '')
        subtipo = solicitud.get('subtipo', '')  # cambio_destino o incorporacion_construccion
        
        # === VERIFICAR SI EL PREDIO ESTÁ BLOQUEADO ===
        if predio_id:
            bloqueo_check = await verificar_predio_bloqueado(predio_id)
            if bloqueo_check.get("bloqueado"):
                bloqueo_info = bloqueo_check.get("info", {})
                raise Exception(
                    f"El predio está bloqueado por proceso legal. "
                    f"Motivo: {bloqueo_info.get('motivo', 'No especificado')}. "
                    f"Bloqueado por: {bloqueo_info.get('bloqueado_por_nombre', 'Desconocido')}"
                )
        
        # Obtener predio
        predio = await db.predios.find_one({"id": predio_id}, {"_id": 0})
        if not predio:
            raise Exception(f"Predio no encontrado: {predio_id}")
        
        # Obtener nombre del municipio
        municipio_nombre = MUNICIPIOS_POR_CODIGO.get(municipio, {}).get('nombre', municipio)
        
        # Generar número de resolución
        resultado_resolucion = await obtener_siguiente_numero_resolucion(municipio)
        numero_resolucion = resultado_resolucion.get("numero_resolucion", f"RES-XX-XXX-0000-{datetime.now().year}")
        fecha_resolucion = resultado_resolucion.get("fecha_resolucion", datetime.now().strftime("%d/%m/%Y"))
        
        # Generar código de verificación para QR
        codigo_verificacion_m3 = generar_codigo_verificacion_resolucion()
        
        # Preparar fechas de inscripción
        fechas_inscripcion = solicitud.get('fechas_inscripcion') or [
            {"año": datetime.now().year, "avaluo": solicitud.get('avaluo_nuevo', 0), "avaluo_source": "actual"}
        ]
        
        # Preparar datos para el PDF
        pdf_data = {
            "numero_resolucion": numero_resolucion,
            "fecha_resolucion": fecha_resolucion,
            "municipio": municipio_nombre,
            "subtipo": subtipo,
            "radicado": radicado,
            "predio": predio,
            "destino_anterior": solicitud.get('destino_anterior') or predio.get('destino_economico', 'R'),
            "destino_nuevo": solicitud.get('destino_nuevo'),
            "construcciones_nuevas": solicitud.get('construcciones_nuevas') or [],
            "avaluo_anterior": solicitud.get('avaluo_anterior', 0),
            "avaluo_nuevo": solicitud.get('avaluo_nuevo', 0),
            "fechas_inscripcion": fechas_inscripcion,
            "solicitante": solicitud.get('solicitante') or {"nombre": "No especificado", "documento": ""},
            "elaborado_por": solicitud.get('creado_por_nombre') or aprobador.get("full_name", ""),
            "revisado_por": aprobador.get("full_name", ""),
            "codigo_verificacion": codigo_verificacion_m3,
            "texto_considerando": solicitud.get('texto_considerando')  # Texto personalizado para considerandos
        }
        
        # Crear directorio si no existe
        resoluciones_dir = "/app/uploads/resoluciones"
        os.makedirs(resoluciones_dir, exist_ok=True)
        
        # Generar nombre del archivo - Simplificado
        filename = f"{numero_resolucion.replace('/', '-').replace(' ', '_')}.pdf"
        filepath = os.path.join(resoluciones_dir, filename)
        
        # Generar PDF
        pdf_bytes = generate_resolucion_m3_pdf(pdf_data)
        with open(filepath, 'wb') as f:
            f.write(pdf_bytes)
        
        # ========================================
        # APLICAR CAMBIOS AL PREDIO
        # ========================================
        
        update_predio = {
            "updated_at": datetime.now(COLOMBIA_TZ).isoformat(),
            "avaluo": solicitud.get('avaluo_nuevo', predio.get('avaluo', 0)),
        }
        
        historial_entry = {
            "accion": f"Mutación M3 ({subtipo}) aprobada",
            "tipo_cambio": f"m3_{subtipo}",
            "usuario": aprobador.get('full_name'),
            "usuario_id": aprobador.get('id'),
            "fecha": datetime.now(COLOMBIA_TZ).isoformat(),
            "numero_resolucion": numero_resolucion,
            "cambio_id": solicitud.get('id')
        }
        
        if subtipo == "cambio_destino":
            # Cambiar destino económico
            destino_anterior = predio.get('destino_economico', '')
            destino_nuevo = solicitud.get('destino_nuevo', '')
            
            update_predio["destino_economico"] = destino_nuevo
            historial_entry["detalles"] = {
                "destino_anterior": destino_anterior,
                "destino_nuevo": destino_nuevo,
                "avaluo_anterior": solicitud.get('avaluo_anterior', 0),
                "avaluo_nuevo": solicitud.get('avaluo_nuevo', 0)
            }
            
        elif subtipo == "incorporacion_construccion":
            # Agregar construcciones al R2
            construcciones_nuevas = solicitud.get('construcciones_nuevas', [])
            r2_actuales = predio.get('r2_registros', [])
            
            # Agregar las nuevas construcciones
            for const in construcciones_nuevas:
                r2_actuales.append({
                    **const,
                    "fecha_incorporacion": datetime.now(COLOMBIA_TZ).isoformat(),
                    "resolucion": numero_resolucion
                })
            
            # Recalcular área construida total
            area_construida_total = sum(c.get('area_construida', 0) for c in r2_actuales)
            
            update_predio["r2_registros"] = r2_actuales
            update_predio["area_construida"] = area_construida_total
            
            historial_entry["detalles"] = {
                "construcciones_agregadas": len(construcciones_nuevas),
                "area_total_nueva": area_construida_total,
                "avaluo_anterior": solicitud.get('avaluo_anterior', 0),
                "avaluo_nuevo": solicitud.get('avaluo_nuevo', 0)
            }
        
        # Aplicar actualización al predio
        await db.predios.update_one(
            {"id": predio_id},
            {
                "$set": update_predio,
                "$push": {"historial": historial_entry}
            }
        )
        
        # Guardar resolución en la colección
        resolucion_doc = {
            "id": str(uuid.uuid4()),
            "numero_resolucion": numero_resolucion,
            "fecha_resolucion": fecha_resolucion,
            "tipo": "M3",
            "tipo_mutacion": "M3",
            "subtipo": subtipo,
            "municipio": municipio_nombre,
            "codigo_municipio": municipio,
            "radicado": radicado,
            "solicitud_id": solicitud.get('id'),
            "creado_por_id": solicitud.get('creado_por_id'),
            "predio_id": predio_id,
            "codigo_predial": predio.get('codigo_predial_nacional'),
            "pdf_path": f"/api/resoluciones/descargar/{filename}",
            "generado_por": aprobador.get('id'),
            "generado_por_nombre": aprobador.get('full_name'),
            "elaborado_por": solicitud.get('creado_por_id'),
            "elaborado_por_nombre": solicitud.get('creado_por_nombre', ''),
            "aprobado_por": aprobador.get('id'),
            "aprobado_por_nombre": aprobador.get('full_name', ''),
            "fecha_generacion": datetime.now(COLOMBIA_TZ).isoformat(),
            "created_at": datetime.now(COLOMBIA_TZ).isoformat(),
            "año": datetime.now().year,
            "codigo_verificacion": codigo_verificacion_m3
        }
        await db.resoluciones.insert_one(resolucion_doc)
        
        # Registrar en certificados_verificables para que el QR funcione
        verificable_m3 = {
            "codigo_verificacion": codigo_verificacion_m3,
            "tipo": "RESOLUCION_M3",
            "subtipo": subtipo.upper() if subtipo else "CAMBIO",
            "numero_resolucion": numero_resolucion,
            "municipio": municipio_nombre,
            "fecha_resolucion": fecha_resolucion,
            "radicado": radicado,
            "predio_codigo": predio.get('codigo_predial_nacional'),
            "predio_direccion": predio.get('direccion', ''),
            "pdf_url": f"/api/resoluciones/descargar/{filename}",
            "generado_por": aprobador.get('full_name'),
            "fecha_generacion": datetime.now(COLOMBIA_TZ).isoformat()
        }
        await db.certificados_verificables.insert_one(verificable_m3)
        
        # Registrar en log de actividades
        await registrar_log_actividad(
            accion="generar_resolucion",
            categoria="resoluciones",
            descripcion=f"Generó resolución {numero_resolucion} tipo M3 ({subtipo}) para {municipio_nombre}",
            usuario_id=aprobador.get("id"),
            usuario_nombre=aprobador.get("full_name"),
            usuario_rol=aprobador.get("role"),
            municipio=municipio_nombre,
            detalles={
                "tipo_mutacion": "M3",
                "subtipo": subtipo,
                "predio_id": predio_id,
                "codigo_predial": predio.get('codigo_predial_nacional'),
                "numero_resolucion": numero_resolucion
            }
        )
        
        # === FINALIZAR LA PETICIÓN RELACIONADA Y ENVIAR CORREO ===
        if radicado:
            peticion = await db.petitions.find_one({"radicado": radicado}, {"_id": 0})
            if peticion:
                await db.petitions.update_one(
                    {"radicado": radicado},
                    {
                        "$set": {
                            "status": "completado",
                            "estado": "finalizado",
                            "estado_tramite": "Finalizado",
                            "resolucion_numero": numero_resolucion,
                            "resolucion_pdf": f"/api/resoluciones/descargar/{filename}",
                            "fecha_finalizacion": datetime.now(COLOMBIA_TZ).isoformat(),
                            "updated_at": datetime.now(COLOMBIA_TZ).isoformat()
                        },
                        "$push": {
                            "archivos_staff": {
                                "id": f"res-{str(uuid.uuid4())[:8]}",
                                "filename": filename,
                                "original_name": f"Resolución {numero_resolucion}.pdf",
                                "path": filepath,
                                "uploaded_by": "sistema",
                                "uploaded_by_name": "Sistema - Resolución aprobada",
                                "uploaded_by_role": "sistema",
                                "upload_date": datetime.now(COLOMBIA_TZ).isoformat(),
                                "es_documento_final": True,
                                "es_resolucion": True,
                                "numero_resolucion": numero_resolucion,
                                "pdf_url": f"/api/resoluciones/descargar/{filename}"
                            }
                        }
                    }
                )
                logging.info(f"Petición {radicado} finalizada con resolución M3 {numero_resolucion}")

        # Enviar correo al solicitante
        try:
            email_solicitante = None
            nombre_solicitante = "Estimado usuario"

            # Primero buscar en petición
            if radicado:
                peticion_email = await db.petitions.find_one({"radicado": radicado}, {"_id": 0, "correo": 1, "nombre_completo": 1})
                if peticion_email and peticion_email.get("correo"):
                    email_solicitante = peticion_email["correo"]
                    nombre_solicitante = peticion_email.get("nombre_completo", nombre_solicitante)

            # Fallback: solicitud de mutación
            if not email_solicitante:
                sol_data = solicitud.get("solicitante", {})
                email_solicitante = solicitud.get("correo_solicitante") or sol_data.get("correo") or sol_data.get("email")
                nombre_solicitante = sol_data.get("nombre", sol_data.get("nombre_completo", nombre_solicitante))

            if email_solicitante:
                tipo_texto = "Cambio de Destino" if subtipo == "cambio_destino" else "Incorporación de Construcción"
                email_body = get_resolucion_aprobada_email(
                    numero_resolucion=numero_resolucion,
                    radicado=radicado,
                    nombre_solicitante=nombre_solicitante,
                    municipio=municipio_nombre,
                    codigo_predio=predio.get('codigo_predial_nacional', ''),
                    tipo_mutacion=f"{tipo_texto} (M3)"
                )

                await send_email(
                    to_email=email_solicitante,
                    subject=f"Resolución {tipo_texto} Aprobada - {numero_resolucion}",
                    body=email_body,
                    attachment_path=filepath,
                    attachment_name=f"{numero_resolucion.replace('/', '-')}.pdf"
                )
                logging.info(f"✅ Correo de resolución M3 enviado a {email_solicitante}")
            else:
                logging.info(f"No se encontró correo de solicitante para resolución M3 {numero_resolucion}")
        except Exception as email_error:
            logging.error(f"Error enviando correo M3: {str(email_error)}")
        
        return {
            "success": True,
            "id": resolucion_doc['id'],
            "numero_resolucion": numero_resolucion,
            "pdf_url": f"/api/resoluciones/descargar/{filename}",
            "pdf_path": f"/api/resoluciones/descargar/{filename}"
        }
        
    except Exception as e:
        logging.error(f"Error en _generar_resolucion_m3_interno: {str(e)}")
        import traceback
        traceback.print_exc()
        raise


async def _generar_resolucion_m4_interno(solicitud: dict, aprobador: dict) -> dict:
    """
    Genera resolución M4 (Revisión de Avalúo / Autoestimación) y aplica los cambios.
    Usado internamente cuando se aprueba una solicitud de mutación M4.
    """
    try:
        from resolucion_m4_pdf_generator import generate_resolucion_m4_pdf
        
        # Obtener datos de la solicitud
        municipio = solicitud.get('municipio', '')
        radicado = solicitud.get('radicado', '')
        predio_id = solicitud.get('predio_id', '')
        subtipo = solicitud.get('subtipo', 'revision_avaluo')  # revision_avaluo o autoestimacion
        decision = solicitud.get('decision', 'aceptar')  # aceptar o rechazar
        
        # === VERIFICAR SI EL PREDIO ESTÁ BLOQUEADO ===
        if predio_id:
            bloqueo_check = await verificar_predio_bloqueado(predio_id)
            if bloqueo_check.get("bloqueado"):
                bloqueo_info = bloqueo_check.get("info", {})
                raise Exception(
                    f"El predio está bloqueado por proceso legal. "
                    f"Motivo: {bloqueo_info.get('motivo', 'No especificado')}. "
                    f"Bloqueado por: {bloqueo_info.get('bloqueado_por_nombre', 'Desconocido')}"
                )
        
        # Obtener predio
        predio = await db.predios.find_one({"id": predio_id}, {"_id": 0})
        if not predio:
            raise Exception(f"Predio no encontrado: {predio_id}")
        
        # Obtener nombre del municipio
        municipio_nombre = MUNICIPIOS_POR_CODIGO.get(municipio, {}).get('nombre', municipio)
        
        # Generar número de resolución
        resultado_resolucion = await obtener_siguiente_numero_resolucion(municipio)
        numero_resolucion = resultado_resolucion.get("numero_resolucion", f"RES-XX-XXX-0000-{datetime.now().year}")
        fecha_resolucion = resultado_resolucion.get("fecha_resolucion", datetime.now().strftime("%d/%m/%Y"))
        
        # Generar código de verificación para QR
        codigo_verificacion_m4 = generar_codigo_verificacion_resolucion()
        
        # Preparar datos para el PDF
        pdf_data = {
            "numero_resolucion": numero_resolucion,
            "fecha_resolucion": fecha_resolucion,
            "municipio": municipio_nombre,
            "subtipo": subtipo,
            "decision": decision,
            "radicado": radicado,
            "predio": predio,
            "solicitante": solicitud.get('solicitante') or {"nombre": "No especificado", "documento": ""},
            "avaluo_anterior": solicitud.get('avaluo_anterior') or predio.get('avaluo', 0),
            "avaluo_nuevo": solicitud.get('avaluo_nuevo', 0),
            "motivo_solicitud": solicitud.get('motivo_solicitud', ''),
            "valor_autoestimado": solicitud.get('valor_autoestimado') or solicitud.get('avaluo_nuevo', 0),
            "perito_avaluador": solicitud.get('perito_avaluador', ''),
            "elaborado_por": solicitud.get('creado_por_nombre') or aprobador.get("full_name", ""),
            "revisado_por": aprobador.get("full_name", ""),
            "codigo_verificacion": codigo_verificacion_m4,
            "texto_considerando": solicitud.get('texto_considerando')  # Texto personalizado para considerandos
        }
        
        # Crear directorio si no existe
        resoluciones_dir = "/app/uploads/resoluciones"
        os.makedirs(resoluciones_dir, exist_ok=True)

        # Generar nombre del archivo - Simplificado
        filename = f"{numero_resolucion.replace('/', '-').replace(' ', '_')}.pdf"
        filepath = os.path.join(resoluciones_dir, filename)

        # Generar PDF
        pdf_bytes = generate_resolucion_m4_pdf(pdf_data)
        with open(filepath, 'wb') as f:
            f.write(pdf_bytes)
        
        # ========================================
        # APLICAR CAMBIOS AL PREDIO (solo si se acepta)
        # ========================================
        
        if decision == 'aceptar':
            avaluo_nuevo = solicitud.get('avaluo_nuevo') or solicitud.get('valor_autoestimado', 0)
            
            update_predio = {
                "updated_at": datetime.now(COLOMBIA_TZ).isoformat(),
                "avaluo": avaluo_nuevo,
            }
            
            # Historial para mostrar en el frontend (historial_resoluciones)
            historial_resolucion_entry = {
                "tipo_mutacion": "M4",
                "subtipo": subtipo,
                "numero_resolucion": numero_resolucion,
                "fecha_resolucion": fecha_resolucion,
                "radicado": radicado,
                "generado_por": aprobador.get('full_name'),
                "pdf_path": f"/api/resoluciones/descargar/{filename}",
                "decision": decision,
                "avaluo_anterior": solicitud.get('avaluo_anterior', 0),
                "avaluo_nuevo": avaluo_nuevo,
                "motivo": solicitud.get('motivo_solicitud', '')
            }
            
            # Aplicar actualización al predio
            await db.predios.update_one(
                {"id": predio_id},
                {
                    "$set": update_predio,
                    "$push": {"historial_resoluciones": historial_resolucion_entry}
                }
            )
        else:
            # Si se rechaza, solo registrar en historial sin cambiar avalúo
            historial_resolucion_entry = {
                "tipo_mutacion": "M4",
                "subtipo": subtipo,
                "numero_resolucion": numero_resolucion,
                "fecha_resolucion": fecha_resolucion,
                "radicado": radicado,
                "generado_por": aprobador.get('full_name'),
                "pdf_path": f"/api/resoluciones/descargar/{filename}",
                "decision": decision,
                "avaluo_solicitado": solicitud.get('avaluo_nuevo') or solicitud.get('valor_autoestimado', 0),
                "motivo": solicitud.get('motivo_solicitud', '')
            }
            
            await db.predios.update_one(
                {"id": predio_id},
                {"$push": {"historial_resoluciones": historial_resolucion_entry}}
            )
        
        # Guardar resolución en la colección
        resolucion_doc = {
            "id": str(uuid.uuid4()),
            "numero_resolucion": numero_resolucion,
            "fecha_resolucion": fecha_resolucion,
            "tipo": "M4",
            "tipo_mutacion": "M4",
            "subtipo": subtipo,
            "decision": decision,
            "municipio": municipio_nombre,
            "codigo_municipio": municipio,
            "radicado": radicado,
            "solicitud_id": solicitud.get('id'),
            "creado_por_id": solicitud.get('creado_por_id'),
            "predio_id": predio_id,
            "codigo_predial": predio.get('codigo_predial_nacional'),
            "pdf_path": f"/api/resoluciones/descargar/{filename}",
            "generado_por": aprobador.get('id'),
            "generado_por_nombre": aprobador.get('full_name'),
            "elaborado_por": solicitud.get('creado_por_id'),
            "elaborado_por_nombre": solicitud.get('creado_por_nombre', ''),
            "aprobado_por": aprobador.get('id'),
            "aprobado_por_nombre": aprobador.get('full_name', ''),
            "fecha_generacion": datetime.now(COLOMBIA_TZ).isoformat(),
            "created_at": datetime.now(COLOMBIA_TZ).isoformat(),
            "año": datetime.now().year,
            "codigo_verificacion": codigo_verificacion_m4
        }
        await db.resoluciones.insert_one(resolucion_doc)
        
        # Registrar en certificados_verificables para que el QR funcione
        verificable_m4 = {
            "codigo_verificacion": codigo_verificacion_m4,
            "tipo": "RESOLUCION_M4",
            "subtipo": f"{subtipo.upper()}_{decision.upper()}" if subtipo else "M4",
            "numero_resolucion": numero_resolucion,
            "municipio": municipio_nombre,
            "fecha_resolucion": fecha_resolucion,
            "radicado": radicado,
            "predio_codigo": predio.get('codigo_predial_nacional'),
            "predio_direccion": predio.get('direccion', ''),
            "pdf_url": f"/api/resoluciones/descargar/{filename}",
            "generado_por": aprobador.get('full_name'),
            "fecha_generacion": datetime.now(COLOMBIA_TZ).isoformat()
        }
        await db.certificados_verificables.insert_one(verificable_m4)
        
        # Registrar en log de actividades
        await registrar_log_actividad(
            accion="generar_resolucion",
            categoria="resoluciones",
            descripcion=f"Generó resolución {numero_resolucion} tipo M4 ({subtipo}) - {decision.upper()} para {municipio_nombre}",
            usuario_id=aprobador.get("id"),
            usuario_nombre=aprobador.get("full_name"),
            usuario_rol=aprobador.get("role"),
            municipio=municipio_nombre,
            detalles={
                "tipo_mutacion": "M4",
                "subtipo": subtipo,
                "decision": decision,
                "predio_id": predio_id,
                "codigo_predial": predio.get('codigo_predial_nacional'),
                "numero_resolucion": numero_resolucion
            }
        )
        
        # === FINALIZAR PETICIÓN Y ENVIAR CORREO ===
        try:
            peticion = None
            if radicado:
                peticion = await db.petitions.find_one({"radicado": radicado}, {"_id": 0})
                if peticion:
                    await db.petitions.update_one(
                        {"radicado": radicado},
                        {
                            "$set": {
                                "status": "completado",
                                "estado": "finalizado",
                                "estado_tramite": "Finalizado",
                                "resolucion_numero": numero_resolucion,
                                "resolucion_pdf": f"/api/resoluciones/descargar/{filename}",
                                "fecha_finalizacion": datetime.now(COLOMBIA_TZ).isoformat(),
                                "updated_at": datetime.now(COLOMBIA_TZ).isoformat()
                            },
                            "$push": {
                                "archivos_staff": {
                                    "id": f"res-{str(uuid.uuid4())[:8]}",
                                    "filename": filename,
                                    "original_name": f"Resolución {numero_resolucion}.pdf",
                                    "path": filepath,
                                    "uploaded_by": "sistema",
                                    "uploaded_by_name": "Sistema - Resolución aprobada",
                                    "uploaded_by_role": "sistema",
                                    "upload_date": datetime.now(COLOMBIA_TZ).isoformat(),
                                    "es_documento_final": True,
                                    "es_resolucion": True,
                                    "numero_resolucion": numero_resolucion,
                                    "pdf_url": f"/api/resoluciones/descargar/{filename}"
                                }
                            }
                        }
                    )
                    logging.info(f"Petición {radicado} finalizada con resolución M4 {numero_resolucion}")

            # Determinar correo del solicitante
            email_solicitante = None
            nombre_solicitante = "Estimado usuario"

            if peticion and peticion.get("correo"):
                email_solicitante = peticion["correo"]
                nombre_solicitante = peticion.get("nombre_completo", nombre_solicitante)

            # Fallback: solicitud de mutación
            if not email_solicitante:
                sol_data = solicitud.get("solicitante", {})
                email_solicitante = solicitud.get("correo_solicitante") or sol_data.get("correo") or sol_data.get("email")
                nombre_solicitante = sol_data.get("nombre", sol_data.get("nombre_completo", nombre_solicitante))

            if email_solicitante:
                subtipo_texto = "Revisión de Avalúo" if subtipo == "revision_avaluo" else "Autoestimación"
                decision_texto = "APROBADA" if decision == "aceptar" else "RECHAZADA"
                email_body = get_resolucion_aprobada_email(
                    numero_resolucion=numero_resolucion,
                    radicado=radicado,
                    nombre_solicitante=nombre_solicitante,
                    municipio=municipio_nombre,
                    codigo_predio=predio.get('codigo_predial_nacional', ''),
                    tipo_mutacion=f"M4 - {subtipo_texto} ({decision_texto})"
                )

                await send_email(
                    to_email=email_solicitante,
                    subject=f"Resolución {decision_texto} - {numero_resolucion}",
                    body=email_body,
                    attachment_path=filepath,
                    attachment_name=f"{numero_resolucion.replace('/', '-')}.pdf"
                )
                logging.info(f"Correo de resolución M4 enviado a {email_solicitante}")
            else:
                logging.info(f"No se encontró correo de solicitante para resolución M4 {numero_resolucion}")

        except Exception as email_error:
            logging.error(f"Error enviando correo de resolución M4: {str(email_error)}")
        
        return {
            "success": True,
            "id": resolucion_doc['id'],
            "numero_resolucion": numero_resolucion,
            "pdf_url": f"/api/resoluciones/descargar/{filename}",
            "pdf_path": f"/api/resoluciones/descargar/{filename}"
        }
        
    except Exception as e:
        logging.error(f"Error en _generar_resolucion_m4_interno: {str(e)}")
        import traceback
        traceback.print_exc()
        raise


async def _generar_resolucion_m5_interno(solicitud: dict, aprobador: dict) -> dict:
    """
    Genera internamente una resolución M5 (Cancelación o Inscripción de predio).
    Usado internamente cuando se aprueba una solicitud de mutación M5.
    """
    try:
        from resolucion_m5_pdf_generator import generate_m5_resolution_pdf
        
        subtipo = solicitud.get('subtipo', 'cancelacion')
        municipio = solicitud.get('municipio', '')
        radicado = solicitud.get('radicado', '')
        solicitante = solicitud.get('solicitante', {})
        motivo_solicitud = solicitud.get('motivo_solicitud', 'Solicitud de trámite catastral')
        predio_m5 = solicitud.get('predio_m5', {})
        es_doble_inscripcion = solicitud.get('es_doble_inscripcion', False)
        codigo_predio_duplicado = solicitud.get('codigo_predio_duplicado', '')
        
        # === VERIFICAR SI EL PREDIO ESTÁ BLOQUEADO ===
        predio_id = solicitud.get('predio_id') or predio_m5.get('id')
        if predio_id:
            bloqueo_check = await verificar_predio_bloqueado(predio_id)
            if bloqueo_check.get("bloqueado"):
                bloqueo_info = bloqueo_check.get("info", {})
                raise Exception(
                    f"El predio está bloqueado por proceso legal. "
                    f"Motivo: {bloqueo_info.get('motivo', 'No especificado')}. "
                    f"Bloqueado por: {bloqueo_info.get('bloqueado_por_nombre', 'Desconocido')}"
                )
        
        # Determinar vigencia
        colombia_tz = ZoneInfo("America/Bogota")
        año_actual = datetime.now(colombia_tz).year
        if subtipo == 'cancelacion':
            vigencia = solicitud.get('vigencia_cancelacion', año_actual)
        else:
            vigencia = solicitud.get('vigencia_inscripcion', año_actual)
        
        # Obtener código de municipio
        codigo_municipio = None
        for codigo, nombre in MUNICIPIOS_R1R2.items():
            if nombre.lower() == municipio.lower() or municipio.lower() in nombre.lower():
                codigo_municipio = codigo
                break
        if not codigo_municipio:
            codigo_municipio = "54003"
        
        # Obtener siguiente número de resolución
        numero_info = await obtener_siguiente_numero_resolucion_interno(codigo_municipio)
        numero_resolucion = numero_info['numero_resolucion']
        fecha_resolucion = numero_info['fecha_resolucion']
        municipio_nombre = numero_info['municipio']
        
        # Preparar datos para el PDF
        elaboro_nombre = solicitud.get('creado_por_nombre', '')

        # Generar código de verificación para el QR
        codigo_verificacion = generar_codigo_verificacion_resolucion()
        
        pdf_data = {
            "subtipo": subtipo,
            "numero_resolucion": numero_resolucion,
            "fecha_resolucion": fecha_resolucion,
            "municipio": municipio_nombre,
            "radicado": radicado,
            "solicitante": solicitante,
            "predio": predio_m5,
            "vigencia": vigencia,
            "motivo_solicitud": motivo_solicitud,
            "es_doble_inscripcion": es_doble_inscripcion,
            "codigo_predio_duplicado": codigo_predio_duplicado,
            "elaboro": elaboro_nombre or aprobador.get('full_name', ''),
            "aprobo": aprobador.get('full_name', ''),
            "codigo_verificacion": codigo_verificacion,
            "texto_considerando": solicitud.get('texto_considerando')  # Texto personalizado de considerandos
        }
        
        # Generar PDF
        pdf_bytes = generate_m5_resolution_pdf(pdf_data)
        
        # Guardar archivo - Nombre simplificado
        filename = f"{numero_resolucion.replace('/', '-').replace(' ', '_')}.pdf"
        resoluciones_dir = "/app/uploads/resoluciones"
        os.makedirs(resoluciones_dir, exist_ok=True)
        filepath = f"{resoluciones_dir}/{filename}"
        with open(filepath, 'wb') as f:
            f.write(pdf_bytes)

        # Registrar en base de datos
        resolucion_doc = {
            "id": str(uuid.uuid4()),
            "numero_resolucion": numero_resolucion,
            "tipo": "M5",
            "tipo_mutacion": "M5",
            "subtipo": subtipo,
            "municipio": municipio_nombre,
            "codigo_municipio": codigo_municipio,
            "radicado": radicado,
            "fecha_resolucion": fecha_resolucion,
            "pdf_path": f"/api/resoluciones/descargar/{filename}",
            "filename": filename,
            "solicitante": solicitante,
            "predio_id": predio_m5.get('id'),
            "codigo_predial": predio_m5.get('codigo_predial_nacional') or predio_m5.get('codigo_predial'),
            "vigencia": vigencia,
            "es_doble_inscripcion": es_doble_inscripcion,
            "codigo_predio_duplicado": codigo_predio_duplicado,
            "año": numero_info['año'],
            "creado_por_id": aprobador.get('id'),
            "creado_por_nombre": aprobador.get('full_name'),
            "elaborado_por": solicitud.get('creado_por_id'),
            "elaborado_por_nombre": solicitud.get('creado_por_nombre', ''),
            "aprobado_por": aprobador.get('id'),
            "aprobado_por_nombre": aprobador.get('full_name', ''),
            "fecha_creacion": datetime.now(COLOMBIA_TZ).isoformat(),
            "created_at": datetime.now(COLOMBIA_TZ).isoformat(),
            "codigo_verificacion": codigo_verificacion
        }

        logger.info(f"🔵 M5: Guardando resolución {numero_resolucion} con código {codigo_verificacion}")
        insert_result = await db.resoluciones.insert_one(resolucion_doc)
        logger.info(f"✅ M5: Resolución guardada en DB con _id: {insert_result.inserted_id}")
        
        # Verificar que se guardó
        verificacion = await db.resoluciones.find_one({"numero_resolucion": numero_resolucion})
        if verificacion:
            logger.info("✅ M5: Verificación exitosa - resolución encontrada")
        else:
            logger.error("❌ M5: Error - resolución NO encontrada después de insert")
        
        # Registrar en certificados_verificables para que el QR funcione
        verificable_record = {
            "codigo_verificacion": codigo_verificacion,
            "tipo": "RESOLUCION_M5",
            "subtipo": subtipo.upper(),
            "numero_resolucion": numero_resolucion,
            "municipio": municipio_nombre,
            "fecha_resolucion": fecha_resolucion,
            "radicado": radicado,
            "solicitante": solicitante,
            "predio_codigo": predio_m5.get('codigo_predial_nacional') or predio_m5.get('codigo_predial'),
            "predio_direccion": predio_m5.get('direccion', ''),
            "pdf_url": f"/api/resoluciones/descargar/{filename}",
            "generado_por": aprobador.get('full_name'),
            "fecha_generacion": datetime.now(COLOMBIA_TZ).isoformat()
        }
        await db.certificados_verificables.insert_one(verificable_record)
        logger.info("✅ M5: Certificado verificable guardado")
        
        # Actualizar historial del predio según subtipo
        predio_id = predio_m5.get('id')
        if predio_id:
            historial_entry = {
                "tipo_mutacion": "M5",
                "subtipo": subtipo,
                "numero_resolucion": numero_resolucion,
                "fecha_resolucion": fecha_resolucion,
                "radicado": radicado,
                "generado_por": aprobador.get('full_name'),
                "pdf_path": f"/api/resoluciones/descargar/{filename}",
                "vigencia": vigencia,
                "motivo": motivo_solicitud
            }
            
            if subtipo == 'cancelacion':
                # Para cancelación, marcar el predio como cancelado
                await db.predios.update_one(
                    {"id": predio_id},
                    {
                        "$set": {
                            "estado": "cancelado",
                            "fecha_cancelacion": fecha_resolucion,
                            "vigencia_cancelacion": vigencia,
                            "resolucion_cancelacion": numero_resolucion
                        },
                        "$push": {"historial_resoluciones": historial_entry}
                    }
                )
            else:
                # Para inscripción, registrar en historial
                await db.predios.update_one(
                    {"id": predio_id},
                    {
                        "$set": {
                            "estado": "activo",
                            "fecha_inscripcion": fecha_resolucion,
                            "vigencia_inscripcion": vigencia,
                            "resolucion_inscripcion": numero_resolucion
                        },
                        "$push": {"historial_resoluciones": historial_entry}
                    }
                )
        
        # Registrar actividad
        await db.actividad.insert_one(
            {
                "id": str(uuid.uuid4()),
                "tipo": f"resolucion_m5_{subtipo}",
                "usuario_id": aprobador.get('id'),
                "usuario_nombre": aprobador.get('full_name'),
                "fecha": datetime.now(COLOMBIA_TZ).isoformat(),
                "descripcion": f"Resolución M5 ({subtipo}) {numero_resolucion} generada",
                "predio_id": predio_id,
                "codigo_predial": predio_m5.get('codigo_predial_nacional') or predio_m5.get('codigo_predial'),
                "numero_resolucion": numero_resolucion
            }
        )
        
        # === FINALIZAR PETICIÓN Y ENVIAR CORREO ===
        try:
            peticion = None
            if radicado:
                peticion = await db.petitions.find_one({"radicado": radicado}, {"_id": 0})
                if peticion:
                    await db.petitions.update_one(
                        {"radicado": radicado},
                        {
                            "$set": {
                                "status": "completado",
                                "estado": "finalizado",
                                "estado_tramite": "Finalizado",
                                "resolucion_numero": numero_resolucion,
                                "resolucion_pdf": f"/api/resoluciones/descargar/{filename}",
                                "fecha_finalizacion": datetime.now(COLOMBIA_TZ).isoformat(),
                                "updated_at": datetime.now(COLOMBIA_TZ).isoformat()
                            },
                            "$push": {
                                "archivos_staff": {
                                    "id": f"res-{str(uuid.uuid4())[:8]}",
                                    "filename": filename,
                                    "original_name": f"Resolución {numero_resolucion}.pdf",
                                    "path": filepath,
                                    "uploaded_by": "sistema",
                                    "uploaded_by_name": "Sistema - Resolución aprobada",
                                    "uploaded_by_role": "sistema",
                                    "upload_date": datetime.now(COLOMBIA_TZ).isoformat(),
                                    "es_documento_final": True,
                                    "es_resolucion": True,
                                    "numero_resolucion": numero_resolucion,
                                    "pdf_url": f"/api/resoluciones/descargar/{filename}"
                                }
                            }
                        }
                    )
                    logging.info(f"Petición {radicado} finalizada con resolución M5 {numero_resolucion}")

            # Determinar correo del solicitante
            email_solicitante = None
            nombre_solicitante = "Estimado usuario"

            if peticion and peticion.get("correo"):
                email_solicitante = peticion["correo"]
                nombre_solicitante = peticion.get("nombre_completo", nombre_solicitante)

            # Fallback: solicitud de mutación
            if not email_solicitante:
                sol_data = solicitud.get("solicitante", {})
                email_solicitante = solicitud.get("correo_solicitante") or sol_data.get("correo") or sol_data.get("email")
                nombre_solicitante = sol_data.get("nombre", sol_data.get("nombre_completo", nombre_solicitante))

            if email_solicitante:
                subtipo_texto = "Cancelación de Predio" if subtipo == "cancelacion" else "Inscripción de Predio Nuevo"
                email_body = get_resolucion_aprobada_email(
                    numero_resolucion=numero_resolucion,
                    radicado=radicado,
                    nombre_solicitante=nombre_solicitante,
                    municipio=municipio_nombre,
                    codigo_predio=predio_m5.get('codigo_predial_nacional', predio_m5.get('codigo_predial', '')),
                    tipo_mutacion=f"M5 - {subtipo_texto}"
                )

                await send_email(
                    to_email=email_solicitante,
                    subject=f"Resolución {subtipo_texto} - {numero_resolucion}",
                    body=email_body,
                    attachment_path=filepath,
                    attachment_name=f"{numero_resolucion.replace('/', '-')}.pdf"
                )
                logging.info(f"Correo de resolución M5 enviado a {email_solicitante}")
            else:
                logging.info(f"No se encontró correo de solicitante para resolución M5 {numero_resolucion}")
        except Exception as email_error:
            logging.error(f"Error enviando correo de resolución M5: {str(email_error)}")
        
        return {
            "success": True,
            "id": resolucion_doc['id'],
            "numero_resolucion": numero_resolucion,
            "pdf_url": f"/api/resoluciones/descargar/{filename}",
            "pdf_path": f"/api/resoluciones/descargar/{filename}"
        }
        
    except Exception as e:
        logging.error(f"Error en _generar_resolucion_m5_interno: {str(e)}")
        import traceback
        traceback.print_exc()
        raise


async def _generar_resolucion_m6_interno(solicitud: dict, aprobador: dict) -> dict:
    """
    Genera internamente una resolución de Rectificación de Área.
    Actualiza el área del predio en la base de datos.
    """
    try:
        from resolucion_m6_pdf_generator import generate_m6_resolution_pdf
        
        municipio = solicitud.get('municipio', '')
        radicado = solicitud.get('radicado', '')
        solicitante = solicitud.get('solicitante', {})
        predio_data = solicitud.get('predio_rectificacion', {})
        
        # === VERIFICAR SI EL PREDIO ESTÁ BLOQUEADO ===
        predio_id = solicitud.get('predio_id') or predio_data.get('id')
        if predio_id:
            bloqueo_check = await verificar_predio_bloqueado(predio_id)
            if bloqueo_check.get("bloqueado"):
                bloqueo_info = bloqueo_check.get("info", {})
                raise Exception(
                    f"El predio está bloqueado por proceso legal. "
                    f"Motivo: {bloqueo_info.get('motivo', 'No especificado')}. "
                    f"Bloqueado por: {bloqueo_info.get('bloqueado_por_nombre', 'Desconocido')}"
                )
        
        # Áreas anteriores y nuevas
        area_terreno_anterior = solicitud.get('area_terreno_anterior', 0)
        area_terreno_nueva = solicitud.get('area_terreno_nueva', 0)
        area_construida_anterior = solicitud.get('area_construida_anterior', 0)
        area_construida_nueva = solicitud.get('area_construida_nueva', 0)
        avaluo_anterior = solicitud.get('avaluo_anterior', predio_data.get('avaluo', 0))
        avaluo_nuevo = solicitud.get('avaluo_nuevo', avaluo_anterior)
        
        # Obtener código de municipio
        codigo_municipio = None
        for codigo, nombre in MUNICIPIOS_R1R2.items():
            if nombre.lower() == municipio.lower() or municipio.lower() in nombre.lower():
                codigo_municipio = codigo
                break
        if not codigo_municipio:
            codigo_municipio = "54003"
        
        # Obtener siguiente número de resolución
        numero_info = await obtener_siguiente_numero_resolucion_interno(codigo_municipio)
        numero_resolucion = numero_info['numero_resolucion']
        fecha_resolucion = numero_info['fecha_resolucion']
        municipio_nombre = numero_info['municipio']
        
        # Obtener datos R1/R2 del predio
        predio_id = predio_data.get('id')
        predio_db = None
        if predio_id:
            predio_db = await db.predios.find_one({"id": predio_id}, {"_id": 0})
        
        # Función auxiliar para obtener datos R1/R2
        def obtener_datos_r1_r2_m6(predio):
            resultado = {}
            if not predio:
                return resultado
            r1_registros = predio.get('r1_registros', [])
            if r1_registros and len(r1_registros) > 0:
                r1 = r1_registros[0]
                resultado['codigo_homologado'] = r1.get('codigo_homologado') or r1.get('nupre') or ''
                resultado['destino_economico'] = r1.get('destino_economico') or 'A'
                resultado['direccion'] = r1.get('direccion') or predio.get('direccion', '')
            else:
                resultado['codigo_homologado'] = predio.get('codigo_homologado', '')
                resultado['destino_economico'] = predio.get('destino_economico', 'A')
                resultado['direccion'] = predio.get('direccion', '')
            
            r2_registros = predio.get('r2_registros', [])
            if r2_registros and len(r2_registros) > 0:
                r2 = r2_registros[0]
                resultado['matricula_inmobiliaria'] = r2.get('matricula_inmobiliaria') or ''
                resultado['propietarios'] = r2.get('propietarios') or predio.get('propietarios', [])
            else:
                resultado['matricula_inmobiliaria'] = predio.get('matricula_inmobiliaria', '')
                resultado['propietarios'] = predio.get('propietarios', [])
            return resultado
        
        datos_r1_r2 = obtener_datos_r1_r2_m6(predio_db or predio_data)
        
        # Obtener nombre del elaborador
        elaboro_nombre = solicitud.get('creado_por_nombre', '')

        # Generar código de verificación para QR
        codigo_verificacion = generar_codigo_verificacion_resolucion()
        
        # Preparar predio con datos R1/R2 incorporados
        predio_completo = {
            **predio_data,
            'codigo_homologado': datos_r1_r2.get('codigo_homologado', ''),
            'matricula_inmobiliaria': datos_r1_r2.get('matricula_inmobiliaria', ''),
            'destino_economico': datos_r1_r2.get('destino_economico', 'A'),
            'direccion': datos_r1_r2.get('direccion', ''),
            'propietarios': datos_r1_r2.get('propietarios', [])
        }
        
        # Vigencias
        colombia_tz = ZoneInfo("America/Bogota")
        año_actual = datetime.now(colombia_tz).year
        vigencia_anterior = f"01/01/{año_actual - 1}"
        vigencia_nueva = f"01/01/{año_actual}"
        
        pdf_data = {
            "numero_resolucion": numero_resolucion,
            "fecha_resolucion": fecha_resolucion,
            "municipio": municipio_nombre,
            "radicado": radicado,
            "solicitante": solicitante,
            "predio": predio_completo,
            "area_terreno_anterior": area_terreno_anterior,
            "area_terreno_nueva": area_terreno_nueva,
            "area_construida_anterior": area_construida_anterior,
            "area_construida_nueva": area_construida_nueva,
            "avaluo_anterior": avaluo_anterior,
            "avaluo_nuevo": avaluo_nuevo,
            "vigencia_anterior": vigencia_anterior,
            "vigencia_nueva": vigencia_nueva,
            "elaborado_por": elaboro_nombre or aprobador.get('full_name', ''),
            "revisado_por": aprobador.get('full_name', ''),
            "codigo_verificacion": codigo_verificacion,
            "texto_considerando": solicitud.get('texto_considerando')
        }
        
        # Generar PDF
        pdf_bytes = generate_m6_resolution_pdf(pdf_data)
        
        # Guardar archivo - Nombre simplificado
        filename = f"{numero_resolucion.replace('/', '-').replace(' ', '_')}.pdf"
        resoluciones_dir = "/app/uploads/resoluciones"
        os.makedirs(resoluciones_dir, exist_ok=True)
        filepath = f"{resoluciones_dir}/{filename}"
        with open(filepath, 'wb') as f:
            f.write(pdf_bytes)

        # Registrar en base de datos
        codigo_predial = predio_data.get('codigo_predial_nacional') or predio_data.get('codigo_predial') or predio_data.get('NPN', '')
        
        resolucion_doc = {
            "id": str(uuid.uuid4()),
            "numero_resolucion": numero_resolucion,
            "tipo": "RECTIFICACION_AREA",
            "tipo_mutacion": "RECTIFICACION_AREA",
            "subtipo": "rectificacion_area",
            "municipio": municipio_nombre,
            "codigo_municipio": codigo_municipio,
            "radicado": radicado,
            "fecha_resolucion": fecha_resolucion,
            "pdf_path": f"/api/resoluciones/descargar/{filename}",
            "filename": filename,
            "solicitante": solicitante,
            "predio_id": predio_id,
            "codigo_predial": codigo_predial,
            "area_terreno_anterior": area_terreno_anterior,
            "area_terreno_nueva": area_terreno_nueva,
            "area_construida_anterior": area_construida_anterior,
            "area_construida_nueva": area_construida_nueva,
            "avaluo_anterior": avaluo_anterior,
            "avaluo_nuevo": avaluo_nuevo,
            "año": numero_info['año'],
            "creado_por_id": aprobador.get('id'),
            "creado_por_nombre": aprobador.get('full_name'),
            "elaborado_por": solicitud.get('creado_por_id'),
            "elaborado_por_nombre": solicitud.get('creado_por_nombre', ''),
            "aprobado_por": aprobador.get('id'),
            "aprobado_por_nombre": aprobador.get('full_name', ''),
            "fecha_creacion": datetime.now(COLOMBIA_TZ).isoformat(),
            "created_at": datetime.now(COLOMBIA_TZ).isoformat(),
            "codigo_verificacion": codigo_verificacion
        }

        logger.info(f"🔵 Rectificación Área: Guardando resolución {numero_resolucion}")
        await db.resoluciones.insert_one(resolucion_doc)
        
        # Registrar en certificados_verificables para que el QR funcione
        verificable_record = {
            "codigo_verificacion": codigo_verificacion,
            "tipo": "RESOLUCION_RECTIFICACION_AREA",
            "subtipo": "RECTIFICACION_AREA",
            "numero_resolucion": numero_resolucion,
            "municipio": municipio_nombre,
            "fecha_resolucion": fecha_resolucion,
            "radicado": radicado,
            "solicitante": solicitante,
            "predio_codigo": codigo_predial,
            "predio_direccion": predio_completo.get('direccion', ''),
            "area_terreno_anterior": area_terreno_anterior,
            "area_terreno_nueva": area_terreno_nueva,
            "pdf_url": f"/api/resoluciones/descargar/{filename}",
            "generado_por": aprobador.get('full_name'),
            "fecha_generacion": datetime.now(COLOMBIA_TZ).isoformat()
        }
        await db.certificados_verificables.insert_one(verificable_record)
        logger.info("✅ Rectificación Área: Certificado verificable guardado")
        
        # Actualizar predio en la base de datos con las nuevas áreas
        if predio_id:
            # Obtener datos detallados de zonas y construcciones de la solicitud
            zonas_terreno_nuevas = solicitud.get('zonas_terreno_nuevas', [])
            construcciones_nuevas = solicitud.get('construcciones_nuevas', [])
            
            historial_entry = {
                "tipo_mutacion": "RECTIFICACION_AREA",
                "numero_resolucion": numero_resolucion,
                "fecha_resolucion": fecha_resolucion,
                "radicado": radicado,
                "generado_por": aprobador.get('full_name'),
                "pdf_path": f"/api/resoluciones/descargar/{filename}",
                "area_terreno_anterior": area_terreno_anterior,
                "area_terreno_nueva": area_terreno_nueva,
                "area_construida_anterior": area_construida_anterior,
                "area_construida_nueva": area_construida_nueva,
                "avaluo_anterior": avaluo_anterior,
                "avaluo_nuevo": avaluo_nuevo,
                "zonas_terreno_nuevas": zonas_terreno_nuevas,
                "construcciones_nuevas": construcciones_nuevas,
                "fecha": datetime.now(COLOMBIA_TZ).isoformat()
            }
            
            # Preparar actualización del predio
            update_fields = {
                "area_terreno": area_terreno_nueva,
                "area_construida": area_construida_nueva,
                "avaluo": avaluo_nuevo,
                "ultima_rectificacion_area": fecha_resolucion,
                "resolucion_rectificacion": numero_resolucion,
                "area_editada_en_plataforma": True,  # Marcar como editado en plataforma (área automática)
                "updated_at": datetime.now(COLOMBIA_TZ).isoformat()
            }
            
            # Si hay zonas de terreno nuevas, actualizar zonas_homogeneas y zonas (para R2)
            if zonas_terreno_nuevas:
                zonas_formateadas = [
                    {
                        "zona_fisica": z.get("zona_fisica", ""),
                        "zona_economica": z.get("zona_economica", ""),
                        "area_terreno": float(z.get("area_terreno", 0))
                    }
                    for z in zonas_terreno_nuevas
                ]
                update_fields["zonas_homogeneas"] = zonas_formateadas
                update_fields["zonas"] = zonas_formateadas  # Para exportación R2
            
            # Si hay construcciones nuevas, actualizar construcciones (para R2)
            if construcciones_nuevas:
                construcciones_formateadas = [
                    {
                        "id": c.get("id", f"C{i+1}"),
                        "piso": int(c.get("piso", 0)),
                        "pisos": int(c.get("piso", 0)),  # Alias para compatibilidad con export R2
                        "habitaciones": int(c.get("habitaciones", 0)),
                        "banos": int(c.get("banos", 0)),
                        "locales": int(c.get("locales", 0)),
                        "tipificacion": c.get("tipificacion", ""),
                        "uso": c.get("uso", ""),
                        "puntaje": float(c.get("puntaje", 0)),
                        "area_construida": float(c.get("area_construida", 0))
                    }
                    for i, c in enumerate(construcciones_nuevas)
                ]
                update_fields["construcciones"] = construcciones_formateadas
            
            # Actualizar áreas del predio
            await db.predios.update_one(
                {"id": predio_id},
                {
                    "$set": update_fields,
                    "$push": {"historial_resoluciones": historial_entry}
                }
            )
            logger.info(f"✅ Predio {predio_id} actualizado con nuevas áreas")
            
            # También actualizar R1 si existe
            r1_update = {
                "r1_registros.0.area_terreno": area_terreno_nueva,
                "r1_registros.0.area_construida": area_construida_nueva,
                "r1_registros.0.avaluo": avaluo_nuevo
            }
            
            # Agregar zonas homogéneas a R1 si existen
            if zonas_terreno_nuevas:
                r1_update["r1_registros.0.zonas_homogeneas"] = [
                    {
                        "zona_fisica": z.get("zona_fisica", ""),
                        "zona_economica": z.get("zona_economica", ""),
                        "area_terreno": float(z.get("area_terreno", 0))
                    }
                    for z in zonas_terreno_nuevas
                ]
            
            # Agregar construcciones a R1 si existen
            if construcciones_nuevas:
                r1_update["r1_registros.0.construcciones"] = [
                    {
                        "id": c.get("id", f"C{i+1}"),
                        "piso": int(c.get("piso", 0)),
                        "pisos": int(c.get("piso", 0)),  # Alias para compatibilidad
                        "habitaciones": int(c.get("habitaciones", 0)),
                        "banos": int(c.get("banos", 0)),
                        "locales": int(c.get("locales", 0)),
                        "tipificacion": c.get("tipificacion", ""),
                        "uso": c.get("uso", ""),
                        "puntaje": float(c.get("puntaje", 0)),
                        "area_construida": float(c.get("area_construida", 0))
                    }
                    for i, c in enumerate(construcciones_nuevas)
                ]
            
            await db.predios.update_one(
                {"id": predio_id, "r1_registros.0": {"$exists": True}},
                {"$set": r1_update}
            )
            logger.info(f"✅ R1 del predio {predio_id} actualizado con zonas y construcciones")
        
        # Registrar actividad
        await db.actividad.insert_one({
            "id": str(uuid.uuid4()),
            "tipo": "resolucion_rectificacion_area",
            "usuario_id": aprobador.get('id'),
            "usuario_nombre": aprobador.get('full_name'),
            "fecha": datetime.now(COLOMBIA_TZ).isoformat(),
            "descripcion": f"Resolución Rectificación de Área {numero_resolucion} generada",
            "predio_id": predio_id,
            "codigo_predial": codigo_predial,
            "numero_resolucion": numero_resolucion
        })
        
        # === FINALIZAR PETICIÓN Y ENVIAR CORREO ===
        try:
            peticion = None
            if radicado:
                peticion = await db.petitions.find_one({"radicado": radicado}, {"_id": 0})
                if peticion:
                    await db.petitions.update_one(
                        {"radicado": radicado},
                        {
                            "$set": {
                                "status": "completado",
                                "estado": "finalizado",
                                "estado_tramite": "Finalizado",
                                "resolucion_numero": numero_resolucion,
                                "resolucion_pdf": f"/api/resoluciones/descargar/{filename}",
                                "fecha_finalizacion": datetime.now(COLOMBIA_TZ).isoformat(),
                                "updated_at": datetime.now(COLOMBIA_TZ).isoformat()
                            },
                            "$push": {
                                "archivos_staff": {
                                    "id": f"res-{str(uuid.uuid4())[:8]}",
                                    "filename": filename,
                                    "original_name": f"Resolución {numero_resolucion}.pdf",
                                    "path": filepath,
                                    "uploaded_by": "sistema",
                                    "uploaded_by_name": "Sistema - Resolución aprobada",
                                    "uploaded_by_role": "sistema",
                                    "upload_date": datetime.now(COLOMBIA_TZ).isoformat(),
                                    "es_documento_final": True,
                                    "es_resolucion": True,
                                    "numero_resolucion": numero_resolucion,
                                    "pdf_url": f"/api/resoluciones/descargar/{filename}"
                                }
                            }
                        }
                    )
                    logging.info(f"Petición {radicado} finalizada con resolución {numero_resolucion}")

            # Determinar correo del solicitante
            email_solicitante = None
            nombre_solicitante = "Estimado usuario"

            if peticion and peticion.get("correo"):
                email_solicitante = peticion["correo"]
                nombre_solicitante = peticion.get("nombre_completo", nombre_solicitante)

            # Fallback: solicitud de mutación
            if not email_solicitante:
                sol_data = solicitud.get("solicitante", {})
                email_solicitante = solicitud.get("correo_solicitante") or sol_data.get("correo") or sol_data.get("email")
                nombre_solicitante = sol_data.get("nombre", sol_data.get("nombre_completo", nombre_solicitante))

            if email_solicitante:
                email_body = get_resolucion_aprobada_email(
                    numero_resolucion=numero_resolucion,
                    radicado=radicado,
                    nombre_solicitante=nombre_solicitante,
                    municipio=municipio_nombre,
                    codigo_predio=codigo_predial,
                    tipo_mutacion="Rectificación de Área"
                )

                await send_email(
                    to_email=email_solicitante,
                    subject=f"Resolución Rectificación de Área - {numero_resolucion}",
                    body=email_body,
                    attachment_path=filepath,
                    attachment_name=f"{numero_resolucion.replace('/', '-')}.pdf"
                )
                logging.info(f"Correo de resolución Rectificación de Área enviado a {email_solicitante}")
            else:
                logging.info(f"No se encontró correo de solicitante para resolución M6 {numero_resolucion}")
        except Exception as email_error:
            logging.error(f"Error enviando correo de resolución Rectificación de Área: {str(email_error)}")
        
        return {
            "success": True,
            "id": resolucion_doc['id'],
            "numero_resolucion": numero_resolucion,
            "pdf_url": f"/api/resoluciones/descargar/{filename}",
            "pdf_path": f"/api/resoluciones/descargar/{filename}"
        }
        
    except Exception as e:
        logging.error(f"Error en _generar_resolucion_m6_interno: {str(e)}")
        import traceback
        traceback.print_exc()
        raise


async def _generar_resolucion_complementacion_interno(solicitud: dict, aprobador: dict) -> dict:
    """
    Genera internamente una resolución de Complementación de Información.
    """
    try:
        from resolucion_complementacion_pdf_generator import generate_complementacion_resolution_pdf
        
        # Obtener datos de la solicitud
        predio_data = solicitud.get('predio', {})
        solicitante = solicitud.get('solicitante', {})
        municipio = solicitud.get('municipio', '')
        
        # Obtener predio de la base de datos si existe ID
        predio_id = predio_data.get('id')
        predio_db = None
        if predio_id:
            predio_db = await db.predios.find_one({"id": predio_id}, {"_id": 0})
        
        # === VERIFICAR SI EL PREDIO ESTÁ BLOQUEADO ===
        if predio_id:
            bloqueo_check = await verificar_predio_bloqueado(predio_id)
            if bloqueo_check.get("bloqueado"):
                bloqueo_info = bloqueo_check.get("info", {})
                raise Exception(
                    f"El predio está bloqueado por proceso legal. "
                    f"Motivo: {bloqueo_info.get('motivo', 'No especificado')}. "
                    f"Bloqueado por: {bloqueo_info.get('bloqueado_por_nombre', 'Desconocido')}"
                )
        
        # Datos R1/R2 del predio
        def obtener_datos_r1_r2_comp(predio):
            if not predio:
                return {}
            r1 = predio.get('r1_registros', [])
            r2 = predio.get('r2_registros', [])
            r1_data = r1[0] if r1 else {}
            r2_data = r2[0] if r2 else {}
            return {
                'codigo_homologado': r1_data.get('codigo_homologado') or predio.get('codigo_homologado', ''),
                'direccion': r1_data.get('direccion') or predio.get('direccion', ''),
                'destino_economico': r1_data.get('destino_economico') or predio.get('destino_economico', 'A'),
                'area_terreno': r1_data.get('area_terreno') or predio.get('area_terreno', 0),
                'area_construida': r1_data.get('area_construida') or predio.get('area_construida', 0),
                'avaluo': r1_data.get('avaluo') or predio.get('avaluo', 0),
                'matricula_inmobiliaria': r2_data.get('matricula_inmobiliaria') or predio.get('matricula_inmobiliaria', ''),
                'propietarios': r2_data.get('propietarios') or predio.get('propietarios', [])
            }
        
        datos_r1_r2 = obtener_datos_r1_r2_comp(predio_db or predio_data)
        
        # Datos actuales del predio
        area_terreno_anterior = solicitud.get('area_terreno_anterior', datos_r1_r2.get('area_terreno', 0))
        area_construida_anterior = solicitud.get('area_construida_anterior', datos_r1_r2.get('area_construida', 0))
        avaluo_anterior = solicitud.get('avaluo_anterior', datos_r1_r2.get('avaluo', 0))
        
        # Datos nuevos
        area_terreno_nueva = solicitud.get('area_terreno_nueva', area_terreno_anterior)
        area_construida_nueva = solicitud.get('area_construida_nueva', area_construida_anterior)
        avaluo_nuevo = solicitud.get('avaluo_nuevo', avaluo_anterior)
        
        documentos_soporte = solicitud.get('documentos_soporte', 'Oficio de solicitud, Cédula del propietario, Certificado de libertad y tradición')
        
        # Generar número de resolución usando la función centralizada (misma que M2, M3, etc.)
        predio_ref = predio_db or predio_data
        codigo_predial_full = predio_ref.get('codigo_predial_nacional', predio_ref.get('codigo_predial', ''))
        codigo_municipio = codigo_predial_full[0:5] if len(codigo_predial_full) >= 5 else None

        # Fallback: buscar código de municipio por nombre
        if not codigo_municipio:
            for codigo, nombre in MUNICIPIOS_R1R2.items():
                if nombre.lower() == municipio.lower() or municipio.lower() in nombre.lower():
                    codigo_municipio = codigo
                    break
        if not codigo_municipio:
            codigo_municipio = "54003"

        # Usar función centralizada para obtener consecutivo global del municipio
        res_numero = await obtener_siguiente_numero_resolucion_interno(codigo_municipio)
        numero_resolucion = res_numero["numero_resolucion"]
        siguiente_numero = res_numero["siguiente_numero"]
        year = res_numero["año"]
        depto = codigo_municipio[0:2] if len(codigo_municipio) >= 2 else "54"
        mpio = codigo_municipio[2:5] if len(codigo_municipio) >= 5 else "003"
        
        # Código de verificación único
        codigo_verificacion = f"COMP-{str(uuid.uuid4())[:8].upper()}"
        
        # Obtener propietarios del payload o del predio
        propietarios_anteriores_raw = solicitud.get('propietarios_anteriores', [])
        propietarios_nuevos_raw = solicitud.get('propietarios_nuevos', [])

        # Fallback: si no se enviaron propietarios, usar los del predio
        if not propietarios_anteriores_raw:
            props_predio = (predio_db or predio_data).get('propietarios', [])
            propietarios_anteriores_raw = [{
                "nombre": p.get("nombre_propietario", p.get("nombre", "")),
                "tipo_documento": p.get("tipo_documento", "CC"),
                "documento": formatear_documento(p.get("numero_documento", "")),
                "estado_civil": validar_estado_civil(p.get("estado_civil", "")),
            } for p in props_predio]

        if not propietarios_nuevos_raw:
            propietarios_nuevos_raw = propietarios_anteriores_raw

        # Formatear propietarios para el PDF
        propietarios_anteriores = [{
            "nombre": p.get("nombre_propietario", p.get("nombre", "")),
            "tipo_documento": p.get("tipo_documento", "CC"),
            "documento": formatear_documento(p.get("numero_documento", p.get("documento", ""))),
            "estado_civil": validar_estado_civil(p.get("estado_civil", "")),
        } for p in propietarios_anteriores_raw]

        propietarios_nuevos = [{
            "nombre": p.get("nombre_propietario", p.get("nombre", "")),
            "tipo_documento": p.get("tipo_documento", "CC"),
            "documento": formatear_documento(p.get("numero_documento", p.get("documento", ""))),
            "estado_civil": validar_estado_civil(p.get("estado_civil", "")),
        } for p in propietarios_nuevos_raw]

        # Obtener matrícula: del payload o del predio R2
        matricula_nueva = solicitud.get('matricula_nueva') or datos_r1_r2.get('matricula_inmobiliaria', '')
        direccion_nueva = solicitud.get('direccion_nueva') or datos_r1_r2.get('direccion', '')
        destino_nuevo = solicitud.get('destino_nuevo') or datos_r1_r2.get('destino_economico', 'A')

        # Preparar datos para el PDF
        pdf_data = {
            "numero_resolucion": numero_resolucion,
            "municipio": municipio,
            "radicado": solicitud.get('radicado', ''),
            "codigo_verificacion": codigo_verificacion,
            "elaborado_por": solicitud.get('creado_por_nombre', aprobador['full_name']),
            "revisado_por": aprobador['full_name'],
            "documentos_soporte": documentos_soporte,
            "texto_considerando": solicitud.get('texto_considerando', ''),
            "predio": predio_db or predio_data,
            "solicitante": solicitante,
            "propietarios_anteriores": propietarios_anteriores,
            "propietarios_nuevos": propietarios_nuevos,
            "matricula_nueva": matricula_nueva,
            "direccion_nueva": direccion_nueva,
            "destino_nuevo": destino_nuevo,
            "area_terreno_nueva": area_terreno_nueva,
            "area_construida_nueva": area_construida_nueva,
            "avaluo_nuevo": avaluo_nuevo,
            "vigencia_cancelacion": year - 1,
            "vigencia_inscripcion": year
        }
        
        # Generar PDF
        pdf_bytes = generate_complementacion_resolution_pdf(pdf_data)
        
        # Guardar archivo - misma ubicación que las demás resoluciones
        filename = f"{numero_resolucion.replace('/', '-').replace(' ', '_')}.pdf"
        pdf_dir = "/app/uploads/resoluciones"
        os.makedirs(pdf_dir, exist_ok=True)
        pdf_path = f"{pdf_dir}/{filename}"
        
        with open(pdf_path, "wb") as f:
            f.write(pdf_bytes)
        
        # Crear documento de resolución
        resolucion_doc = {
            "id": str(uuid.uuid4()),
            "tipo": "COMPLEMENTACION",
            "tipo_mutacion": "COMPLEMENTACION",
            "numero_resolucion": numero_resolucion,
            "año": year,
            "consecutivo": siguiente_numero,
            "codigo_municipio": codigo_municipio,
            "codigo_verificacion": codigo_verificacion,
            "municipio": municipio,
            "fecha_creacion": datetime.now(COLOMBIA_TZ).isoformat(),
            "fecha_resolucion": datetime.now(COLOMBIA_TZ).strftime("%Y-%m-%d"),
            "fecha_generacion": datetime.now(COLOMBIA_TZ).isoformat(),
            "created_at": datetime.now(COLOMBIA_TZ).isoformat(),
            "archivo_pdf": pdf_path,
            "pdf_path": f"/api/resoluciones/descargar/{filename}",
            "filename": filename,
            "solicitud_id": solicitud.get('id'),
            "creado_por_id": solicitud.get('creado_por_id'),
            "predio_id": predio_id,
            "datos": {
                "area_terreno_anterior": area_terreno_anterior,
                "area_terreno_nueva": area_terreno_nueva,
                "area_construida_anterior": area_construida_anterior,
                "area_construida_nueva": area_construida_nueva,
                "avaluo_anterior": avaluo_anterior,
                "avaluo_nuevo": avaluo_nuevo,
                "documentos_soporte": documentos_soporte
            },
            "elaborado_por": solicitud.get('creado_por_id'),
            "elaborado_por_nombre": solicitud.get('creado_por_nombre', ''),
            "aprobado_por": aprobador['id'],
            "aprobado_por_nombre": aprobador['full_name']
        }

        await db.resoluciones.insert_one(resolucion_doc)
        
        # Actualizar solicitud
        await db.solicitudes_mutacion.update_one(
            {"id": solicitud['id']},
            {
                "$set": {
                    "estado": "APROBADA",
                    "resolucion_id": resolucion_doc['id'],
                    "resolucion_numero": numero_resolucion,
                    "resolucion_pdf": f"/api/resoluciones/descargar/{filename}",
                    "fecha_aprobacion": datetime.now(COLOMBIA_TZ).isoformat(),
                    "aprobado_por": aprobador['id'],
                    "aprobado_por_nombre": aprobador['full_name']
                }
            }
        )
        
        # Actualizar predio en la base de datos si existe
        if predio_id:
            historial_entry = {
                "tipo": "COMPLEMENTACION",
                "tipo_mutacion": "COMPLEMENTACION",
                "fecha": datetime.now(COLOMBIA_TZ).isoformat(),
                "resolucion": numero_resolucion,
                "numero_resolucion": numero_resolucion,
                "fecha_resolucion": datetime.now(COLOMBIA_TZ).strftime("%Y-%m-%d"),
                "radicado": solicitud.get('radicado', ''),
                "pdf_path": f"/api/resoluciones/descargar/{filename}",
                "generado_por": aprobador.get("full_name", ""),
                "aprobado_por": aprobador.get("full_name", ""),
                "descripcion": "Complementación de información",
                "area_terreno_anterior": area_terreno_anterior,
                "area_terreno_nueva": area_terreno_nueva,
                "area_construida_anterior": area_construida_anterior,
                "area_construida_nueva": area_construida_nueva,
                "avaluo_anterior": avaluo_anterior,
                "avaluo_nuevo": avaluo_nuevo
            }
            
            update_fields = {
                "area_terreno": area_terreno_nueva,
                "area_construida": area_construida_nueva,
                "avaluo": avaluo_nuevo,
                "area_editada_en_plataforma": True,
                "ultima_actualizacion": datetime.now(COLOMBIA_TZ).isoformat()
            }
            # Actualizar campos complementados si se enviaron
            if matricula_nueva:
                update_fields["matricula_inmobiliaria"] = matricula_nueva
            if direccion_nueva:
                update_fields["direccion"] = direccion_nueva
            if destino_nuevo:
                update_fields["destino_economico"] = destino_nuevo
            if propietarios_nuevos_raw:
                update_fields["propietarios"] = [{
                    "nombre_propietario": p.get("nombre_propietario", p.get("nombre", "")),
                    "tipo_documento": p.get("tipo_documento", "C"),
                    "numero_documento": p.get("numero_documento", p.get("documento", "")),
                    "estado_civil": validar_estado_civil(p.get("estado_civil", "")),
                } for p in propietarios_nuevos_raw]
            
            await db.predios.update_one(
                {"id": predio_id},
                {
                    "$set": update_fields,
                    "$push": {"historial_resoluciones": historial_entry}
                }
            )
            logger.info(f"✅ Predio {predio_id} actualizado con datos complementados")
        
        # === FINALIZAR PETICIÓN Y ENVIAR CORREO ===
        try:
            radicado = solicitud.get('radicado', '')
            peticion = None

            if radicado:
                peticion = await db.petitions.find_one({"radicado": radicado}, {"_id": 0})
                if peticion:
                    await db.petitions.update_one(
                        {"radicado": radicado},
                        {
                            "$set": {
                                "status": "completado",
                                "estado": "finalizado",
                                "estado_tramite": "Finalizado",
                                "resolucion_numero": numero_resolucion,
                                "resolucion_pdf": f"/api/resoluciones/descargar/{filename}",
                                "fecha_finalizacion": datetime.now(COLOMBIA_TZ).isoformat(),
                                "updated_at": datetime.now(COLOMBIA_TZ).isoformat()
                            },
                            "$push": {
                                "archivos_staff": {
                                    "id": f"res-{str(uuid.uuid4())[:8]}",
                                    "filename": filename,
                                    "original_name": f"Resolución {numero_resolucion}.pdf",
                                    "path": pdf_path,
                                    "uploaded_by": "sistema",
                                    "uploaded_by_name": "Sistema - Resolución aprobada",
                                    "uploaded_by_role": "sistema",
                                    "upload_date": datetime.now(COLOMBIA_TZ).isoformat(),
                                    "es_documento_final": True,
                                    "es_resolucion": True,
                                    "numero_resolucion": numero_resolucion,
                                    "pdf_url": f"/api/resoluciones/descargar/{filename}"
                                }
                            }
                        }
                    )
                    logging.info(f"Petición {radicado} finalizada con resolución {numero_resolucion}")

            # Determinar correo del solicitante
            email_solicitante = None
            nombre_solicitante = "Estimado usuario"

            if peticion and peticion.get("correo"):
                email_solicitante = peticion["correo"]
                nombre_solicitante = peticion.get("nombre_completo", nombre_solicitante)

            # Fallback: solicitud de mutación
            if not email_solicitante:
                sol_data = solicitud.get("solicitante", {})
                email_solicitante = solicitud.get("correo_solicitante") or sol_data.get("correo") or sol_data.get("email")
                nombre_solicitante = sol_data.get("nombre", sol_data.get("nombre_completo", nombre_solicitante))

            if email_solicitante:
                codigo_predial = predio_data.get('codigo_predial_nacional', predio_data.get('codigo_predial', ''))
                email_body = get_resolucion_aprobada_email(
                    numero_resolucion=numero_resolucion,
                    radicado=radicado,
                    nombre_solicitante=nombre_solicitante,
                    municipio=municipio,
                    codigo_predio=codigo_predial,
                    tipo_mutacion="Complementación de Información"
                )

                await send_email(
                    to_email=email_solicitante,
                    subject=f"Resolución Complementación de Información - {numero_resolucion}",
                    body=email_body,
                    attachment_path=pdf_path,
                    attachment_name=f"{numero_resolucion.replace('/', '-')}.pdf"
                )
                logging.info(f"Correo de resolución Complementación enviado a {email_solicitante}")
            else:
                logging.info(f"No se encontró correo de solicitante para resolución COMP {numero_resolucion}")
        except Exception as email_error:
            logging.error(f"Error enviando correo de resolución Complementación: {str(email_error)}")
        
        return {
            "success": True,
            "id": resolucion_doc['id'],
            "numero_resolucion": numero_resolucion,
            "pdf_url": f"/api/resoluciones/descargar/{filename}",
            "pdf_path": f"/api/resoluciones/descargar/{filename}"
        }
        
    except Exception as e:
        logging.error(f"Error en _generar_resolucion_complementacion_interno: {str(e)}")
        import traceback
        traceback.print_exc()
        raise


@api_router.post("/predios/cambios/aprobar")
async def aprobar_rechazar_cambio(
    request: CambioAprobacionRequest,
    current_user: dict = Depends(get_current_user)
):
    """Aprueba o rechaza un cambio pendiente (solo coordinadores/admin o con permiso)"""
    has_permission = await check_permission(current_user, Permission.APPROVE_CHANGES)
    if not has_permission:
        raise HTTPException(status_code=403, detail="No tiene permiso para aprobar cambios")
    
    # Buscar el cambio
    cambio = await db.predios_cambios.find_one({"id": request.cambio_id}, {"_id": 0})
    
    if not cambio:
        raise HTTPException(status_code=404, detail="Cambio no encontrado")
    
    if cambio["estado"] not in [
        PredioEstadoAprobacion.PENDIENTE_CREACION,
        PredioEstadoAprobacion.PENDIENTE_MODIFICACION,
        PredioEstadoAprobacion.PENDIENTE_ELIMINACION
    ]:
        raise HTTPException(status_code=400, detail="Este cambio ya fue procesado")
    
    nuevo_estado = PredioEstadoAprobacion.APROBADO if request.aprobado else PredioEstadoAprobacion.RECHAZADO
    
    update_data = {
        "estado": nuevo_estado,
        "aprobado_por": current_user['id'],
        "aprobado_por_nombre": current_user['full_name'],
        "fecha_aprobacion": datetime.now(COLOMBIA_TZ).isoformat(),
        "comentario_aprobacion": request.comentario
    }
    
    # Si es una modificación, guardar los datos anteriores del predio ANTES de aplicar el cambio
    if cambio["tipo_cambio"] == "modificacion" and cambio.get("predio_id"):
        predio_actual = await db.predios.find_one({"id": cambio["predio_id"]}, {"_id": 0})
        if predio_actual:
            # Guardar solo los campos relevantes como datos_anteriores
            datos_anteriores = {
                "codigo_predial_nacional": predio_actual.get("codigo_predial_nacional"),
                "municipio": predio_actual.get("municipio"),
                "direccion": predio_actual.get("direccion"),
                "nombre_propietario": predio_actual.get("nombre_propietario"),
                "propietarios": predio_actual.get("propietarios", []),
                "area_terreno": predio_actual.get("area_terreno"),
                "area_construida": predio_actual.get("area_construida"),
                "avaluo": predio_actual.get("avaluo"),
                "destino_economico": predio_actual.get("destino_economico"),
                "zona": predio_actual.get("zona"),
            }
            update_data["datos_anteriores"] = datos_anteriores
    
    # Si se aprueba, aplicar el cambio
    if request.aprobado:
        resultado = await aplicar_cambio_predio(cambio, current_user)
        update_data["resultado"] = resultado
        
        # === GENERAR RESOLUCIÓN PDF AUTOMÁTICAMENTE ===
        try:
            resolucion_data = await generar_resolucion_final(cambio, current_user)
            if resolucion_data:
                update_data["resolucion"] = resolucion_data
                
                # Actualizar el historial del predio con el pdf_path de la resolución
                if cambio.get("predio_id") and resolucion_data.get("pdf_path"):
                    await db.predios.update_one(
                        {"id": cambio["predio_id"], "historial.cambio_id": cambio["id"]},
                        {"$set": {
                            "historial.$.pdf_path": resolucion_data.get("pdf_path"),
                            "historial.$.numero_resolucion": resolucion_data.get("numero_resolucion"),
                            "historial.$.tipo_mutacion": resolucion_data.get("tipo_mutacion")
                        }}
                    )
                
                logging.info(f"Resolución generada: {resolucion_data.get('numero_resolucion')}")
        except Exception as e:
            logging.error(f"Error generando resolución automática: {str(e)}")
            # No interrumpir el flujo si falla la generación del PDF
    
    await db.predios_cambios.update_one(
        {"id": request.cambio_id},
        {"$set": update_data}
    )
    
    # Notificar al usuario que propuso el cambio
    if cambio.get("propuesto_por"):
        codigo_predio = cambio.get("datos_propuestos", {}).get("codigo_predial_nacional",
                        cambio.get("datos_propuestos", {}).get("codigo_homologado", "N/A"))

        try:
            if request.aprobado:
                # Notificar aprobación - incluir instrucción para sincronizar
                await crear_notificacion(
                    usuario_id=cambio["propuesto_por"],
                    titulo="✅ Cambio de Predio Aprobado",
                    mensaje=f"El cambio propuesto para el predio {codigo_predio} ha sido aprobado por {current_user['full_name']}. Por favor, sincronice los datos del municipio para ver los cambios actualizados.",
                    tipo="success",
                    enlace=f"/dashboard/conservacion?municipio={cambio.get('datos_propuestos', {}).get('municipio', '')}",
                    enviar_email=False
                )
            else:
                # Notificar rechazo
                await crear_notificacion(
                    usuario_id=cambio["propuesto_por"],
                    titulo="❌ Cambio de Predio Rechazado",
                    mensaje=f"El cambio propuesto para el predio {codigo_predio} ha sido rechazado por {current_user['full_name']}. Motivo: {request.comentario or 'Sin comentario'}",
                    tipo="warning",
                    enlace="/dashboard/pendientes",
                    enviar_email=False
                )
        except Exception as e:
            logging.error(f"Error enviando notificación de aprobación/rechazo: {e}")
    
    # === WEBSOCKET NOTIFICATION ===
    # Broadcast real-time notification to all connected users
    ws_notification = {
        "type": "cambio_predio",
        "action": "aprobado" if request.aprobado else "rechazado",
        "cambio_id": request.cambio_id,
        "predio_id": cambio.get("predio_id"),
        "codigo_predio": cambio.get("datos_propuestos", {}).get("codigo_homologado", "N/A"),
        "municipio": cambio.get("datos_propuestos", {}).get("municipio", ""),
        "decidido_por": current_user['full_name'],
        "propuesto_por": cambio.get("propuesto_por"),
        "timestamp": datetime.now(COLOMBIA_TZ).isoformat()
    }
    await ws_manager.broadcast(ws_notification, exclude_user=current_user['id'])
    
    return {
        "mensaje": "Cambio aprobado y aplicado" if request.aprobado else "Cambio rechazado",
        "estado": nuevo_estado
    }


# ===== ENDPOINTS PARA FLUJO DE GESTOR DE APOYO EN MODIFICACIONES =====

@api_router.get("/predios/cambios/mis-asignaciones")
async def get_mis_asignaciones_apoyo(
    skip: int = 0,
    limit: int = 50,
    current_user: dict = Depends(get_current_user)
):
    """Obtiene las modificaciones asignadas al gestor de apoyo actual"""
    query = {
        "gestor_apoyo_id": current_user['id'],
        "estado": "en_digitalizacion"
    }
    
    total = await db.predios_cambios.count_documents(query)
    cambios = await db.predios_cambios.find(query, {"_id": 0}).sort("fecha_asignacion_apoyo", -1).skip(skip).limit(limit).to_list(limit)
    
    # Enriquecer con datos del predio actual
    for cambio in cambios:
        if cambio.get("predio_id"):
            predio = await db.predios.find_one(
                {"id": cambio["predio_id"]}, 
                {"_id": 0, "historial": 0}
            )
            cambio["predio_actual"] = predio
    
    return {
        "total": total,
        "cambios": cambios
    }


