# ========================================
# ENDPOINTS DE BLOQUEO DE PREDIOS
# ========================================

class BloquearPredioRequest(BaseModel):
    motivo: str
    numero_proceso: Optional[str] = None
    entidad_judicial: Optional[str] = None
    observaciones: Optional[str] = None

class DesbloquearPredioRequest(BaseModel):
    motivo: str
    observaciones: Optional[str] = None


@api_router.post("/predios/{predio_id}/bloquear")
async def bloquear_predio(
    predio_id: str,
    request: BloquearPredioRequest,
    current_user: dict = Depends(get_current_user)
):
    """
    Bloquea un predio por proceso legal. Solo coordinadores pueden bloquear.
    El predio bloqueado no podrá ser modificado por ninguna mutación.
    """
    # Solo coordinadores pueden bloquear
    if current_user['role'] not in [UserRole.COORDINADOR, UserRole.ADMINISTRADOR]:
        raise HTTPException(
            status_code=403, 
            detail="Solo los coordinadores pueden bloquear predios"
        )
    
    # Buscar el predio
    predio = await db.predios.find_one({"id": predio_id}, {"_id": 0})
    if not predio:
        raise HTTPException(status_code=404, detail="Predio no encontrado")
    
    # Verificar si ya está bloqueado
    if predio.get("bloqueado"):
        raise HTTPException(
            status_code=400, 
            detail="El predio ya está bloqueado"
        )
    
    # Crear información de bloqueo
    fecha_actual = datetime.now(COLOMBIA_TZ).isoformat()
    bloqueo_info = {
        "motivo": request.motivo,
        "numero_proceso": request.numero_proceso or "",
        "entidad_judicial": request.entidad_judicial or "",
        "observaciones": request.observaciones or "",
        "fecha_bloqueo": fecha_actual,
        "bloqueado_por_id": current_user['id'],
        "bloqueado_por_nombre": current_user['full_name']
    }
    
    # Entrada para historial
    historial_entry = {
        "accion": "BLOQUEO",
        "fecha": fecha_actual,
        "usuario_id": current_user['id'],
        "usuario_nombre": current_user['full_name'],
        "motivo": request.motivo,
        "numero_proceso": request.numero_proceso or "",
        "entidad_judicial": request.entidad_judicial or "",
        "observaciones": request.observaciones or ""
    }
    
    # Actualizar el predio seleccionado
    await db.predios.update_one(
        {"id": predio_id},
        {
            "$set": {
                "bloqueado": True,
                "bloqueo_info": bloqueo_info,
                "ultima_actualizacion": fecha_actual
            },
            "$push": {
                "historial_bloqueos": historial_entry
            }
        }
    )
    
    # Propagar el bloqueo a TODAS las vigencias del mismo código predial
    codigo_predial = predio.get("codigo_predial_nacional", "")
    if codigo_predial:
        result = await db.predios.update_many(
            {
                "codigo_predial_nacional": codigo_predial,
                "id": {"$ne": predio_id}  # Excluir el que ya actualizamos
            },
            {
                "$set": {
                    "bloqueado": True,
                    "bloqueo_info": bloqueo_info,
                    "ultima_actualizacion": fecha_actual
                },
                "$push": {
                    "historial_bloqueos": historial_entry
                }
            }
        )
        logging.info(f"🔒 Bloqueo propagado a {result.modified_count} vigencias adicionales del predio {codigo_predial}")
    
    # Registrar en log de actividades
    await registrar_log_actividad(
        accion="bloquear_predio",
        categoria="predios",
        descripcion=f"Bloqueó el predio {predio.get('codigo_predial_nacional', predio_id)} por proceso legal",
        usuario_id=current_user['id'],
        usuario_nombre=current_user['full_name'],
        usuario_rol=current_user['role'],
        municipio=predio.get('municipio', ''),
        detalles={
            "predio_id": predio_id,
            "codigo_predial": predio.get('codigo_predial_nacional', ''),
            "motivo": request.motivo,
            "numero_proceso": request.numero_proceso
        }
    )
    
    logging.info(f"🔒 Predio {predio_id} bloqueado por {current_user['full_name']}")
    
    return {
        "success": True,
        "mensaje": "Predio bloqueado exitosamente",
        "predio_id": predio_id,
        "bloqueo_info": bloqueo_info
    }


@api_router.post("/predios/{predio_id}/desbloquear")
async def desbloquear_predio(
    predio_id: str,
    request: DesbloquearPredioRequest,
    current_user: dict = Depends(get_current_user)
):
    """
    Desbloquea un predio. Solo coordinadores pueden desbloquear.
    """
    # Solo coordinadores pueden desbloquear
    if current_user['role'] not in [UserRole.COORDINADOR, UserRole.ADMINISTRADOR]:
        raise HTTPException(
            status_code=403, 
            detail="Solo los coordinadores pueden desbloquear predios"
        )
    
    # Buscar el predio
    predio = await db.predios.find_one({"id": predio_id}, {"_id": 0})
    if not predio:
        raise HTTPException(status_code=404, detail="Predio no encontrado")
    
    # Verificar si está bloqueado
    if not predio.get("bloqueado"):
        raise HTTPException(
            status_code=400, 
            detail="El predio no está bloqueado"
        )
    
    fecha_actual = datetime.now(COLOMBIA_TZ).isoformat()
    
    # Entrada para historial
    historial_entry = {
        "accion": "DESBLOQUEO",
        "fecha": fecha_actual,
        "usuario_id": current_user['id'],
        "usuario_nombre": current_user['full_name'],
        "motivo": request.motivo,
        "observaciones": request.observaciones or "",
        "bloqueo_anterior": predio.get("bloqueo_info", {})
    }
    
    # Actualizar el predio seleccionado
    await db.predios.update_one(
        {"id": predio_id},
        {
            "$set": {
                "bloqueado": False,
                "bloqueo_info": None,
                "ultima_actualizacion": fecha_actual
            },
            "$push": {
                "historial_bloqueos": historial_entry
            }
        }
    )
    
    # Propagar el desbloqueo a TODAS las vigencias del mismo código predial
    codigo_predial = predio.get("codigo_predial_nacional", "")
    if codigo_predial:
        result = await db.predios.update_many(
            {
                "codigo_predial_nacional": codigo_predial,
                "id": {"$ne": predio_id}  # Excluir el que ya actualizamos
            },
            {
                "$set": {
                    "bloqueado": False,
                    "bloqueo_info": None,
                    "ultima_actualizacion": fecha_actual
                },
                "$push": {
                    "historial_bloqueos": historial_entry
                }
            }
        )
        logging.info(f"🔓 Desbloqueo propagado a {result.modified_count} vigencias adicionales del predio {codigo_predial}")
    
    # Registrar en log de actividades
    await registrar_log_actividad(
        accion="desbloquear_predio",
        categoria="predios",
        descripcion=f"Desbloqueó el predio {predio.get('codigo_predial_nacional', predio_id)}",
        usuario_id=current_user['id'],
        usuario_nombre=current_user['full_name'],
        usuario_rol=current_user['role'],
        municipio=predio.get('municipio', ''),
        detalles={
            "predio_id": predio_id,
            "codigo_predial": predio.get('codigo_predial_nacional', ''),
            "motivo": request.motivo
        }
    )
    
    logging.info(f"🔓 Predio {predio_id} desbloqueado por {current_user['full_name']}")
    
    return {
        "success": True,
        "mensaje": "Predio desbloqueado exitosamente",
        "predio_id": predio_id
    }


@api_router.get("/predios/bloqueados")
async def listar_predios_bloqueados(
    municipio: Optional[str] = None,
    limit: int = 50,
    skip: int = 0,
    current_user: dict = Depends(get_current_user)
):
    """
    Lista todos los predios bloqueados. Accesible para todos los usuarios.
    """
    filtro = {"bloqueado": True}
    
    if municipio:
        filtro["municipio"] = {"$regex": municipio, "$options": "i"}
    
    total = await db.predios.count_documents(filtro)
    
    predios = await db.predios.find(
        filtro,
        {
            "_id": 0,
            "id": 1,
            "codigo_predial_nacional": 1,
            "codigo_predial": 1,
            "direccion": 1,
            "municipio": 1,
            "nombre_propietario": 1,
            "bloqueado": 1,
            "bloqueo_info": 1
        }
    ).sort("bloqueo_info.fecha_bloqueo", -1).skip(skip).limit(limit).to_list(length=limit)
    
    return {
        "predios": predios,
        "total": total,
        "pagina_actual": skip // limit + 1,
        "total_paginas": (total + limit - 1) // limit
    }


@api_router.get("/predios/{predio_id}/historial-bloqueos")
async def obtener_historial_bloqueos(
    predio_id: str,
    current_user: dict = Depends(get_current_user)
):
    """
    Obtiene el historial de bloqueos/desbloqueos de un predio.
    """
    predio = await db.predios.find_one(
        {"id": predio_id},
        {"_id": 0, "historial_bloqueos": 1, "bloqueado": 1, "bloqueo_info": 1}
    )
    
    if not predio:
        raise HTTPException(status_code=404, detail="Predio no encontrado")
    
    return {
        "bloqueado": predio.get("bloqueado", False),
        "bloqueo_info": predio.get("bloqueo_info"),
        "historial": predio.get("historial_bloqueos", [])
    }


# Función auxiliar para verificar si un predio está bloqueado
async def verificar_predio_bloqueado(predio_id: str) -> dict:
    """
    Verifica si un predio está bloqueado.
    Retorna {"bloqueado": True/False, "info": {...}} 
    """
    predio = await db.predios.find_one(
        {"id": predio_id},
        {"_id": 0, "bloqueado": 1, "bloqueo_info": 1}
    )
    
    if not predio:
        return {"bloqueado": False, "info": None, "existe": False}
    
    return {
        "bloqueado": predio.get("bloqueado", False),
        "info": predio.get("bloqueo_info"),
        "existe": True
    }


class VincularRadicadoRequest(BaseModel):
    radicado_id: str
    radicado_numero: Optional[str] = None

@api_router.patch("/predios/cambios/{cambio_id}/vincular-radicado")
async def vincular_radicado_a_cambio(
    cambio_id: str,
    request: VincularRadicadoRequest,
    current_user: dict = Depends(get_current_user)
):
    """Vincula un radicado/petición a un cambio pendiente existente"""
    # Permitir a coordinadores, admins y gestores
    if current_user['role'] not in [UserRole.COORDINADOR, UserRole.ADMINISTRADOR, UserRole.GESTOR]:
        raise HTTPException(status_code=403, detail="No tiene permiso para vincular radicados")
    
    # Buscar el cambio
    cambio = await db.predios_cambios.find_one({"id": cambio_id}, {"_id": 0})
    if not cambio:
        raise HTTPException(status_code=404, detail="Cambio no encontrado")
    
    # Actualizar con el radicado
    update_data = {
        "radicado_id": request.radicado_id,
        "radicado_numero": request.radicado_numero,
        "vinculado_por": current_user['id'],
        "vinculado_por_nombre": current_user['full_name'],
        "fecha_vinculacion": datetime.now(COLOMBIA_TZ).isoformat()
    }
    
    await db.predios_cambios.update_one(
        {"id": cambio_id},
        {"$set": update_data}
    )
    
    return {
        "mensaje": f"Radicado {request.radicado_numero} vinculado exitosamente",
        "cambio_id": cambio_id,
        "radicado_numero": request.radicado_numero
    }


async def aplicar_cambio_predio(cambio: dict, aprobador: dict) -> dict:
    """Aplica un cambio aprobado al predio"""
    tipo = cambio["tipo_cambio"]
    datos = cambio["datos_propuestos"]
    
    # Obtener número de resolución/acto administrativo
    numero_resolucion = (
        cambio.get("radicado_numero") or 
        datos.get("acto_administrativo") or 
        datos.get("numero_resolucion") or 
        datos.get("resolucion") or
        ""
    )
    
    historial_entry = {
        "accion": f"Cambio {tipo} aprobado",
        "tipo_cambio": tipo,
        "usuario": aprobador['full_name'],
        "usuario_id": aprobador.get('id'),
        "usuario_rol": aprobador['role'],
        "propuesto_por": cambio.get("propuesto_por_nombre"),
        "propuesto_por_id": cambio.get("propuesto_por"),
        "fecha": datetime.now(COLOMBIA_TZ).isoformat(),
        "comentario": cambio.get("comentario_aprobacion") or cambio.get("justificacion"),
        "numero_resolucion": numero_resolucion,
        "radicado_numero": cambio.get("radicado_numero"),
        "cambio_id": cambio.get("id")
    }
    
    if tipo == "creacion":
        # Agregar detalles específicos de creación al historial
        historial_entry["accion"] = "Predio creado"
        historial_entry["detalles"] = {
            "codigo_predial_nacional": datos.get("codigo_predial_nacional"),
            "propietario": datos.get("nombre_propietario") or (datos.get("propietarios", [{}])[0].get("nombre_propietario") if datos.get("propietarios") else ""),
            "area_terreno": datos.get("area_terreno"),
            "area_construida": datos.get("area_construida"),
            "avaluo": datos.get("avaluo"),
            "direccion": datos.get("direccion"),
            "destino_economico": datos.get("destino_economico")
        }
        
        # Crear nuevo predio
        predio_doc = datos.copy()
        predio_doc["id"] = str(uuid.uuid4())
        predio_doc["estado_aprobacion"] = PredioEstadoAprobacion.APROBADO
        predio_doc["deleted"] = False
        predio_doc["created_at"] = datetime.now(COLOMBIA_TZ).isoformat()
        predio_doc["updated_at"] = datetime.now(COLOMBIA_TZ).isoformat()
        # Guardar tipo_mutacion y resolución en el predio
        predio_doc["tipo_mutacion"] = datos.get("tipo_mutacion") or "Mutación Quinta"
        predio_doc["numero_resolucion"] = numero_resolucion
        predio_doc["fecha_resolucion"] = datos.get("fecha_resolucion") or datetime.now().strftime("%Y-%m-%d")
        predio_doc["historial"] = [historial_entry]
        
        await db.predios.insert_one(predio_doc)
        return {"predio_id": predio_doc["id"], "accion": "creado"}
    
    elif tipo == "modificacion":
        predio_id = cambio["predio_id"]
        
        # Obtener predio actual para comparar cambios
        predio_actual = await db.predios.find_one({"id": predio_id}, {"_id": 0})
        
        # Calcular qué campos se cambiaron
        campos_modificados = []
        if predio_actual:
            # Campos simples a comparar
            campos_simples = [
                ("direccion", "Dirección"),
                ("area_terreno", "Área Terreno"),
                ("area_construida", "Área Construida"),
                ("avaluo", "Avalúo"),
                ("destino_economico", "Destino Económico"),
                ("matricula_inmobiliaria", "Matrícula Inmobiliaria"),
            ]
            
            for campo, nombre in campos_simples:
                if campo in datos:
                    valor_anterior = predio_actual.get(campo)
                    valor_nuevo = datos.get(campo)
                    
                    # Normalizar valores para comparación precisa
                    def normalizar(v):
                        if v is None:
                            return ''
                        # Si es número, comparar como número
                        try:
                            num = float(v)
                            return num
                        except (ValueError, TypeError):
                            return str(v).strip().upper()
                    
                    val_ant_norm = normalizar(valor_anterior)
                    val_nuevo_norm = normalizar(valor_nuevo)
                    
                    # Solo agregar si realmente son diferentes
                    if val_ant_norm != val_nuevo_norm:
                        campos_modificados.append({
                            "campo": nombre,
                            "campo_key": campo,
                            "valor_anterior": valor_anterior,
                            "valor_nuevo": valor_nuevo
                        })
            
            # Comparación especial para propietarios: solo comparar nombre_propietario
            if "propietarios" in datos:
                # Obtener nombre del propietario anterior
                props_anterior = predio_actual.get("propietarios", [])
                nombre_anterior = props_anterior[0].get("nombre_propietario", "") if props_anterior else predio_actual.get("nombre_propietario", "")
                
                # Obtener nombre del propietario nuevo
                props_nuevo = datos.get("propietarios", [])
                nombre_nuevo = props_nuevo[0].get("nombre_propietario", "") if props_nuevo else ""
                
                # Solo registrar cambio si el nombre realmente cambió
                if nombre_anterior.strip().upper() != nombre_nuevo.strip().upper():
                    campos_modificados.append({
                        "campo": "Propietario",
                        "campo_key": "propietarios",
                        "valor_anterior": nombre_anterior,
                        "valor_nuevo": nombre_nuevo
                    })
            
            # Comparar zonas y construcciones solo si hay cambios significativos
            for campo, nombre in [("zonas", "Zonas R2"), ("construcciones", "Construcciones R2"), ("zonas_fisicas", "Zonas Físicas")]:
                if campo in datos:
                    valor_anterior = predio_actual.get(campo, [])
                    valor_nuevo = datos.get(campo, [])
                    # Solo comparar si la cantidad de elementos cambió o si hay diferencias
                    if len(valor_anterior) != len(valor_nuevo):
                        campos_modificados.append({
                            "campo": nombre,
                            "campo_key": campo,
                            "valor_anterior": f"{len(valor_anterior)} registros",
                            "valor_nuevo": f"{len(valor_nuevo)} registros"
                        })
        
        # Agregar detalles de modificación al historial
        historial_entry["accion"] = "Predio modificado"
        historial_entry["tipo_mutacion"] = datos.get("tipo_mutacion") or ""
        historial_entry["numero_resolucion"] = numero_resolucion or datos.get("numero_resolucion") or ""
        historial_entry["fecha_resolucion"] = datos.get("fecha_resolucion") or datetime.now().strftime("%Y-%m-%d")
        # Nota: pdf_path se actualizará después si se genera resolución
        historial_entry["detalles"] = {
            "campos_modificados": campos_modificados,
            "total_campos": len(campos_modificados)
        }
        
        # Actualizar predio
        datos["updated_at"] = datetime.now(COLOMBIA_TZ).isoformat()
        datos["estado_aprobacion"] = PredioEstadoAprobacion.APROBADO
        
        # CONCATENAR tipo_mutacion, numero_resolucion y fecha_resolucion (no reemplazar)
        # Formato: "Tipo1 (Res1, Fecha1) | Tipo2 (Res2, Fecha2)"
        tipo_mutacion_nuevo = datos.get("tipo_mutacion", "")
        resolucion_nueva = numero_resolucion or datos.get("numero_resolucion", "")
        fecha_resolucion_nueva = datos.get("fecha_resolucion", datetime.now().strftime("%Y-%m-%d"))
        
        if tipo_mutacion_nuevo or resolucion_nueva:
            # Construir la nueva entrada
            nueva_entrada = tipo_mutacion_nuevo
            if resolucion_nueva:
                nueva_entrada += f" ({resolucion_nueva}"
                if fecha_resolucion_nueva:
                    nueva_entrada += f", {fecha_resolucion_nueva}"
                nueva_entrada += ")"
            elif fecha_resolucion_nueva:
                nueva_entrada += f" ({fecha_resolucion_nueva})"
            
            # Concatenar con el valor anterior si existe
            tipo_mutacion_anterior = predio_actual.get("tipo_mutacion", "") if predio_actual else ""
            if tipo_mutacion_anterior and nueva_entrada:
                datos["tipo_mutacion"] = f"{tipo_mutacion_anterior} | {nueva_entrada}"
            elif nueva_entrada:
                datos["tipo_mutacion"] = nueva_entrada
            
            # Concatenar resoluciones
            resolucion_anterior = predio_actual.get("numero_resolucion", "") if predio_actual else ""
            if resolucion_anterior and resolucion_nueva:
                datos["numero_resolucion"] = f"{resolucion_anterior} | {resolucion_nueva}"
            elif resolucion_nueva:
                datos["numero_resolucion"] = resolucion_nueva
            
            # Concatenar fechas
            fecha_anterior = predio_actual.get("fecha_resolucion", "") if predio_actual else ""
            if fecha_anterior and fecha_resolucion_nueva:
                datos["fecha_resolucion"] = f"{fecha_anterior} | {fecha_resolucion_nueva}"
            elif fecha_resolucion_nueva:
                datos["fecha_resolucion"] = fecha_resolucion_nueva
        
        # Si se modifican áreas, activar sincronización automática R2→R1
        campos_area = ['area_terreno', 'area_construida', 'zonas', 'construcciones', 'zonas_fisicas', 'r2_registros', 'r2']
        if any(campo in datos for campo in campos_area):
            datos["area_editada_en_plataforma"] = True
        
        # Convertir r2 a formato r2_registros para mantener consistencia
        if "r2" in datos:
            r2_data = datos["r2"]
            datos["r2_registros"] = [{
                "matricula_inmobiliaria": r2_data.get("matricula_inmobiliaria"),
                "zonas": r2_data.get("zonas", [])
            }]
            del datos["r2"]  # Eliminar campo r2 para evitar duplicados
        
        await db.predios.update_one(
            {"id": predio_id},
            {
                "$set": datos,
                "$push": {"historial": historial_entry}
            }
        )
        return {"predio_id": predio_id, "accion": "modificado"}
    
    elif tipo == "eliminacion":
        predio_id = cambio["predio_id"]
        
        # Obtener datos del predio antes de eliminar
        predio = await db.predios.find_one({"id": predio_id}, {"_id": 0})
        
        if predio:
            # Guardar en predios_eliminados para el Excel de exportación
            eliminado_doc = {
                "id": str(uuid.uuid4()),
                "codigo_predial_nacional": predio.get("codigo_predial_nacional"),
                "codigo_homologado": predio.get("codigo_homologado"),
                "municipio": predio.get("municipio"),
                "direccion": predio.get("direccion"),
                "nombre_propietario": predio.get("nombre_propietario"),
                "propietarios": predio.get("propietarios", []),
                "area_terreno": predio.get("area_terreno"),
                "area_construida": predio.get("area_construida"),
                "avaluo": predio.get("avaluo"),
                "destino_economico": predio.get("destino_economico"),
                "vigencia_origen": predio.get("vigencia"),
                "vigencia_eliminacion": datetime.now().year,
                # Datos de la eliminación (vienen del modal)
                "radicado_eliminacion": datos.get("radicado") or datos.get("radicado_eliminacion"),
                "resolucion": datos.get("resolucion") or datos.get("numero_resolucion"),
                "fecha_resolucion": datos.get("fecha_resolucion"),
                "motivo": datos.get("motivo") or cambio.get("justificacion", "Eliminación de predio"),
                # Metadatos
                "eliminado_en": datetime.now(COLOMBIA_TZ).isoformat(),
                "eliminado_por": aprobador['full_name'],
                "eliminado_por_id": aprobador['id'],
                "predio_id_original": predio_id,
                "propuesto_por": cambio.get("propuesto_por_nombre"),
                "fecha_propuesta": cambio.get("fecha_propuesta")
            }
            await db.predios_eliminados.insert_one(eliminado_doc)
            logger.info(f"[Eliminación] Predio {predio.get('codigo_predial_nacional')} guardado en predios_eliminados")
        
        # Soft delete en la colección principal
        await db.predios.update_one(
            {"id": predio_id},
            {
                "$set": {
                    "deleted": True,
                    "deleted_at": datetime.now(COLOMBIA_TZ).isoformat(),
                    "deleted_by": aprobador['id'],
                    "deleted_by_name": aprobador['full_name'],
                    "estado_aprobacion": PredioEstadoAprobacion.APROBADO,
                    "radicado_eliminacion": datos.get("radicado") or datos.get("radicado_eliminacion"),
                    "resolucion_eliminacion": datos.get("resolucion") or datos.get("numero_resolucion"),
                    "motivo_eliminacion": datos.get("motivo") or cambio.get("justificacion")
                },
                "$push": {"historial": historial_entry}
            }
        )
        return {"predio_id": predio_id, "accion": "eliminado"}
    
    return {"error": "Tipo de cambio no reconocido"}


@api_router.get("/predios/cambios/mis-propuestas")
async def get_mis_propuestas(
    skip: int = 0,
    limit: int = 50,
    current_user: dict = Depends(get_current_user)
):
    """Lista las propuestas de cambio del usuario actual"""
    if current_user['role'] == UserRole.USUARIO:
        raise HTTPException(status_code=403, detail="No tiene permiso")
    
    query = {"propuesto_por": current_user['id']}
    
    total = await db.predios_cambios.count_documents(query)
    cambios = await db.predios_cambios.find(query, {"_id": 0}).sort("fecha_propuesta", -1).skip(skip).limit(limit).to_list(limit)
    
    # Enriquecer con datos del predio actual
    for cambio in cambios:
        if cambio.get("predio_id"):
            predio = await db.predios.find_one(
                {"id": cambio["predio_id"]}, 
                {"_id": 0, "historial": 0}
            )
            if not predio:
                predio = await db.predios.find_one(
                    {"id": cambio["predio_id"], "deleted": True}, 
                    {"_id": 0, "historial": 0}
                )
            if not predio and cambio.get("datos_propuestos", {}).get("codigo_predial_nacional"):
                predio = await db.predios_eliminados.find_one(
                    {"codigo_predial_nacional": cambio["datos_propuestos"]["codigo_predial_nacional"]},
                    {"_id": 0}
                )
            cambio["predio_actual"] = predio
    
    return {
        "total": total,
        "cambios": cambios
    }


@api_router.get("/predios/cambios/stats")
async def get_cambios_stats(current_user: dict = Depends(get_current_user)):
    """Obtiene estadísticas de cambios pendientes e historial"""
    if current_user['role'] == UserRole.USUARIO:
        raise HTTPException(status_code=403, detail="No tiene permiso")
    
    pendientes_creacion = await db.predios_cambios.count_documents({"estado": PredioEstadoAprobacion.PENDIENTE_CREACION})
    pendientes_modificacion = await db.predios_cambios.count_documents({"estado": PredioEstadoAprobacion.PENDIENTE_MODIFICACION})
    pendientes_eliminacion = await db.predios_cambios.count_documents({"estado": PredioEstadoAprobacion.PENDIENTE_ELIMINACION})
    
    # Contar modificaciones en digitalización (flujo de gestor de apoyo)
    en_digitalizacion = await db.predios_cambios.count_documents({"estado": "en_digitalizacion"})
    
    # Mis asignaciones de apoyo pendientes
    mis_asignaciones_apoyo = await db.predios_cambios.count_documents({
        "gestor_apoyo_id": current_user['id'],
        "estado": "en_digitalizacion"
    })
    
    # Contar historial de cambios procesados
    historial_aprobados = await db.predios_cambios.count_documents({"estado": PredioEstadoAprobacion.APROBADO})
    historial_rechazados = await db.predios_cambios.count_documents({"estado": PredioEstadoAprobacion.RECHAZADO})
    
    return {
        "pendientes_creacion": pendientes_creacion,
        "pendientes_modificacion": pendientes_modificacion,
        "pendientes_eliminacion": pendientes_eliminacion,
        "en_digitalizacion": en_digitalizacion,
        "mis_asignaciones_apoyo": mis_asignaciones_apoyo,
        "total_pendientes": pendientes_creacion + pendientes_modificacion + pendientes_eliminacion,
        "historial_aprobados": historial_aprobados,
        "historial_rechazados": historial_rechazados,
        "total_historial": historial_aprobados + historial_rechazados
    }


@api_router.get("/predios/cambios/historial")
async def get_cambios_historial(
    limit: int = Query(50, ge=1, le=200),
    estado: Optional[str] = Query(None, description="Filtrar por estado: 'aprobado' o 'rechazado'"),
    tipo_cambio: Optional[str] = Query(None, description="Filtrar por tipo: 'creacion', 'modificacion', 'eliminacion'"),
    municipio: Optional[str] = Query(None, description="Filtrar por municipio"),
    fecha_desde: Optional[str] = Query(None, description="Fecha desde (YYYY-MM-DD)"),
    fecha_hasta: Optional[str] = Query(None, description="Fecha hasta (YYYY-MM-DD)"),
    current_user: dict = Depends(get_current_user)
):
    """Obtiene el historial de cambios aprobados y rechazados con filtros opcionales"""
    # Permitir a coordinadores, admins, gestores y atención ver el historial
    allowed_roles = [UserRole.COORDINADOR, UserRole.ADMINISTRADOR, UserRole.GESTOR, UserRole.ATENCION_USUARIO]
    if current_user['role'] not in allowed_roles:
        raise HTTPException(status_code=403, detail="No tiene permiso para ver el historial de cambios")
    
    # Buscar cambios que ya fueron procesados (aprobados o rechazados)
    estados_procesados = [
        PredioEstadoAprobacion.APROBADO,
        PredioEstadoAprobacion.RECHAZADO
    ]
    
    # Construir query con filtros
    query = {"estado": {"$in": estados_procesados}}
    
    # Filtro por estado específico
    if estado:
        if estado == 'aprobado':
            query["estado"] = PredioEstadoAprobacion.APROBADO
        elif estado == 'rechazado':
            query["estado"] = PredioEstadoAprobacion.RECHAZADO
    
    # Filtro por tipo de cambio
    if tipo_cambio:
        query["tipo_cambio"] = tipo_cambio
    
    # Filtro por municipio
    if municipio:
        query["datos_propuestos.municipio"] = municipio
    
    # Filtro por fecha
    if fecha_desde or fecha_hasta:
        fecha_query = {}
        if fecha_desde:
            fecha_query["$gte"] = fecha_desde + "T00:00:00"
        if fecha_hasta:
            fecha_query["$lte"] = fecha_hasta + "T23:59:59"
        query["fecha_aprobacion"] = fecha_query
    
    cambios = await db.predios_cambios.find(
        query,
        {"_id": 0}
    ).sort("fecha_aprobacion", -1).limit(limit).to_list(limit)
    
    # Enriquecer con datos del predio original
    for cambio in cambios:
        # Solo enriquecer si NO tiene datos_anteriores guardados (para compatibilidad con registros antiguos)
        if cambio.get('predio_id') and not cambio.get('datos_anteriores'):
            predio = await db.predios.find_one({"id": cambio['predio_id']}, {"_id": 0, "codigo_predial_nacional": 1, "nombre_propietario": 1, "codigo_homologado": 1, "direccion": 1, "municipio": 1, "area_terreno": 1, "area_construida": 1, "avaluo": 1, "destino_economico": 1, "zona": 1, "propietarios": 1})
            
            # Si no se encuentra, buscar incluyendo eliminados
            if not predio:
                predio = await db.predios.find_one({"id": cambio['predio_id'], "deleted": True}, {"_id": 0, "codigo_predial_nacional": 1, "nombre_propietario": 1, "codigo_homologado": 1, "direccion": 1, "municipio": 1, "area_terreno": 1, "area_construida": 1, "avaluo": 1, "destino_economico": 1, "zona": 1, "propietarios": 1})
            
            # Si aún no se encuentra, buscar en predios_eliminados
            if not predio and cambio.get("datos_propuestos", {}).get("codigo_predial_nacional"):
                predio = await db.predios_eliminados.find_one(
                    {"codigo_predial_nacional": cambio["datos_propuestos"]["codigo_predial_nacional"]},
                    {"_id": 0}
                )
            
            if predio:
                # Usar como predio_actual para mostrar datos de referencia (actuales)
                # Nota: Este es el estado ACTUAL, no el estado en el momento del cambio
                cambio['predio_actual'] = predio
                cambio['predio_actual_es_referencia'] = True  # Flag para indicar que no son datos históricos
    
    # Obtener lista de municipios únicos para el selector de filtros
    municipios_cursor = await db.predios_cambios.distinct("datos_propuestos.municipio", {"estado": {"$in": estados_procesados}})
    municipios = sorted([m for m in municipios_cursor if m])
    
    return {
        "cambios": cambios,
        "total": len(cambios),
        "municipios": municipios
    }


# ===== GEOGRAPHIC DATABASE (GDB) INTEGRATION =====

GDB_PATH = Path("/app/gdb_data/54003.gdb")

async def get_gdb_geometry_async(codigo_predial: str) -> Optional[dict]:
    """Get geometry for a property from MongoDB gdb_geometrias collection first, then fallback to GDB files"""
    
    try:
        # Buscar en la colección gdb_geometrias de MongoDB por código exacto
        geometria = await db.gdb_geometrias.find_one(
            {"codigo": codigo_predial},
            {"_id": 0}
        )
        
        if geometria:
            return {
                "type": "Feature",
                "geometry": geometria.get("geometry"),
                "properties": {
                    "codigo": codigo_predial,
                    "tipo": geometria.get("tipo", "Rural"),
                    "municipio": geometria.get("municipio", ""),
                    "area_m2": geometria.get("area_m2", 0)
                }
            }
        
        # Si no se encontró con código exacto, buscar el terreno base para mejoras
        # Una mejora tiene los últimos 8 dígitos != "00000000"
        # El terreno base es: primeros 21 dígitos + "000000000"
        if len(codigo_predial) == 30:
            ultimos_8 = codigo_predial[-8:]
            es_mejora = ultimos_8 != "00000000"
            
            if es_mejora:
                # Buscar el terreno base (mismo predio, sin edificio/piso/unidad/mejora)
                codigo_terreno_base = codigo_predial[:21] + "000000000"
                geometria = await db.gdb_geometrias.find_one(
                    {"codigo": codigo_terreno_base},
                    {"_id": 0}
                )
                
                if geometria:
                    return {
                        "type": "Feature",
                        "geometry": geometria.get("geometry"),
                        "properties": {
                            "codigo": codigo_predial,  # Mantener código original de la mejora
                            "codigo_terreno": codigo_terreno_base,  # Indicar que es del terreno
                            "tipo": geometria.get("tipo", "Rural"),
                            "municipio": geometria.get("municipio", ""),
                            "area_m2": geometria.get("area_m2", 0),
                            "es_mejora": True
                        }
                    }
                
                # Buscar por predio (primeros 21 dígitos) con cualquier terminación
                geometria = await db.gdb_geometrias.find_one(
                    {"codigo": {"$regex": f"^{codigo_predial[:21]}"}},
                    {"_id": 0}
                )
                
                if geometria:
                    return {
                        "type": "Feature",
                        "geometry": geometria.get("geometry"),
                        "properties": {
                            "codigo": codigo_predial,
                            "codigo_terreno": geometria.get("codigo"),
                            "tipo": geometria.get("tipo", "Rural"),
                            "municipio": geometria.get("municipio", ""),
                            "area_m2": geometria.get("area_m2", 0),
                            "es_mejora": True
                        }
                    }
        
        # Si no está en MongoDB, NO hacer búsqueda parcial
        # El predio simplemente no tiene geometría disponible
        return None
        
    except Exception as e:
        logger.error(f"Error getting geometry from MongoDB: {e}")
        return None


def get_gdb_geometry(codigo_predial: str) -> Optional[dict]:
    """Get geometry for a property from multiple GDB files, transformed to WGS84 for web mapping"""
    import geopandas as gpd
    from shapely.geometry import mapping
    
    # Mapeo de códigos de municipio a archivos GDB
    GDB_FILES = {
        '54003': '/app/gdb_data/54003.gdb',  # Ábrego
        '54109': '/app/gdb_data/54109.gdb',  # Bucarasica
        '54128': '/app/gdb_data/54128.gdb',  # Cáchira
    }
    
    try:
        # Extraer código de municipio del código predial (posiciones 0-5)
        municipio_code = codigo_predial[:5]
        
        # Determinar si es rural o urbano
        sector = codigo_predial[5:8]
        is_urban = sector != "000"
        
        # Buscar el archivo GDB correcto
        gdb_path = None
        for code, path in GDB_FILES.items():
            if municipio_code == code:
                gdb_path = Path(path)
                break
        
        if not gdb_path or not gdb_path.exists():
            # Intentar con el GDB por defecto
            if GDB_PATH.exists():
                gdb_path = GDB_PATH
            else:
                return None
        
        # Determinar nombre de capa (diferentes GDBs usan diferentes nombres)
        # 54003 (Ábrego): R_TERRENO_1, U_TERRENO_1
        # Otros: R_TERRENO, U_TERRENO
        if '54003' in str(gdb_path):
            layer = "U_TERRENO_1" if is_urban else "R_TERRENO_1"
        else:
            layer = "U_TERRENO" if is_urban else "R_TERRENO"
        
        # Leer capa y buscar el código
        gdf = gpd.read_file(str(gdb_path), layer=layer)
        match = gdf[gdf['codigo'] == codigo_predial]
        
        if len(match) == 0:
            return None
        
        # Obtener área y perímetro originales
        area_m2 = float(match.iloc[0]['shape_Area']) if 'shape_Area' in match.columns else None
        perimetro_m = float(match.iloc[0]['shape_Length']) if 'shape_Length' in match.columns else None
        
        # Transformar a WGS84
        match_wgs84 = match.to_crs(epsg=4326)
        
        geom = match_wgs84.iloc[0]['geometry']
        if geom is None:
            return None
            
        geojson = mapping(geom)
        
        return {
            "type": "Feature",
            "geometry": geojson,
            "properties": {
                "codigo": codigo_predial,
                "area_m2": area_m2,
                "perimetro_m": perimetro_m,
                "tipo": "Urbano" if is_urban else "Rural"
            }
        }
    except Exception as e:
        logger.error(f"Error reading GDB geometry: {e}")
        return None


@api_router.get("/predios/{predio_id}/geometria")
async def get_predio_geometry(predio_id: str, current_user: dict = Depends(get_current_user)):
    """Get geographic geometry for a property"""
    # Only staff can access geometry
    if current_user['role'] == UserRole.USUARIO:
        raise HTTPException(status_code=403, detail="No tiene permiso")
    
    # Get predio from database
    predio = await db.predios.find_one({"id": predio_id}, {"_id": 0})
    if not predio:
        raise HTTPException(status_code=404, detail="Predio no encontrado")
    
    codigo = predio.get("codigo_predial_nacional")
    if not codigo:
        raise HTTPException(status_code=404, detail="Predio sin código catastral")
    
    # Primero intentar con la función async que busca en MongoDB
    geometry = await get_gdb_geometry_async(codigo)
    if not geometry:
        # Fallback a la función que lee archivos GDB directamente
        geometry = get_gdb_geometry(codigo)
    if not geometry:
        raise HTTPException(status_code=404, detail="Geometría no disponible para este predio")
    
    return geometry


@api_router.get("/predios/codigo/{codigo_predial}/geometria")
async def get_geometry_by_code(codigo_predial: str, current_user: dict = Depends(get_current_user)):
    """Get geographic geometry directly by cadastral code"""
