@api_router.get("/actualizacion/proyectos/{proyecto_id}/ortofoto/file")
async def get_ortofoto_file(proyecto_id: str):
    """Sirve el archivo de ortofoto"""
    from fastapi.responses import FileResponse
    
    proyecto = await db.proyectos_actualizacion.find_one({"id": proyecto_id})
    if not proyecto or not proyecto.get('ortofoto_archivo'):
        raise HTTPException(status_code=404, detail="Ortofoto no encontrada")
    
    ortofoto_path = Path(proyecto['ortofoto_archivo'])
    if not ortofoto_path.exists():
        raise HTTPException(status_code=404, detail="Archivo de ortofoto no encontrado")
    
    # Determinar tipo MIME
    extension = ortofoto_path.suffix.lower()
    media_types = {
        '.tif': 'image/tiff',
        '.tiff': 'image/tiff',
        '.png': 'image/png',
        '.jpg': 'image/jpeg',
        '.jpeg': 'image/jpeg'
    }
    media_type = media_types.get(extension, 'application/octet-stream')
    
    return FileResponse(str(ortofoto_path), media_type=media_type)


async def procesar_gdb_actualizacion(proyecto_id: str, zip_path: str, municipio: str, modo_carga: str = "reemplazar", capa_especifica: Optional[str] = None):
    """Procesa el GDB de un proyecto de actualización y guarda las geometrías
    
    Args:
        modo_carga: "reemplazar" elimina todo antes, "incremental" solo añade/actualiza
        capa_especifica: Si se indica, solo procesa esa capa
    """
    import zipfile
    import tempfile
    import shutil
    
    logger.info(f"[GDB Actualizacion] Iniciando procesamiento para proyecto {proyecto_id}")
    logger.info(f"[GDB Actualizacion] Archivo: {zip_path}, Municipio: {municipio}")
    logger.info(f"[GDB Actualizacion] Modo: {modo_carga}, Capa específica: {capa_especifica}")
    
    temp_dir = tempfile.mkdtemp()
    try:
        # Extraer ZIP
        logger.info("[GDB Actualizacion] Extrayendo ZIP...")
        with zipfile.ZipFile(zip_path, 'r') as zip_ref:
            zip_ref.extractall(temp_dir)
        
        # Buscar .gdb o .shp
        gdb_path = None
        shp_files = []
        is_shapefile = False
        
        for root, dirs, files in os.walk(temp_dir):
            # Primero buscar .gdb (tiene prioridad)
            for d in dirs:
                if d.endswith('.gdb'):
                    gdb_path = os.path.join(root, d)
                    break
            if gdb_path:
                break
            
            # Si no hay .gdb, buscar archivos .shp
            for f in files:
                if f.endswith('.shp'):
                    shp_files.append(os.path.join(root, f))
        
        # Determinar qué tipo de archivo procesar
        if gdb_path:
            logger.info(f"[GDB Actualizacion] GDB encontrado: {gdb_path}")
            data_source = gdb_path
            is_shapefile = False
        elif shp_files:
            logger.info(f"[GDB Actualizacion] Shapefiles encontrados: {len(shp_files)}")
            for shp in shp_files:
                logger.info(f"  - {os.path.basename(shp)}")
            data_source = shp_files  # Lista de shapefiles
            is_shapefile = True
        else:
            logger.error("[GDB Actualizacion] No se encontró archivo .gdb ni .shp en el ZIP")
            raise Exception("No se encontró archivo .gdb ni .shp en el ZIP. Asegúrese de que el ZIP contenga una geodatabase (.gdb) o archivos shapefile (.shp)")
        
        
        # Leer capas según el tipo de archivo
        import pyogrio
        
        if is_shapefile:
            # Para Shapefiles, cada archivo .shp es una "capa"
            layer_names = [os.path.splitext(os.path.basename(shp))[0] for shp in shp_files]
            logger.info(f"[GDB/SHP Actualizacion] Shapefiles como capas: {layer_names}")
        else:
            # Para GDB, usar pyogrio para listar capas
            layers = pyogrio.list_layers(data_source)
            layer_names = [l[0] for l in layers]
            logger.info(f"[GDB Actualizacion] Capas encontradas: {len(layer_names)}")
        
        # Si se especificó una capa específica, verificar que exista
        if capa_especifica:
            if capa_especifica not in layer_names:
                # Buscar con case-insensitive
                capa_encontrada = None
                for ln in layer_names:
                    if ln.upper() == capa_especifica.upper():
                        capa_encontrada = ln
                        break
                if not capa_encontrada:
                    raise Exception(f"Capa '{capa_especifica}' no encontrada. Capas disponibles: {', '.join(layer_names[:15])}")
                capa_especifica = capa_encontrada
            logger.info(f"[GDB/SHP Actualizacion] Procesando solo capa específica: {capa_especifica}")
        
        # Buscar capas de terreno (usar mismos estándares que Conservación)
        rural_layers = ['R_TERRENO', 'R_TERRENO_1', 'r_terreno', 'TERRENO', 'terreno_rural', 'RURAL']
        urban_layers = ['U_TERRENO', 'U_TERRENO_1', 'u_terreno', 'terreno_urbano', 'URBANO']
        construccion_layers = ['U_CONSTRUCCION', 'R_CONSTRUCCION', 'CONSTRUCCION', 'U_UNIDAD', 'R_UNIDAD']
        perimetro_layers = ['PERIMETRO_URBANO', 'PERIMETRO', 'LIMITE_URBANO', 'perimetro_urbano']
        
        # Verificar qué capas están presentes
        rural_found = [l for l in layer_names if any(r.upper() in l.upper() for r in rural_layers)]
        urban_found = [l for l in layer_names if any(u.upper() in l.upper() for u in urban_layers)]
        perimetro_found = [l for l in layer_names if any(p.upper() in l.upper() for p in perimetro_layers)]
        
        logger.info(f"[GDB/SHP Actualizacion] Capas rurales detectadas: {rural_found}")
        logger.info(f"[GDB/SHP Actualizacion] Capas urbanas detectadas: {urban_found}")
        logger.info(f"[GDB/SHP Actualizacion] Capas perímetro detectadas: {perimetro_found}")
        
        geometrias_guardadas = 0
        construcciones_guardadas = 0
        
        # Lógica de eliminación según modo de carga
        if modo_carga == "reemplazar":
            # Eliminar TODAS las geometrías anteriores del proyecto
            logger.info("[GDB Actualizacion] Modo REEMPLAZAR: Eliminando todas las geometrías anteriores...")
            deleted_geom = await db.geometrias_actualizacion.delete_many({"proyecto_id": proyecto_id})
            deleted_const = await db.construcciones_actualizacion.delete_many({"proyecto_id": proyecto_id})
            logger.info(f"[GDB Actualizacion] Eliminadas {deleted_geom.deleted_count} geometrías y {deleted_const.deleted_count} construcciones")
        elif modo_carga == "incremental" and capa_especifica:
            # Solo eliminar geometrías de la capa específica
            logger.info(f"[GDB Actualizacion] Modo INCREMENTAL: Eliminando solo geometrías de capa '{capa_especifica}'...")
            deleted = await db.geometrias_actualizacion.delete_many({
                "proyecto_id": proyecto_id,
                "capa_origen": capa_especifica
            })
            logger.info(f"[GDB Actualizacion] Eliminadas {deleted.deleted_count} geometrías de capa '{capa_especifica}'")
        else:
            # Incremental sin capa específica: no eliminar nada
            logger.info("[GDB Actualizacion] Modo INCREMENTAL: Añadiendo sin eliminar...")
        
        # Si hay capa específica, procesar solo esa capa
        if capa_especifica:
            try:
                logger.info(f"[GDB/SHP Actualizacion] Procesando capa específica: {capa_especifica}")
                
                # Determinar la fuente de datos según el tipo
                if is_shapefile:
                    # Buscar el shapefile que coincide con la capa específica
                    shp_path = None
                    for shp in shp_files:
                        if os.path.splitext(os.path.basename(shp))[0].upper() == capa_especifica.upper():
                            shp_path = shp
                            break
                    if not shp_path:
                        raise Exception(f"Shapefile '{capa_especifica}' no encontrado")
                    gdf = pyogrio.read_dataframe(shp_path)
                else:
                    gdf = pyogrio.read_dataframe(data_source, layer=capa_especifica)
                
                if len(gdf) > 0:
                    # Convertir CRS de forma segura (asume MAGNA-SIRGAS si no hay CRS)
                    gdf = safe_convert_crs(gdf, capa_especifica)
                    logger.info(f"[GDB/SHP Actualizacion] Capa '{capa_especifica}' tiene {len(gdf)} registros")
                    
                    # Determinar tipo de zona basado en el nombre de la capa
                    tipo_zona = "otro"
                    if capa_especifica.upper().startswith("R_") or "RURAL" in capa_especifica.upper():
                        tipo_zona = "rural"
                    elif capa_especifica.upper().startswith("U_") or "URBAN" in capa_especifica.upper():
                        tipo_zona = "urbano"
                    elif "PERIMETRO" in capa_especifica.upper():
                        tipo_zona = "perimetro_urbano"
                    elif "MANZANA" in capa_especifica.upper():
                        tipo_zona = "manzana"
                    elif "SECTOR" in capa_especifica.upper():
                        tipo_zona = "sector"
                    
                    for idx, row in gdf.iterrows():
                        geom = row.geometry.__geo_interface__
                        props = {k: (str(v) if v is not None else None) for k, v in row.items() if k != 'geometry'}
                        props['zona'] = tipo_zona
                        props['proyecto_id'] = proyecto_id
                        props['municipio'] = municipio
                        props['capa_origen'] = capa_especifica
                        
                        # Obtener código si existe
                        codigo = props.get('CODIGO', props.get('codigo', props.get('NUMERO_PREDIAL', f"{capa_especifica}_{idx}")))
                        
                        await db.geometrias_actualizacion.insert_one({
                            "proyecto_id": proyecto_id,
                            "municipio": municipio,
                            "zona": tipo_zona,
                            "capa_origen": capa_especifica,
                            "codigo_predial": codigo,
                            "numero_predial": props.get('NUMERO_PREDIAL', props.get('numero_predial', '')),
                            "geometry": geom,
                            "properties": props,
                            "created_at": datetime.now(COLOMBIA_TZ)
                        })
                        geometrias_guardadas += 1
                    
                    logger.info(f"[GDB Actualizacion] Guardadas {geometrias_guardadas} geometrías de capa '{capa_especifica}'")
                else:
                    logger.warning(f"[GDB Actualizacion] Capa '{capa_especifica}' está vacía")
                    
            except Exception as e:
                logger.error(f"[GDB Actualizacion] Error procesando capa específica '{capa_especifica}': {e}")
                raise
            
            # Actualizar proyecto y finalizar
            await db.proyectos_actualizacion.update_one(
                {"id": proyecto_id},
                {"$set": {
                    "gdb_procesado": True,
                    "gdb_total_geometrias": geometrias_guardadas,
                    f"capa_{capa_especifica.lower()}_cargada": True,
                    "updated_at": datetime.now(COLOMBIA_TZ)
                }}
            )
            logger.info(f"[GDB/SHP Actualizacion] Carga de capa '{capa_especifica}' completada: {geometrias_guardadas} geometrías")
            return
        
        # Función auxiliar para leer un dataframe según el tipo de fuente
        def read_layer(layer_name):
            if is_shapefile:
                # Buscar el shapefile que coincide
                for shp in shp_files:
                    if os.path.splitext(os.path.basename(shp))[0].upper() == layer_name.upper():
                        return pyogrio.read_dataframe(shp)
                return None
            else:
                return pyogrio.read_dataframe(data_source, layer=layer_name)
        
        # Función auxiliar para convertir CRS de forma segura
        def safe_convert_crs(gdf, layer_name):
            """Convierte el CRS a WGS84 (EPSG:4326), asumiendo MAGNA-SIRGAS si no hay CRS definido"""
            if gdf.crs is None:
                logger.warning(f"[GDB/SHP] Capa '{layer_name}' no tiene CRS definido. Asumiendo MAGNA-SIRGAS (EPSG:3116)")
                gdf = gdf.set_crs(epsg=3116)  # MAGNA-SIRGAS Colombia Bogotá zone
            return gdf.to_crs(epsg=4326)
        
        # Procesar capas estándar (comportamiento original)
        # Procesar terrenos rurales
        for layer_name in rural_found:
            try:
                logger.info(f"[GDB/SHP Actualizacion] Procesando capa rural: {layer_name}")
                gdf = read_layer(layer_name)
                if gdf is not None and len(gdf) > 0:
                    gdf = safe_convert_crs(gdf, layer_name)
                    for idx, row in gdf.iterrows():
                        geom = row.geometry.__geo_interface__
                        props = {k: (str(v) if v is not None else None) for k, v in row.items() if k != 'geometry'}
                        props['zona'] = 'rural'
                        props['proyecto_id'] = proyecto_id
                        props['municipio'] = municipio
                        props['capa_origen'] = layer_name
                        
                        await db.geometrias_actualizacion.insert_one({
                            "proyecto_id": proyecto_id,
                            "municipio": municipio,
                            "zona": "rural",
                            "capa_origen": layer_name,
                            "codigo_predial": props.get('CODIGO', props.get('codigo', props.get('NUMERO_PREDIAL', ''))),
                            "numero_predial": props.get('NUMERO_PREDIAL', props.get('numero_predial', '')),
                            "geometry": geom,
                            "properties": props,
                            "created_at": datetime.now(COLOMBIA_TZ)
                        })
                        geometrias_guardadas += 1
            except Exception as e:
                logger.error(f"[GDB/SHP Actualizacion] Error procesando capa rural {layer_name}: {e}")
        
        # Procesar terrenos urbanos
        for layer_name in urban_found:
            try:
                logger.info(f"[GDB/SHP Actualizacion] Procesando capa urbana: {layer_name}")
                gdf = read_layer(layer_name)
                if gdf is not None and len(gdf) > 0:
                    logger.info(f"[GDB/SHP Actualizacion] Convirtiendo CRS de {len(gdf)} registros...")
                    gdf = safe_convert_crs(gdf, layer_name)
                    for idx, row in gdf.iterrows():
                        geom = row.geometry.__geo_interface__
                        props = {k: (str(v) if v is not None else None) for k, v in row.items() if k != 'geometry'}
                        props['zona'] = 'urbano'
                        props['proyecto_id'] = proyecto_id
                        props['municipio'] = municipio
                        props['capa_origen'] = layer_name
                        
                        await db.geometrias_actualizacion.insert_one({
                            "proyecto_id": proyecto_id,
                            "municipio": municipio,
                            "zona": "urbano",
                            "capa_origen": layer_name,
                            "codigo_predial": props.get('CODIGO', props.get('codigo', props.get('NUMERO_PREDIAL', ''))),
                            "numero_predial": props.get('NUMERO_PREDIAL', props.get('numero_predial', '')),
                            "geometry": geom,
                            "properties": props,
                            "created_at": datetime.now(COLOMBIA_TZ)
                        })
                        geometrias_guardadas += 1
            except Exception as e:
                logger.error(f"[GDB/SHP Actualizacion] Error procesando capa urbana {layer_name}: {e}")
        
        # Procesar capas de perímetro si existen
        for layer_name in perimetro_found:
            try:
                logger.info(f"[GDB/SHP Actualizacion] Procesando capa perímetro: {layer_name}")
                gdf = read_layer(layer_name)
                if gdf is not None and len(gdf) > 0:
                    gdf = safe_convert_crs(gdf, layer_name)
                    for idx, row in gdf.iterrows():
                        geom = row.geometry.__geo_interface__
                        props = {k: (str(v) if v is not None else None) for k, v in row.items() if k != 'geometry'}
                        props['zona'] = 'perimetro_urbano'
                        props['proyecto_id'] = proyecto_id
                        props['municipio'] = municipio
                        props['capa_origen'] = layer_name
                        
                        await db.geometrias_actualizacion.insert_one({
                            "proyecto_id": proyecto_id,
                            "municipio": municipio,
                            "zona": "perimetro_urbano",
                            "capa_origen": layer_name,
                            "codigo_predial": props.get('CODIGO', props.get('codigo', f"PERIMETRO_{idx}")),
                            "numero_predial": "",
                            "geometry": geom,
                            "properties": props,
                            "created_at": datetime.now(COLOMBIA_TZ)
                        })
                        geometrias_guardadas += 1
            except Exception as e:
                logger.error(f"[GDB/SHP Actualizacion] Error procesando capa perímetro {layer_name}: {e}")
        
        logger.info(f"[GDB/SHP Actualizacion] Geometrías guardadas hasta ahora: {geometrias_guardadas}")
        
        # Procesar construcciones (solo para GDB, shapefiles de construcción se procesan si existen)
        construccion_found = [l for l in layer_names if any(c.upper() in l.upper() for c in construccion_layers)]
        for layer_name in construccion_found:
            try:
                logger.info(f"[GDB/SHP Actualizacion] Procesando construcciones: {layer_name}")
                gdf = read_layer(layer_name)
                if gdf is not None and len(gdf) > 0:
                    gdf = safe_convert_crs(gdf, layer_name)
                    for idx, row in gdf.iterrows():
                        geom = row.geometry.__geo_interface__
                        props = {k: (str(v) if v is not None else None) for k, v in row.items() if k != 'geometry'}
                        
                        await db.construcciones_actualizacion.insert_one({
                            "proyecto_id": proyecto_id,
                            "municipio": municipio,
                            "capa_origen": layer_name,
                            "codigo_predial": props.get('CODIGO', props.get('codigo', '')),
                            "geometry": geom,
                            "properties": props,
                            "created_at": datetime.now(COLOMBIA_TZ)
                        })
                        construcciones_guardadas += 1
            except Exception as e:
                logger.error(f"[GDB/SHP Actualizacion] Error procesando construcciones {layer_name}: {e}")
                import traceback
                logger.error(f"[GDB/SHP Actualizacion] Traceback: {traceback.format_exc()}")
        
        logger.info(f"[GDB/SHP Actualizacion] Total construcciones guardadas: {construcciones_guardadas}")
        
        # Actualizar proyecto con información detallada de capas procesadas
        capas_info = {
            "rural_encontradas": rural_found,
            "urbano_encontradas": urban_found,
            "perimetro_encontradas": perimetro_found,
            "construccion_encontradas": construccion_found,
            "es_shapefile": is_shapefile
        }
        
        await db.proyectos_actualizacion.update_one(
            {"id": proyecto_id},
            {"$set": {
                "gdb_procesado": True,
                "base_grafica_total_predios": geometrias_guardadas,
                "total_construcciones": construcciones_guardadas,
                "gdb_procesado_en": datetime.now(COLOMBIA_TZ),
                "capas_procesadas": capas_info,
                "tiene_zona_rural": len(capas_info["rural_encontradas"]) > 0,
                "tiene_zona_urbana": len(capas_info["urbano_encontradas"]) > 0,
                "updated_at": datetime.now(COLOMBIA_TZ)
            }}
        )
        
        logger.info(f"[GDB Actualizacion] ✅ COMPLETADO: {geometrias_guardadas} geometrías, {construcciones_guardadas} construcciones")
        logger.info(f"[GDB Actualizacion] Capas - Rural: {capas_info['rural_encontradas']}, Urbano: {capas_info['urbano_encontradas']}")
        
    except Exception as e:
        logger.error(f"[GDB Actualizacion] ❌ ERROR GENERAL: {str(e)}")
        import traceback
        logger.error(f"[GDB Actualizacion] Traceback: {traceback.format_exc()}")
        raise
    finally:
        shutil.rmtree(temp_dir, ignore_errors=True)


@api_router.post("/actualizacion/proyectos/{proyecto_id}/resync-gdb")
async def resync_gdb_geometrias(
    proyecto_id: str,
    background_tasks: BackgroundTasks,
    current_user: dict = Depends(get_current_user)
):
    """
    Fuerza la re-sincronización de las geometrías GDB del proyecto.
    Útil cuando las geometrías no se cargaron correctamente o después de un fork.
    """
    import zipfile
    import tempfile
    
    if current_user['role'] not in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR]:
        raise HTTPException(status_code=403, detail="Solo administradores y coordinadores pueden resincronizar")
    
    proyecto = await db.proyectos_actualizacion.find_one({"id": proyecto_id}, {"_id": 0})
    if not proyecto:
        raise HTTPException(status_code=404, detail="Proyecto no encontrado")
    
    # Buscar archivo GDB
    proyecto_dir = Path(f"/app/proyectos_actualizacion/{proyecto_id}")
    if not proyecto_dir.exists():
        raise HTTPException(status_code=404, detail="Directorio del proyecto no existe")
    
    gdb_files = list(proyecto_dir.glob("*.zip")) + list(proyecto_dir.glob("*.gdb"))
    gdb_file = None
    
    for f in gdb_files:
        if "base_grafica" in f.name.lower() or "gdb" in f.name.lower():
            gdb_file = f
            break
    
    if not gdb_file:
        raise HTTPException(status_code=404, detail="No se encontró archivo GDB en el proyecto")
    
    # Contar geometrías actuales
    count_actual = await db.geometrias_actualizacion.count_documents({"proyecto_id": proyecto_id})
    
    # Ejecutar sincronización en background
    async def sync_task():
        temp_dir = None
        try:
            temp_dir = tempfile.mkdtemp()
            gdb_path = None
            
            if gdb_file.suffix.lower() == '.zip':
                with zipfile.ZipFile(gdb_file, 'r') as z:
                    z.extractall(temp_dir)
                
                for item in Path(temp_dir).rglob("*.gdb"):
                    if item.is_dir():
                        gdb_path = item
                        break
            else:
                gdb_path = gdb_file
            
            if not gdb_path or not gdb_path.exists():
                logger.error("Resync: No se encontró GDB válido")
                return
            
            import fiona
            capas = fiona.listlayers(str(gdb_path))
            
            # Buscar capa de terrenos
            capa_terrenos = None
            for capa in capas:
                if any(t in capa.upper() for t in ['TERRENO', 'U_TERRENO', 'R_TERRENO']):
                    capa_terrenos = capa
                    break
            
            if not capa_terrenos:
                for capa in capas:
                    try:
                        with fiona.open(str(gdb_path), layer=capa) as src:
                            if src.schema.get('geometry') in ['Polygon', 'MultiPolygon']:
                                capa_terrenos = capa
                                break
                    except:
                        continue
            
            if not capa_terrenos:
                logger.error("Resync: No se encontró capa de terrenos")
                return
            
            # Eliminar geometrías existentes
            await db.geometrias_actualizacion.delete_many({"proyecto_id": proyecto_id})
            
            # Procesar nuevas geometrías
            geometrias_batch = []
            municipio = proyecto.get("municipio", "")
            
            with fiona.open(str(gdb_path), layer=capa_terrenos) as src:
                for feat in src:
                    props = feat.get('properties', {})
                    geom = feat.get('geometry')
                    
                    codigo = (
                        props.get('codigo') or 
                        props.get('CODIGO') or 
                        props.get('terreno_codigo') or
                        props.get('codigo_predial') or
                        ''
                    )
                    
                    if not codigo or not geom:
                        continue
                    
                    zona = "urbano" if str(codigo)[9:11] == "01" else "rural"
                    
                    geometrias_batch.append({
                        "proyecto_id": proyecto_id,
                        "codigo_predial": str(codigo).strip(),
                        "numero_predial": str(props.get('numero_predial', '')).strip(),
                        "zona": zona,
                        "geometry": dict(geom),
                        "properties": {k: str(v) if v else None for k, v in props.items()},
                        "municipio": municipio,
                        "created_at": datetime.now(COLOMBIA_TZ)
                    })
                    
                    if len(geometrias_batch) >= 1000:
                        await db.geometrias_actualizacion.insert_many(geometrias_batch)
                        geometrias_batch = []
            
            if geometrias_batch:
                await db.geometrias_actualizacion.insert_many(geometrias_batch)
            
            total = await db.geometrias_actualizacion.count_documents({"proyecto_id": proyecto_id})
            
            await db.proyectos_actualizacion.update_one(
                {"id": proyecto_id},
                {"$set": {
                    "base_grafica_archivo": str(gdb_file),
                    "base_grafica_cargado_en": datetime.now(COLOMBIA_TZ),
                    "total_geometrias": total
                }}
            )
            
            logger.info(f"Resync completado: {total} geometrías sincronizadas para proyecto {proyecto_id}")
            
        except Exception as e:
            logger.error(f"Error en resync: {str(e)}")
        finally:
            if temp_dir:
                shutil.rmtree(temp_dir, ignore_errors=True)
    
    background_tasks.add_task(sync_task)
    
    return {
        "message": "Resincronización iniciada en segundo plano",
        "proyecto_id": proyecto_id,
        "archivo_gdb": gdb_file.name,
        "geometrias_actuales": count_actual
    }


@api_router.get("/actualizacion/proyectos/{proyecto_id}/geometrias/info")
async def get_geometrias_info(
    proyecto_id: str,
    zona: str = Query(None, description="Filtrar por zona: urbano, rural"),
    current_user: dict = Depends(get_current_user)
):
    """Obtiene información sobre las geometrías del proyecto (para descarga progresiva)"""
    if current_user['role'] not in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR, UserRole.GESTOR]:
        raise HTTPException(status_code=403, detail="No tiene permiso")
    
    query = {"proyecto_id": proyecto_id}
    if zona:
        query["zona"] = zona
    
    total = await db.geometrias_actualizacion.count_documents(query)
    total_construcciones = await db.construcciones_actualizacion.count_documents({"proyecto_id": proyecto_id})
    
    return {
        "total": total,
        "total_construcciones": total_construcciones,
        "proyecto_id": proyecto_id
    }


@api_router.get("/actualizacion/proyectos/{proyecto_id}/geometrias")
async def get_geometrias_proyecto(
    proyecto_id: str,
    zona: str = Query(None, description="Filtrar por zona: urbano, rural"),
    offset: int = Query(0, description="Offset para paginación"),
    limit: int = Query(50000, description="Límite de resultados"),
    current_user: dict = Depends(get_current_user)
):
    """Obtiene las geometrías procesadas del proyecto para el visor"""
    if current_user['role'] not in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR, UserRole.GESTOR]:
        raise HTTPException(status_code=403, detail="No tiene permiso para ver geometrías")
    
    proyecto = await db.proyectos_actualizacion.find_one({"id": proyecto_id}, {"_id": 0})
    if not proyecto:
        raise HTTPException(status_code=404, detail="Proyecto no encontrado")
    
    # Query de geometrías con paginación
    query = {"proyecto_id": proyecto_id}
    if zona:
        query["zona"] = zona
    
    geometrias = await db.geometrias_actualizacion.find(query, {"_id": 0}).skip(offset).limit(limit).to_list(limit)
    
    # Solo cargar construcciones en la primera página (offset=0)
    construcciones = []
    if offset == 0:
        construcciones = await db.construcciones_actualizacion.find({"proyecto_id": proyecto_id}, {"_id": 0}).to_list(50000)
    
    # ENRIQUECER GEOMETRÍAS CON DATOS DE PROPIETARIOS desde predios_actualizacion
    # Crear un mapa de código -> propietario para enriquecimiento rápido
    codigos_geom = [g.get("codigo_predial") for g in geometrias if g.get("codigo_predial")]
    propietarios_map = {}
    if codigos_geom:
        predios_con_prop = await db.predios_actualizacion.find(
            {"proyecto_id": proyecto_id, "codigo_predial": {"$in": codigos_geom}},
            {"_id": 0, "codigo_predial": 1, "propietarios": 1, "propietario": 1, "nombre_propietario": 1, 
             "direccion": 1, "area_terreno": 1, "area_construida": 1, "avaluo_catastral": 1, "estado_visita": 1}
        ).to_list(len(codigos_geom))
        
        for p in predios_con_prop:
            cpn = p.get("codigo_predial")
            if cpn:
                # Extraer nombre del propietario del array o del campo directo
                nombre_prop = p.get("nombre_propietario") or p.get("propietario")
                if not nombre_prop:
                    propietarios_arr = p.get("propietarios", [])
                    if propietarios_arr and len(propietarios_arr) > 0:
                        nombre_prop = propietarios_arr[0].get("nombre_propietario", "")
                
                propietarios_map[cpn] = {
                    "propietario": nombre_prop,
                    "direccion": p.get("direccion"),
                    "area_terreno": p.get("area_terreno"),
                    "area_construida": p.get("area_construida"),
                    "avaluo_catastral": p.get("avaluo_catastral"),
                    "estado_visita": p.get("estado_visita", "pendiente")
                }
    
    # Convertir a GeoJSON FeatureCollection con datos enriquecidos
    geom_features = []
    for g in geometrias:
        codigo = g.get("codigo_predial")
        extra_props = propietarios_map.get(codigo, {})
        
        geom_features.append({
            "type": "Feature",
            "geometry": g.get("geometry"),
            "properties": {
                "codigo_predial": codigo,
                "numero_predial": g.get("numero_predial"),
                "zona": g.get("zona"),
                "propietario": extra_props.get("propietario"),
                "direccion": extra_props.get("direccion"),
                "area_terreno_r1": extra_props.get("area_terreno"),
                "area_construida_r1": extra_props.get("area_construida"),
                "avaluo_catastral": extra_props.get("avaluo_catastral"),
                "estado_visita": extra_props.get("estado_visita", "pendiente"),
                **g.get("properties", {})
            }
        })
    
    constr_features = []
    for c in construcciones:
        constr_features.append({
            "type": "Feature",
            "geometry": c.get("geometry"),
            "properties": c.get("properties", {})
        })
    
    return {
        "geometrias": {
            "type": "FeatureCollection",
            "features": geom_features
        },
        "construcciones": {
            "type": "FeatureCollection",
            "features": constr_features
        },
        "total_geometrias": len(geom_features),
        "total_construcciones": len(constr_features),
        "offset": offset,
        "limit": limit
    }


@api_router.get("/actualizacion/proyectos/{proyecto_id}/predios")
async def get_predios_proyecto(
    proyecto_id: str,
    page: int = Query(1, ge=1, description="Número de página"),
    page_size: int = Query(500, ge=50, le=1000, description="Predios por página"),
    estado: Optional[str] = Query(None, description="Filtrar por estado: pendiente, visitado, actualizado"),
    search: Optional[str] = Query(None, description="Buscar por código predial, dirección o propietario"),
    zona: Optional[str] = Query(None, description="Filtrar por zona"),
    current_user: dict = Depends(get_current_user)
):
    """
    Obtiene los predios R1/R2 cargados para el proyecto con PAGINACIÓN.
    
    Para carga inicial rápida, el frontend puede usar page_size=500 y cargar 
    páginas adicionales en segundo plano.
    
    Parámetros:
    - page: Número de página (default 1)
    - page_size: Predios por página (default 500, max 1000)
    - estado: Filtrar por estado_visita (opcional)
    - search: Búsqueda por código, dirección o propietario
    - zona: Filtrar por zona (Urbano, Rural)
    """
    if current_user['role'] not in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR, UserRole.GESTOR]:
        raise HTTPException(status_code=403, detail="No tiene permiso para ver predios")
    
    proyecto = await db.proyectos_actualizacion.find_one({"id": proyecto_id}, {"_id": 0})
    if not proyecto:
        raise HTTPException(status_code=404, detail="Proyecto no encontrado")
    
    # Construir filtro
    filtro = {"proyecto_id": proyecto_id}
    if estado:
        filtro["estado_visita"] = estado
    if zona:
        filtro["zona"] = zona
    
    # Agregar búsqueda si se proporciona
    if search and len(search) >= 3:
        # Búsqueda por regex en múltiples campos
        filtro["$or"] = [
            {"codigo_predial": {"$regex": search, "$options": "i"}},
            {"direccion": {"$regex": search, "$options": "i"}},
            {"propietarios.nombre_propietario": {"$regex": search, "$options": "i"}}
        ]
    
    # Contar total PRIMERO (usa índice, es rápido)
    total = await db.predios_actualizacion.count_documents(filtro)
    
    # Calcular skip
    skip = (page - 1) * page_size
    
    # Obtener predios del proyecto CON PAGINACIÓN
    # Proyección optimizada: solo campos necesarios para la lista
    projection = {
        "_id": 0,
        "codigo_predial": 1,
        "numero_predial": 1,
        "direccion": 1,
        "propietario": 1,
        "nombre_propietario": 1,
        "propietarios": 1,  # IMPORTANTE: Incluir array de propietarios para mostrar nombre
        "destino_economico": 1,
        "area_terreno": 1,
        "area_construida": 1,
        "estado_visita": 1,
        "fecha_visita": 1,
        "visitado_por": 1,
        "zona": 1,
        "sector": 1,
        "manzana": 1,
        "observaciones": 1,
        "tiene_visita": 1,
        "sin_cambios": 1,
        "propuesta_pendiente": 1,
        "matricula_inmobiliaria": 1,
        "codigo_homologado": 1,
        "avaluo_catastral": 1,
        "avaluo": 1
    }
    
    predios = await db.predios_actualizacion.find(
        filtro,
        projection
    ).skip(skip).limit(page_size).to_list(page_size)
    
    # Extraer nombre_propietario del array propietarios si no existe directamente
    for predio in predios:
        if not predio.get('nombre_propietario') and not predio.get('propietario'):
            propietarios = predio.get('propietarios', [])
            if propietarios and len(propietarios) > 0:
                primer_prop = propietarios[0]
                predio['nombre_propietario'] = primer_prop.get('nombre_propietario', '')
    
    # Enriquecer con datos de la colección principal de predios (optimizado)
    if predios:
        codigos_prediales = [p.get('codigo_predial') for p in predios if p.get('codigo_predial')]
        
        if codigos_prediales:
            # Buscar datos adicionales - SOLO los campos necesarios
            # Priorizar documentos que tengan r2_registros con matrícula
            predios_principales = await db.predios.find(
                {"codigo_predial_nacional": {"$in": codigos_prediales}},
                {"_id": 0, "codigo_predial_nacional": 1, "codigo_homologado": 1, "r2_registros.matricula_inmobiliaria": 1}
            ).to_list(len(codigos_prediales) * 5)  # Aumentar límite para capturar duplicados
            
            # Crear mapas de código -> datos
            codigo_homologado_map = {}
            matricula_map = {}
            for p in predios_principales:
                cpn = p.get('codigo_predial_nacional')
                if cpn:
                    ch = p.get('codigo_homologado')
                    # Solo guardar código homologado si no existe aún
                    if ch and cpn not in codigo_homologado_map:
                        codigo_homologado_map[cpn] = ch
                    
                    # Para matrícula: SIEMPRE actualizar si encontramos una válida
                    # (puede haber duplicados donde solo algunos tienen matrícula)
                    r2 = p.get('r2_registros', [])
                    if r2 and len(r2) > 0:
                        mat = r2[0].get('matricula_inmobiliaria')
                        if mat and mat.strip():  # Solo si hay matrícula válida
                            matricula_map[cpn] = mat
            
            # Agregar datos a cada predio
            for predio in predios:
                codigo = predio.get('codigo_predial')
                if codigo:
                    if codigo in codigo_homologado_map:
                        predio['codigo_homologado'] = codigo_homologado_map[codigo]
                    if codigo in matricula_map:
                        predio['matricula_inmobiliaria'] = matricula_map[codigo]
    
    # Calcular metadatos de paginación
    total_pages = (total + page_size - 1) // page_size
    has_more = page < total_pages
    
    return {
        "predios": predios,
        "total": total,
        "page": page,
        "page_size": page_size,
        "total_pages": total_pages,
        "has_more": has_more
    }



@api_router.post("/actualizacion/proyectos/{proyecto_id}/predios")
async def crear_predio_actualizacion(
    proyecto_id: str,
    data: dict,
    current_user: dict = Depends(get_current_user)
):
    """
    Crea un nuevo predio dentro de un proyecto de actualización.
    El predio queda en predios_actualizacion para ser procesado durante la actualización.
    """
    if current_user['role'] not in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR, UserRole.GESTOR]:
        raise HTTPException(status_code=403, detail="No tiene permiso para crear predios")
    
    # Verificar que el proyecto existe y está activo
    proyecto = await db.proyectos_actualizacion.find_one({"id": proyecto_id}, {"_id": 0})
    if not proyecto:
        raise HTTPException(status_code=404, detail="Proyecto no encontrado")
    
    if proyecto.get('estado') not in [ProyectoActualizacionEstado.ACTIVO, ProyectoActualizacionEstado.PAUSADO]:
        raise HTTPException(status_code=400, detail="El proyecto no está activo")
    
    municipio = proyecto.get('municipio')
    codigo_predial = data.get('codigo_predial', '')
    
    if not codigo_predial:
        raise HTTPException(status_code=400, detail="El código predial es requerido")
    
    # Verificar que no exista en el proyecto actual
    existing = await db.predios_actualizacion.find_one({
        "proyecto_id": proyecto_id,
        "$or": [
            {"codigo_predial": codigo_predial},
            {"numero_predial": codigo_predial}
        ]
    })
    if existing:
        raise HTTPException(status_code=400, detail="Ya existe un predio con este código en el proyecto")
    
    # Crear el predio
    predio_id = str(uuid.uuid4())
    ahora = datetime.now(COLOMBIA_TZ).isoformat()
    
    predio_nuevo = {
        "id": predio_id,
        "proyecto_id": proyecto_id,
        "codigo_predial": codigo_predial,
        "codigo_predial_nacional": codigo_predial,
        "numero_predial": codigo_predial,
        "municipio": municipio,
        "es_nuevo": True,
        
        # Datos R1 - Jurídicos
        "direccion": data.get('direccion', ''),
        "comuna": data.get('comuna', ''),
        "destino_economico": data.get('destino_economico', ''),
        "area_terreno": float(data.get('area_terreno') or 0),
        "area_construida": float(data.get('area_construida') or 0),
        "avaluo": float(data.get('avaluo_catastral') or data.get('avaluo') or 0),
        "avaluo_catastral": float(data.get('avaluo_catastral') or data.get('avaluo') or 0),
        "matricula_inmobiliaria": data.get('matricula_inmobiliaria', ''),
        "codigo_homologado": data.get('codigo_homologado', ''),
        
        # Propietarios con estado civil
        "propietarios": data.get('propietarios', []),
        
        # Datos R2 - Físicos
        "zonas_fisicas": data.get('zonas_fisicas', []),
        "habitaciones": data.get('habitaciones', ''),
        "banos": data.get('banos', ''),
        "locales": data.get('locales', ''),
        "pisos": data.get('pisos', ''),
        "uso": data.get('uso', ''),
        
        # Estado
        "estado_visita": "pendiente",
        
        # Metadatos
        "creado_por": current_user.get('email'),
        "creado_por_nombre": current_user.get('full_name'),
        "created_at": ahora,
        "updated_at": ahora,
        
        # Historial
        "historial_cambios": [{
            "fecha": ahora,
            "usuario": current_user.get('email'),
            "rol": current_user['role'],
            "accion": "creacion",
            "campos_modificados": list(data.keys())
        }]
    }
    
    await db.predios_actualizacion.insert_one(predio_nuevo)
    
    return {
        "message": "Predio creado correctamente",
        "id": predio_id,
        "codigo_predial": codigo_predial
    }


@api_router.patch("/actualizacion/proyectos/{proyecto_id}/predios/{codigo_predial}")
async def actualizar_predio_proyecto(
    proyecto_id: str,
    codigo_predial: str,
    data: dict,
    current_user: dict = Depends(get_current_user)
):
    """Actualiza un predio del proyecto (trabajo de campo)
    
    FLUJO DE ACTUALIZACIÓN:
    1. Gestor visita el predio → completa formulario de visita → estado "visitado"
    2. Gestor propone cambios a datos prediales → va a "Gestión de Propuestas"
    3. Coordinador aprueba la propuesta → cambios se aplican → estado "actualizado"
    
    - Gestores SOLO pueden: marcar visita, agregar datos de visita, completar formulario
    - Cambios a datos prediales (dirección, áreas, propietarios, etc.) 
      requieren crear una PROPUESTA que el coordinador debe aprobar
    - Todo queda registrado en historial
    """
    if current_user['role'] not in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR, UserRole.GESTOR]:
        raise HTTPException(status_code=403, detail="No tiene permiso para actualizar predios")
    
    proyecto = await db.proyectos_actualizacion.find_one({"id": proyecto_id}, {"_id": 0})
    if not proyecto:
        raise HTTPException(status_code=404, detail="Proyecto no encontrado")
    
    # Buscar el predio por codigo_predial o numero_predial
    predio = await db.predios_actualizacion.find_one({
        "proyecto_id": proyecto_id,
        "$or": [
            {"codigo_predial": codigo_predial},
            {"numero_predial": codigo_predial}
        ]
    })
    
    if not predio:
        raise HTTPException(status_code=404, detail="Predio no encontrado")
    
    es_coordinador = current_user['role'] in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR]
    
    # Campos que gestores pueden modificar directamente (datos de visita)
    campos_visita = [
        'estado_visita', 'observaciones_campo', 'ubicacion_gps',
        'visitado_por', 'visitado_en', 'visitado_por_nombre',
        'visita', 'datos_notificacion', 'fotos',
        'sin_cambios'  # Marcar si el predio fue visitado sin modificaciones
    ]
    
    # Campos que requieren aprobación del coordinador (datos prediales)
    campos_prediales = [
        'direccion', 'destino_economico', 'area_terreno', 'area_construida',
        'matricula_inmobiliaria', 'avaluo_catastral', 'estrato', 'comuna',
        'propietarios', 'zonas_fisicas', 'zonas_terreno', 'construcciones',
        'actualizado_por', 'actualizado_en', 'actualizado_por_nombre',
        'informacion_construcciones', 'calificacion_construccion', 
        'resumen_areas', 'es_ph', 'datos_ph', 'datos_condominio',
        'avaluo', 'codigo_homologado', 'habitaciones', 'banos', 'locales', 'pisos', 'uso',
        'codigo_predial'
    ]
    
    # Verificar si el gestor está intentando modificar datos prediales
    if not es_coordinador:
        campos_prediales_modificados = [k for k in data.keys() if k in campos_prediales]
        
        # Gestores solo pueden marcar como 'visitado', no como 'actualizado'
        if data.get('estado_visita') == 'actualizado':
            raise HTTPException(
                status_code=403, 
                detail="Los gestores no pueden marcar como 'actualizado' directamente. Debe crear una propuesta de cambio que será revisada por el coordinador."
            )
        
        # Si intenta modificar campos prediales, debe crear propuesta
        if campos_prediales_modificados:
            raise HTTPException(
                status_code=403, 
                detail=f"Los cambios a datos prediales ({', '.join(campos_prediales_modificados)}) requieren crear una propuesta de cambio. El predio debe estar visitado y luego usar 'Proponer Cambios' para enviar una solicitud al coordinador."
            )
        
        # Solo permitir campos de visita para gestores
        update_data = {k: v for k, v in data.items() if k in campos_visita}
        accion = "visita_registrada"
        
        # Agregar información del gestor que visitó
        if data.get('estado_visita') == 'visitado':
            update_data['visitado_por'] = current_user.get('email')
            update_data['visitado_por_nombre'] = current_user.get('full_name')
            update_data['visitado_en'] = datetime.now(COLOMBIA_TZ).isoformat()
    else:
        # Coordinadores pueden modificar todo
        campos_permitidos = campos_visita + campos_prediales
        update_data = {k: v for k, v in data.items() if k in campos_permitidos}
        accion = "actualizacion_directa" if data.get('estado_visita') == 'actualizado' else "visita"
        
        # Si coordinador marca como actualizado, registrar quién aprobó
        if data.get('estado_visita') == 'actualizado':
            update_data['actualizado_por'] = current_user.get('email')
            update_data['actualizado_por_nombre'] = current_user.get('full_name')
            update_data['actualizado_en'] = datetime.now(COLOMBIA_TZ).isoformat()
    
    if not update_data:
        raise HTTPException(status_code=400, detail="No hay campos válidos para actualizar")
    
    update_data['updated_at'] = datetime.now(COLOMBIA_TZ)
    
    # Agregar al historial de cambios con detalle completo
    historial_entry = {
        "fecha": datetime.now(COLOMBIA_TZ).isoformat(),
        "usuario": current_user.get('email'),
        "usuario_nombre": current_user.get('full_name'),
        "rol": current_user['role'],
        "accion": accion,
        "campos_modificados": list(update_data.keys()),
        "detalle": f"{'Coordinador' if es_coordinador else 'Gestor'} {current_user.get('full_name')} - {accion}"
    }
    
    await db.predios_actualizacion.update_one(
        {"_id": predio["_id"]},
        {
            "$set": update_data,
            "$push": {"historial_cambios": historial_entry}
        }
    )
    
    return {
        "message": "Predio actualizado exitosamente",
        "codigo_predial": codigo_predial
    }


# ==================== PREDIOS SIN CAMBIOS - ACTUALIZACIÓN ====================

@api_router.get("/actualizacion/proyectos/{proyecto_id}/predios-sin-cambios")
async def get_predios_sin_cambios(
    proyecto_id: str,
    current_user: dict = Depends(get_current_user)
):
    """Obtiene los predios visitados marcados como 'sin cambios' que esperan aprobación del coordinador"""
    if current_user['role'] not in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR]:
        raise HTTPException(status_code=403, detail="Solo coordinadores pueden ver esta lista")
    
    proyecto = await db.proyectos_actualizacion.find_one({"id": proyecto_id}, {"_id": 0})
    if not proyecto:
        raise HTTPException(status_code=404, detail="Proyecto no encontrado")
    
    # Obtener predios visitados marcados como sin_cambios que NO están actualizados
    predios = await db.predios_actualizacion.find(
        {
            "proyecto_id": proyecto_id,
            "sin_cambios": True,
            "estado_visita": {"$in": ["visitado", "pendiente"]},  # No incluir los ya actualizados
        },
        {"_id": 0}
    ).sort("visitado_en", -1).to_list(10000)
    
    return {
        "predios": predios,
        "total": len(predios)
    }


@api_router.post("/actualizacion/proyectos/{proyecto_id}/predios/{codigo_predial}/aprobar-sin-cambios")
async def aprobar_predio_sin_cambios(
    proyecto_id: str,
    codigo_predial: str,
    data: dict,
    current_user: dict = Depends(get_current_user)
):
    """Aprueba un predio visitado sin cambios, marcándolo como actualizado"""
    if current_user['role'] not in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR]:
        raise HTTPException(status_code=403, detail="Solo coordinadores pueden aprobar")
    
    proyecto = await db.proyectos_actualizacion.find_one({"id": proyecto_id}, {"_id": 0})
    if not proyecto:
        raise HTTPException(status_code=404, detail="Proyecto no encontrado")
    
    # Buscar el predio
    predio = await db.predios_actualizacion.find_one({
        "proyecto_id": proyecto_id,
        "$or": [
            {"codigo_predial": codigo_predial},
            {"numero_predial": codigo_predial}
        ]
    })
    
    if not predio:
        raise HTTPException(status_code=404, detail="Predio no encontrado")
    
    # Agregar al historial
    historial_entry = {
        "fecha": datetime.now(COLOMBIA_TZ).isoformat(),
        "usuario": current_user.get('email'),
        "rol": current_user['role'],
        "accion": "aprobado_sin_cambios",
        "comentario": data.get('comentario', 'Aprobado sin cambios')
    }
    
    # Actualizar el predio a estado 'actualizado'
    await db.predios_actualizacion.update_one(
        {"_id": predio["_id"]},
        {
            "$set": {
                "estado_visita": "actualizado",
                "aprobado_sin_cambios": True,
                "aprobado_por": current_user.get('email'),
                "aprobado_en": datetime.now(COLOMBIA_TZ).isoformat(),
                "updated_at": datetime.now(COLOMBIA_TZ)
            },
            "$push": {"historial_cambios": historial_entry}
        }
    )
    
    return {
        "message": "Predio aprobado como actualizado (sin cambios)",
        "codigo_predial": codigo_predial
    }


@api_router.post("/actualizacion/proyectos/{proyecto_id}/predios-sin-cambios/aprobar-masivo")
async def aprobar_masivo_sin_cambios(
    proyecto_id: str,
    data: dict,
    current_user: dict = Depends(get_current_user)
):
    """Aprueba masivamente predios visitados sin cambios"""
    if current_user['role'] not in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR]:
        raise HTTPException(status_code=403, detail="Solo coordinadores pueden aprobar")
    
    codigos = data.get('codigos_prediales', [])
    if not codigos:
        raise HTTPException(status_code=400, detail="Debe proporcionar una lista de códigos prediales")
    
    proyecto = await db.proyectos_actualizacion.find_one({"id": proyecto_id}, {"_id": 0})
    if not proyecto:
        raise HTTPException(status_code=404, detail="Proyecto no encontrado")
    
    comentario = data.get('comentario', 'Aprobación masiva sin cambios')
    aprobados = 0
    
    for codigo in codigos:
        predio = await db.predios_actualizacion.find_one({
            "proyecto_id": proyecto_id,
            "$or": [
                {"codigo_predial": codigo},
                {"numero_predial": codigo}
            ]
        })
        
        if predio:
            historial_entry = {
                "fecha": datetime.now(COLOMBIA_TZ).isoformat(),
                "usuario": current_user.get('email'),
                "rol": current_user['role'],
                "accion": "aprobado_sin_cambios_masivo",
                "comentario": comentario
            }
            
            await db.predios_actualizacion.update_one(
                {"_id": predio["_id"]},
                {
                    "$set": {
                        "estado_visita": "actualizado",
                        "aprobado_sin_cambios": True,
                        "aprobado_por": current_user.get('email'),
                        "aprobado_en": datetime.now(COLOMBIA_TZ).isoformat(),
                        "updated_at": datetime.now(COLOMBIA_TZ)
                    },
                    "$push": {"historial_cambios": historial_entry}
                }
            )
            aprobados += 1
    
    return {
        "message": f"{aprobados} predios aprobados como actualizados (sin cambios)",
        "aprobados": aprobados
    }


# ==================== VISITA DE CAMPO ====================

@api_router.get("/actualizacion/proyectos/{proyecto_id}/predios/{codigo_predial}/visita")
async def obtener_visita_predio(
    proyecto_id: str,
    codigo_predial: str,
    current_user: dict = Depends(get_current_user)
):
    """Obtiene los datos de la visita de campo de un predio"""
    predio = await db.predios_actualizacion.find_one({
        "proyecto_id": proyecto_id,
        "$or": [
            {"codigo_predial": codigo_predial},
            {"numero_predial": codigo_predial},
            {"codigo_predial_nacional": codigo_predial}
        ]
    }, {"_id": 0})
    
    if not predio:
        raise HTTPException(status_code=404, detail="Predio no encontrado")
    
    # Extraer datos de visita del formato_visita o campos separados
    visita = predio.get('formato_visita', {})
    
    # Si hay datos de visita en otros campos, incluirlos
    if predio.get('linderos'):
        visita['linderos'] = predio.get('linderos')
    if predio.get('coordenadas_visita'):
        visita['coordenadas'] = predio.get('coordenadas_visita')
    if predio.get('propietarios_visita'):
        visita['propietarios_visita'] = predio.get('propietarios_visita')
    if predio.get('construcciones_visita'):
        visita['construcciones_visita'] = predio.get('construcciones_visita')
    if predio.get('fotos_visita'):
        visita['fotos'] = predio.get('fotos_visita')
    if predio.get('firma_visita'):
        visita['firma_base64'] = predio.get('firma_visita')
    if predio.get('observaciones_generales'):
        visita['observaciones'] = predio.get('observaciones_generales')
    if predio.get('sin_cambios'):
        visita['sin_cambios'] = predio.get('sin_cambios')
    
    return {
        "visita": visita if visita else None,
        "estado_visita": predio.get('estado_visita', 'pendiente')
    }


@api_router.post("/actualizacion/proyectos/{proyecto_id}/predios/{codigo_predial}/visita")
async def guardar_visita_predio(
    proyecto_id: str,
    codigo_predial: str,
    visita_data: dict,
    current_user: dict = Depends(get_current_user)
):
    """Guarda los datos de la visita de campo de un predio"""
    if current_user['role'] not in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR, UserRole.GESTOR, UserRole.GESTOR_AUXILIAR]:
        raise HTTPException(status_code=403, detail="No tiene permisos para registrar visitas")
    
    predio = await db.predios_actualizacion.find_one({
        "proyecto_id": proyecto_id,
        "$or": [
            {"codigo_predial": codigo_predial},
            {"numero_predial": codigo_predial},
            {"codigo_predial_nacional": codigo_predial}
        ]
    })

    if not predio:
        raise HTTPException(status_code=404, detail="Predio no encontrado")

    # Si el predio ya tiene visita firmada, preservar las firmas existentes si no se envían nuevas
    formato_existente = predio.get('formato_visita', {}) or {}
    if not visita_data.get('firma_visitado_base64') and formato_existente.get('firma_visitado_base64'):
        visita_data['firma_visitado_base64'] = formato_existente['firma_visitado_base64']
    if not visita_data.get('firma_reconocedor_base64') and formato_existente.get('firma_reconocedor_base64'):
        visita_data['firma_reconocedor_base64'] = formato_existente['firma_reconocedor_base64']
    if not visita_data.get('nombre_visitado') and formato_existente.get('nombre_visitado'):
        visita_data['nombre_visitado'] = formato_existente['nombre_visitado']
    if not visita_data.get('nombre_reconocedor') and formato_existente.get('nombre_reconocedor'):
        visita_data['nombre_reconocedor'] = formato_existente['nombre_reconocedor']

    # VALIDACIÓN OBLIGATORIA: Firmas requeridas (ya sea nuevas o preservadas)
    if not visita_data.get('firma_visitado_base64'):
        raise HTTPException(status_code=400, detail="La firma del visitado es obligatoria")
    if not visita_data.get('firma_reconocedor_base64'):
        raise HTTPException(status_code=400, detail="La firma del reconocedor es obligatoria")
    
    ahora = datetime.now(COLOMBIA_TZ)
    
    # Determinar estado basado en si tiene ambas firmas
    tiene_firma_visitado = bool(visita_data.get('firma_visitado_base64'))
    tiene_firma_reconocedor = bool(visita_data.get('firma_reconocedor_base64'))
    
    if tiene_firma_visitado and tiene_firma_reconocedor:
        estado_visita = "visitado_firmado"  # Bloqueado para edición
    else:
        estado_visita = "visitado"
    
    # Preparar datos de actualización
    # NOTA: No duplicar fotos/firmas fuera de formato_visita para evitar
    # inflar el documento y superar el límite de 16 MB de MongoDB.
    # Solo se extraen campos ligeros (texto) útiles para consultas rápidas.
    update_data = {
        "formato_visita": visita_data,
        "estado_visita": estado_visita,
        "visitado_por": current_user.get('email'),
        "visitado_por_nombre": current_user.get('full_name'),
        "visitado_en": ahora.isoformat(),
        "updated_at": ahora,
        # Solo campos de texto ligeros para consultas sin acceder a formato_visita
        "linderos": visita_data.get('linderos'),
        "coordenadas_visita": visita_data.get('coordenadas'),
        "nombre_visitado": visita_data.get('nombre_visitado'),
        "nombre_reconocedor": visita_data.get('nombre_reconocedor') or current_user.get('full_name'),
        "observaciones_generales": visita_data.get('observaciones'),
        "sin_cambios": visita_data.get('sin_cambios', False),
        "fecha_visita": visita_data.get('fecha_visita'),
        "hora_visita": visita_data.get('hora_visita'),
        "persona_atiende": visita_data.get('persona_atiende'),
        "relacion_predio": visita_data.get('relacion_predio'),
        "acceso_predio": visita_data.get('acceso_predio')
    }
    
    # Registrar en historial
    historial_entry = {
        "fecha": ahora.isoformat(),
        "usuario": current_user.get('full_name') or current_user.get('email'),  # Mostrar nombre, no email
        "usuario_email": current_user.get('email'),  # Mantener email como referencia
        "rol": current_user['role'],
        "accion": "visita_registrada" if estado_visita == "visitado" else "visita_firmada",
        "comentario": f"Visita de campo {'firmada y bloqueada' if estado_visita == 'visitado_firmado' else 'registrada'}. {'Sin cambios detectados.' if visita_data.get('sin_cambios') else 'Cambios por verificar.'}"
    }
    
    try:
        await db.predios_actualizacion.update_one(
            {"_id": predio["_id"]},
            {
                "$set": update_data,
                "$push": {"historial_cambios": historial_entry}
            }
        )
    except Exception as e:
        error_msg = str(e).lower()
        if 'too large' in error_msg or 'bson' in error_msg or 'size' in error_msg:
            logger.error(f"[Visita] Documento demasiado grande para {codigo_predial}: {e}")
            raise HTTPException(
                status_code=413,
                detail="Los datos de la visita son demasiado grandes. Reduzca la cantidad o calidad de las fotos e intente de nuevo."
            )
        logger.error(f"[Visita] Error MongoDB al guardar visita {codigo_predial}: {e}")
        raise HTTPException(status_code=500, detail=f"Error al guardar en base de datos: {str(e)}")

    return {
        "message": "Visita guardada correctamente" + (" y firmada (bloqueada para edición)" if estado_visita == "visitado_firmado" else ""),
        "estado_visita": estado_visita,
        "sin_cambios": visita_data.get('sin_cambios', False),
        "firmado": estado_visita == "visitado_firmado"
    }


@api_router.delete("/actualizacion/proyectos/{proyecto_id}/predios/{codigo_predial}/visita")
async def revertir_visita_firmada(
    proyecto_id: str,
    codigo_predial: str,
    data: dict = None,
    current_user: dict = Depends(get_current_user)
):
    """
    Revierte/elimina una visita firmada para que el gestor pueda volver a realizarla.
    SOLO disponible para COORDINADORES y ADMINISTRADORES.
    """
    # Solo coordinadores y administradores pueden revertir
    if current_user['role'] not in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR]:
        raise HTTPException(
            status_code=403, 
            detail="Solo coordinadores y administradores pueden revertir visitas firmadas"
        )
    
    # Buscar el predio
    predio = await db.predios_actualizacion.find_one({
        "proyecto_id": proyecto_id,
        "$or": [
            {"codigo_predial": codigo_predial},
            {"numero_predial": codigo_predial}
        ]
    })
    
    if not predio:
        raise HTTPException(status_code=404, detail="Predio no encontrado")
    
    estado_actual = predio.get('estado_visita', 'pendiente')
    
    # Verificar que el predio tenga una visita firmada
    if estado_actual not in ['visitado', 'visitado_firmado']:
        raise HTTPException(
            status_code=400, 
            detail=f"El predio no tiene visita para revertir. Estado actual: {estado_actual}"
        )
    
    motivo = data.get('motivo', 'Sin motivo especificado') if data else 'Sin motivo especificado'
    ahora = datetime.now(COLOMBIA_TZ).isoformat()
    
    # Guardar copia de la visita anterior en historial antes de eliminarla
    visita_anterior = predio.get('formato_visita', {})
    
    # Revertir el predio a estado pendiente y limpiar datos de visita
    historial_entry = {
        "accion": "visita_revertida",
        "fecha": ahora,
        "usuario": current_user['full_name'],
        "usuario_id": current_user['id'],
        "rol": current_user['role'],
        "motivo": motivo,
        "estado_anterior": estado_actual,
        "visita_eliminada": {
            "fecha_visita": visita_anterior.get('fecha_visita'),
            "visitado_por": predio.get('visitado_por'),
            "firma_visitante": "Sí" if visita_anterior.get('firma_visitante') else "No",
            "firma_propietario": "Sí" if visita_anterior.get('firma_propietario') else "No"
        }
    }
    
    # Actualizar el predio
    await db.predios_actualizacion.update_one(
        {"_id": predio["_id"]},
        {
            "$set": {
                "estado_visita": "pendiente",
                "formato_visita": None,  # Limpiar el formato de visita
                "visitado_por": None,
                "visitado_en": None,
                "ubicacion_gps": None,
                "updated_at": ahora,
                "visita_revertida_en": ahora,
                "visita_revertida_por": current_user['full_name'],
                "visita_revertida_por_id": current_user['id'],
                "motivo_reversion": motivo
            },
            "$push": {
                "historial": historial_entry
            }
        }
    )
    
    logger.info(f"Visita revertida por {current_user['email']}: predio {codigo_predial}, motivo: {motivo}")
    
    return {
        "message": "Visita revertida exitosamente. El gestor puede volver a realizar la visita.",
        "codigo_predial": codigo_predial,
        "estado_anterior": estado_actual,
        "estado_nuevo": "pendiente",
        "revertido_por": current_user['full_name'],
        "motivo": motivo
    }


@api_router.patch("/actualizacion/proyectos/{proyecto_id}/predios/{codigo_predial}/estado")
async def actualizar_estado_predio(
    proyecto_id: str,
    codigo_predial: str,
    estado_data: dict,
    current_user: dict = Depends(get_current_user)
):
    """Actualiza solo el estado de visita de un predio (pendiente/visitado/actualizado)"""
    if current_user['role'] not in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR, UserRole.GESTOR, UserRole.GESTOR_AUXILIAR]:
        raise HTTPException(status_code=403, detail="No tiene permisos para actualizar estado de predios")
    
    nuevo_estado = estado_data.get('estado_visita')
    if nuevo_estado not in ['pendiente', 'visitado', 'actualizado']:
        raise HTTPException(status_code=400, detail="Estado inválido. Debe ser: pendiente, visitado o actualizado")
    
    # Decodificar el código predial
    from urllib.parse import unquote
    codigo_predial = unquote(codigo_predial)
    
    predio = await db.predios_actualizacion.find_one({
        "proyecto_id": proyecto_id,
        "$or": [
            {"codigo_predial": codigo_predial},
            {"numero_predial": codigo_predial},
            {"codigo_predial_nacional": codigo_predial}
        ]
    })
    
    if not predio:
        raise HTTPException(status_code=404, detail="Predio no encontrado")
    
    ahora = datetime.now(COLOMBIA_TZ)
    estado_anterior = predio.get('estado_visita', 'pendiente')
    
    # Preparar datos de actualización
    update_data = {
        "estado_visita": nuevo_estado,
        "updated_at": ahora
    }
    
    # Registrar quién hizo el cambio
    if nuevo_estado == 'visitado':
        update_data["visitado_por"] = current_user.get('email')
        update_data["visitado_en"] = ahora.isoformat()
    elif nuevo_estado == 'actualizado':
        update_data["actualizado_por"] = current_user.get('email')
        update_data["actualizado_en"] = ahora.isoformat()
    
    # Registrar en historial
    historial_entry = {
        "fecha": ahora.isoformat(),
        "usuario": current_user.get('email'),
        "rol": current_user['role'],
        "accion": "cambio_estado",
        "comentario": f"Estado cambiado de '{estado_anterior}' a '{nuevo_estado}'"
    }
    
    await db.predios_actualizacion.update_one(
        {"_id": predio["_id"]},
        {
            "$set": update_data,
            "$push": {"historial_cambios": historial_entry}
        }
    )
    
    return {
        "message": f"Estado actualizado a '{nuevo_estado}'",
        "estado_anterior": estado_anterior,
        "estado_nuevo": nuevo_estado
    }


@api_router.get("/actualizacion/proyectos/{proyecto_id}/construcciones")
async def obtener_construcciones_proyecto(
    proyecto_id: str,
    codigo: str = None,
    current_user: dict = Depends(get_current_user)
):
    """Obtiene las construcciones del proyecto, opcionalmente filtradas por código de terreno"""
    proyecto = await db.proyectos_actualizacion.find_one({"id": proyecto_id}, {"_id": 0})
    if not proyecto:
        raise HTTPException(status_code=404, detail="Proyecto no encontrado")
    
    query = {"proyecto_id": proyecto_id, "tipo": "construccion"}
    
    if codigo:
        # Buscar construcciones que coincidan con el código del terreno (primeros 21-22 dígitos)
        codigo_base = codigo[:21] if len(codigo) >= 21 else codigo
        query["properties.terreno_codigo"] = {"$regex": f"^{codigo_base}"}
    
    construcciones = await db.geometrias_actualizacion.find(query, {"_id": 0}).to_list(length=100)
    
    # Si no encuentra por terreno_codigo, buscar por codigo directamente
    if not construcciones and codigo:
        query["properties.codigo"] = {"$regex": f"^{codigo[:17]}"}  # Buscar por manzana
        del query["properties.terreno_codigo"]
        construcciones = await db.geometrias_actualizacion.find(query, {"_id": 0}).to_list(length=100)
    
    return {
        "construcciones": construcciones,
        "total": len(construcciones)
    }


# ==================== EXPORTACIÓN EXCEL R1/R2 - ACTUALIZACIÓN ====================

@api_router.get("/actualizacion/proyectos/{proyecto_id}/exportar-excel")
async def exportar_actualizacion_excel(
    proyecto_id: str,
    solo_actualizados: bool = False,
    current_user: dict = Depends(get_current_user)
):
    """
    Exporta los predios del proyecto de actualización a Excel en formato R1/R2.
    
    IMPORTANTE: Los predios bloqueados por proceso legal SÍ se incluyen en la exportación.
    El bloqueo solo impide modificaciones, no afecta la exportación de datos.
    
    CRITERIOS DE INCLUSIÓN:
    - solo_actualizados=false: Todos los predios del proyecto (R1/R2 cargados + nuevos aprobados)
    - solo_actualizados=true: Solo predios con visitas firmadas, actualizados, o con cambios aprobados
    
    EXCLUSIONES:
    - Predios con cancelación aprobada
    """
    from openpyxl import Workbook
    from openpyxl.styles import Font, PatternFill, Border, Side, Alignment
    from io import BytesIO
    from fastapi.responses import StreamingResponse
    
    if current_user['role'] not in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR, UserRole.GESTOR]:
        raise HTTPException(status_code=403, detail="No tiene permiso para exportar")
    
    proyecto = await db.proyectos_actualizacion.find_one({"id": proyecto_id})
    if not proyecto:
        raise HTTPException(status_code=404, detail="Proyecto no encontrado")
    
    municipio = proyecto.get('municipio', '')
    
    # ========== PASO 1: Obtener códigos de predios con geometría GDB (para marcar) ==========
    # Buscar en geometrias_actualizacion (GDB cargado al proyecto)
    geometrias_proyecto = await db.geometrias_actualizacion.find(
        {"proyecto_id": proyecto_id, "type": "Feature"},
        {"properties.codigo": 1, "_id": 0}
    ).to_list(100000)
    
    codigos_con_gdb = set()
    for g in geometrias_proyecto:
        codigo = g.get('properties', {}).get('codigo')
        if codigo:
            # El código en GDB suele ser de 21 dígitos, expandir a 30 para terreno
            if len(codigo) == 21:
                codigos_con_gdb.add(codigo + "000000000")  # Terreno
            else:
                codigos_con_gdb.add(codigo)
    
    # También buscar en gdb_geometrias (GDB general del municipio)
    if municipio:
        geometrias_municipio = await db.gdb_geometrias.find(
            {"municipio": municipio},
            {"codigo": 1, "_id": 0}
        ).to_list(100000)
        
        for g in geometrias_municipio:
            codigo = g.get('codigo')
            if codigo:
                if len(codigo) == 21:
                    codigos_con_gdb.add(codigo + "000000000")
                else:
                    codigos_con_gdb.add(codigo)
    
    logger.info(f"[Export R1/R2] Encontrados {len(codigos_con_gdb)} códigos con geometría GDB")
    
    # ========== PASO 2: Obtener predios nuevos y mejoras aprobadas ==========
    propuestas_aprobadas = await db.propuestas_cambio_actualizacion.find(
        {
            "proyecto_id": proyecto_id,
            "estado": "aprobada",
            "tipo": {"$in": ["predio_nuevo", "cambio"]}
        },
        {"_id": 0}
    ).to_list(10000)
    
    codigos_nuevos_aprobados = set()
    codigos_cambios_aprobados = set()
    datos_propuestas = {}
    
    for prop in propuestas_aprobadas:
        codigo = prop.get('codigo_predial') or prop.get('datos_propuestos', {}).get('codigo_predial_nacional')
        if codigo:
            if prop.get('tipo') == 'predio_nuevo':
                codigos_nuevos_aprobados.add(codigo)
                # Guardar datos de la propuesta para usar después
                datos_propuestas[codigo] = {
                    'tipo_cambio': 'mejora_nueva' if prop.get('es_mejora') else 'predio_nuevo',
                    'datos': prop.get('datos_propuestos', {})
                }
            else:
                codigos_cambios_aprobados.add(codigo)
                datos_propuestas[codigo] = {
                    'tipo_cambio': 'actualizado',
                    'datos': prop.get('datos_propuestos', {})
                }
    
    logger.info(f"[Export R1/R2] Predios nuevos aprobados: {len(codigos_nuevos_aprobados)}, Cambios aprobados: {len(codigos_cambios_aprobados)}")
    
    # ========== PASO 3: Obtener cancelaciones aprobadas ==========
    cancelaciones = await db.propuestas_cambio_actualizacion.find(
        {
            "proyecto_id": proyecto_id,
            "estado": "aprobada",
            "tipo": "cancelacion"
        },
        {"codigo_predial": 1, "_id": 0}
    ).to_list(10000)
    
    codigos_cancelados = set(c.get('codigo_predial') for c in cancelaciones if c.get('codigo_predial'))
    logger.info(f"[Export R1/R2] Cancelaciones aprobadas: {len(codigos_cancelados)}")
    
    # ========== PASO 4: Construir lista final de códigos a exportar ==========
    # Ya no filtramos por códigos específicos, obtenemos todos los predios del proyecto
    
    logger.info(f"[Export R1/R2] Códigos GDB: {len(codigos_con_gdb)}, Nuevos aprobados: {len(codigos_nuevos_aprobados)}, Cambios aprobados: {len(codigos_cambios_aprobados)}")
    
    # ========== PASO 5: Obtener TODOS los predios del proyecto ==========
    predios = []
    
    # Consulta base: todos los predios del proyecto
    query = {"proyecto_id": proyecto_id}
    
    # Si solo_actualizados, filtrar por estados específicos
    if solo_actualizados:
        query["$or"] = [
            {"estado_visita": {"$in": ["visitado_firmado", "actualizado"]}},
            {"codigo_predial": {"$in": list(codigos_nuevos_aprobados | codigos_cambios_aprobados)}},
            {"codigo_predial_nacional": {"$in": list(codigos_nuevos_aprobados | codigos_cambios_aprobados)}},
            {"numero_predial": {"$in": list(codigos_nuevos_aprobados | codigos_cambios_aprobados)}}
        ]
    
    # Obtener predios
    predios_actualizacion = await db.predios_actualizacion.find(
        query,
        {"_id": 0}
    ).to_list(100000)
    
    # Excluir cancelados
    for p in predios_actualizacion:
        codigo = p.get('codigo_predial') or p.get('codigo_predial_nacional') or p.get('numero_predial')
        
        # Saltar si está cancelado
        if codigo in codigos_cancelados:
            continue
        
        # Determinar tipo de cambio
        if codigo in codigos_nuevos_aprobados:
            p['tipo_cambio'] = datos_propuestas.get(codigo, {}).get('tipo_cambio', 'predio_nuevo')
        elif codigo in codigos_cambios_aprobados:
            p['tipo_cambio'] = 'actualizado'
        elif codigo in codigos_con_gdb:
            p['tipo_cambio'] = 'con_geometria'
        else:
            p['tipo_cambio'] = 'original'
        
        predios.append(p)
    
    # Agregar predios nuevos aprobados que no estén en predios_actualizacion
    codigos_encontrados = set(
        p.get('codigo_predial') or p.get('codigo_predial_nacional') or p.get('numero_predial') 
        for p in predios
    )
    
    for codigo in codigos_nuevos_aprobados - codigos_encontrados:
        if codigo in datos_propuestas and codigo not in codigos_cancelados:
            datos = datos_propuestas[codigo].get('datos', {})
            datos['tipo_cambio'] = datos_propuestas[codigo].get('tipo_cambio', 'predio_nuevo')
            datos['codigo_predial'] = codigo
            datos['codigo_predial_nacional'] = codigo
            predios.append(datos)
    
    if not predios:
        raise HTTPException(status_code=404, detail="No hay predios para exportar con los criterios especificados")
    
    logger.info(f"[Export R1/R2] Exportando {len(predios)} predios")
    
    # Ordenar predios por código predial (ubicación geográfica)
    predios.sort(key=lambda p: p.get('codigo_predial') or p.get('codigo_predial_nacional') or p.get('numero_predial') or '')
    
    # ========== PASO 6: Crear Excel ==========
    wb = Workbook()
    
    # Estilos
    header_font = Font(bold=True, color="FFFFFF")
    header_fill = PatternFill(start_color="047857", end_color="047857", fill_type="solid")
    nuevo_fill = PatternFill(start_color="DBEAFE", end_color="DBEAFE", fill_type="solid")  # Azul claro
    mejora_fill = PatternFill(start_color="E0E7FF", end_color="E0E7FF", fill_type="solid")  # Indigo claro
    actualizado_fill = PatternFill(start_color="FEF3C7", end_color="FEF3C7", fill_type="solid")  # Amarillo
    firmado_fill = PatternFill(start_color="D1FAE5", end_color="D1FAE5", fill_type="solid")  # Verde claro
    thin_border = Border(
        left=Side(style='thin'),
        right=Side(style='thin'),
        top=Side(style='thin'),
        bottom=Side(style='thin')
    )
    
    # Función para formatear número de documento con padding de 0s (12 dígitos)
    def formatear_documento(numero):
        if not numero:
            return ''
        solo_numeros = ''.join(filter(str.isdigit, str(numero)))
        return solo_numeros.zfill(12) if solo_numeros else ''
    
    # Función para parsear nombre completo en partes
    def parsear_nombre_propietario(nombre_completo):
        if not nombre_completo:
            return {'primer_apellido': '', 'segundo_apellido': '', 'primer_nombre': '', 'segundo_nombre': ''}
        partes = nombre_completo.strip().split()
        if len(partes) >= 4:
            return {'primer_apellido': partes[0], 'segundo_apellido': partes[1], 'primer_nombre': partes[2], 'segundo_nombre': ' '.join(partes[3:])}
        elif len(partes) == 3:
            return {'primer_apellido': partes[0], 'segundo_apellido': partes[1], 'primer_nombre': partes[2], 'segundo_nombre': ''}
        elif len(partes) == 2:
            return {'primer_apellido': partes[0], 'segundo_apellido': '', 'primer_nombre': partes[1], 'segundo_nombre': ''}
        else:
            return {'primer_apellido': partes[0] if partes else '', 'segundo_apellido': '', 'primer_nombre': '', 'segundo_nombre': ''}
    
    # Función para obtener campos de nombre
    def obtener_campos_nombre(prop):
        primer_ap = prop.get('primer_apellido', '').strip()
        primer_nom = prop.get('primer_nombre', '').strip()
        if not primer_ap and not primer_nom:
            nombre_completo = prop.get('nombre_propietario', '') or prop.get('nombre', '')
            return parsear_nombre_propietario(nombre_completo)
        return {
            'primer_apellido': primer_ap,
            'segundo_apellido': prop.get('segundo_apellido', '').strip(),
            'primer_nombre': primer_nom,
            'segundo_nombre': prop.get('segundo_nombre', '').strip()
        }
    
    # Función para generar nombre completo
    def generar_nombre_completo(prop):
        campos = obtener_campos_nombre(prop)
        partes = [campos.get('primer_apellido', ''), campos.get('segundo_apellido', ''), 
                  campos.get('primer_nombre', ''), campos.get('segundo_nombre', '')]
        nombre = ' '.join(p for p in partes if p and p.strip())
        return nombre if nombre else prop.get('nombre_propietario', '')
    
    # === HOJA REGISTRO_R1 (Propietarios) ===
    ws_r1 = wb.active
    ws_r1.title = "REGISTRO_R1"
    
    # Headers R1 - Formato igual a Conservación + campos extra de Actualización
    headers_r1 = [
        "DEPARTAMENTO", "MUNICIPIO", "NUMERO_DEL_PREDIO", "CODIGO_PREDIAL_NACIONAL", 
        "CODIGO_HOMOLOGADO", "TIPO_DE_REGISTRO", "NUMERO_DE_ORDEN", "TOTAL_REGISTROS",
        "PRIMER_APELLIDO", "SEGUNDO_APELLIDO", "PRIMER_NOMBRE", "SEGUNDO_NOMBRE",
        "NOMBRE", "ESTADO", "TIPO_DOCUMENTO", "NUMERO_DOCUMENTO", "DIRECCION",
        "COMUNA", "DESTINO_ECONOMICO", "AREA_TERRENO", "AREA_CONSTRUIDA", "AVALUO",
        "VIGENCIA", "ESTADO_VISITA", "TIPO_CAMBIO", "ACTUALIZADO_POR", "FECHA_ACTUALIZACION"
    ]
    
    for col, header in enumerate(headers_r1, 1):
        cell = ws_r1.cell(row=1, column=col, value=header)
        cell.font = header_font
        cell.fill = header_fill
        cell.border = thin_border
        cell.alignment = Alignment(horizontal='center')
    
    row = 2
    for predio in predios:
        # Obtener código del predio para buscar propuestas aprobadas
        codigo_predio = predio.get('codigo_predial') or predio.get('codigo_predial_nacional') or predio.get('numero_predial')
        
        # ========== FUSIONAR CON DATOS DE PROPUESTA APROBADA ==========
        # Si hay una propuesta aprobada para este predio, usar sus datos
        datos_aprobados = {}
        if codigo_predio and codigo_predio in datos_propuestas:
            datos_aprobados = datos_propuestas[codigo_predio].get('datos', {})
        
        # Función helper para obtener dato priorizando propuesta aprobada
        def get_dato(campo, default=''):
            # Primero buscar en datos aprobados, luego en predio original
            if datos_aprobados:
                # Buscar en datos_aprobados con variantes del nombre del campo
                valor = datos_aprobados.get(campo)
                if valor is not None and valor != '':
                    return valor
                # Buscar en r1 anidado si existe
                r1_data = datos_aprobados.get('r1', {})
                if isinstance(r1_data, dict):
                    valor = r1_data.get(campo)
                    if valor is not None and valor != '':
                        return valor
            return predio.get(campo, default)
        
        # Obtener propietarios - priorizar propuesta aprobada > visita > original
        propietarios = []
        estado_visita = predio.get('estado_visita', 'pendiente')
        visita_data = predio.get('visita_data', {})
        
        # 1. Prioridad: Propietarios de propuesta aprobada
        if datos_aprobados:
            propietarios_propuesta = datos_aprobados.get('propietarios', [])
            # También buscar en r1.propietarios si existe
            if not propietarios_propuesta:
                r1_data = datos_aprobados.get('r1', {})
                if isinstance(r1_data, dict):
                    propietarios_propuesta = r1_data.get('propietarios', [])
            if propietarios_propuesta:
                propietarios = propietarios_propuesta
        
        # 2. Si no hay de propuesta, usar visita
        if not propietarios and estado_visita in ['visitado_firmado', 'actualizado'] and visita_data:
            propietarios_visita = visita_data.get('propietarios', [])
            if propietarios_visita:
                propietarios = propietarios_visita
        
        # 3. Si no hay de visita, usar originales del predio
        if not propietarios:
            propietarios = predio.get('propietarios', [])
        
        # 4. Fallback: crear un propietario con datos del predio/propuesta
        if not propietarios:
            propietarios = [{
                'nombre_propietario': get_dato('nombre_propietario', get_dato('nombre', '')),
                'tipo_documento': get_dato('tipo_documento', ''),
                'numero_documento': get_dato('numero_documento', ''),
                'estado': get_dato('estado', get_dato('estado_civil', ''))
            }]
        
        total_props = len(propietarios)
        tipo_cambio = predio.get('tipo_cambio', 'original')
        
        # Seleccionar color según tipo
        if tipo_cambio == 'predio_nuevo':
            fill = nuevo_fill
        elif tipo_cambio == 'mejora_nueva':
            fill = mejora_fill
        elif tipo_cambio == 'actualizado' or estado_visita == 'actualizado':
            fill = actualizado_fill
        elif estado_visita == 'visitado_firmado':
            fill = firmado_fill
        else:
            fill = None
        
        # Obtener datos del predio fusionando con propuesta aprobada
        codigo_homologado = get_dato('codigo_homologado', '')
        matricula = get_dato('matricula_inmobiliaria', get_dato('matricula', ''))
        direccion = get_dato('direccion', '')
        comuna = get_dato('comuna', '')
        destino_economico = get_dato('destino_economico', '')
        area_terreno = get_dato('area_terreno', 0)
        area_construida = get_dato('area_construida', 0)
        avaluo = get_dato('avaluo', get_dato('avaluo_catastral', 0))
        
        for idx, prop in enumerate(propietarios, 1):
            # Obtener campos de nombre parseados
            campos_nombre = obtener_campos_nombre(prop)
            
            ws_r1.cell(row=row, column=1, value=predio.get('departamento', proyecto.get('departamento', 'NORTE DE SANTANDER')))
            ws_r1.cell(row=row, column=2, value=predio.get('municipio', proyecto.get('municipio', '')))
            ws_r1.cell(row=row, column=3, value=predio.get('numero_predio', predio.get('numero_predial', '')))
            ws_r1.cell(row=row, column=4, value=predio.get('codigo_predial_nacional', predio.get('codigo_predial', predio.get('numero_predial', ''))))
            ws_r1.cell(row=row, column=5, value=codigo_homologado)
            ws_r1.cell(row=row, column=6, value='1')
            ws_r1.cell(row=row, column=7, value=str(idx).zfill(2))
            ws_r1.cell(row=row, column=8, value=str(total_props).zfill(2))
            # Campos de nombre separados
            ws_r1.cell(row=row, column=9, value=campos_nombre.get('primer_apellido', ''))
            ws_r1.cell(row=row, column=10, value=campos_nombre.get('segundo_apellido', ''))
            ws_r1.cell(row=row, column=11, value=campos_nombre.get('primer_nombre', ''))
            ws_r1.cell(row=row, column=12, value=campos_nombre.get('segundo_nombre', ''))
            ws_r1.cell(row=row, column=13, value=generar_nombre_completo(prop))
            # Estado civil: priorizar 'estado_civil' sobre 'estado', validar valor real
            _ec2 = (prop.get('estado_civil') or prop.get('estado') or '').strip().upper()
            if _ec2 not in ('S', 'C', 'V', 'U', 'SOLTERO', 'CASADO', 'VIUDO', 'UNION', 'SOLTERO/A', 'CASADO/A', 'VIUDO/A', 'UNION LIBRE'):
                _ec2 = ''
            ws_r1.cell(row=row, column=14, value=_ec2)
            ws_r1.cell(row=row, column=15, value=prop.get('tipo_documento', ''))
            ws_r1.cell(row=row, column=16, value=formatear_documento(prop.get('numero_documento', '')))
            ws_r1.cell(row=row, column=17, value=direccion)
            ws_r1.cell(row=row, column=18, value=comuna)
            ws_r1.cell(row=row, column=19, value=destino_economico)
            ws_r1.cell(row=row, column=20, value=area_terreno)
            ws_r1.cell(row=row, column=21, value=area_construida)
            ws_r1.cell(row=row, column=22, value=avaluo)
            ws_r1.cell(row=row, column=23, value=predio.get('vigencia', datetime.now().year))
            ws_r1.cell(row=row, column=24, value=estado_visita)
            ws_r1.cell(row=row, column=25, value=tipo_cambio.upper())
            ws_r1.cell(row=row, column=26, value=predio.get('actualizado_por_nombre', predio.get('visitado_por_nombre', predio.get('actualizado_por', predio.get('visitado_por', '')))))
            ws_r1.cell(row=row, column=27, value=predio.get('actualizado_en', predio.get('visitado_en', '')))
            
            # Aplicar color
            if fill:
                for c in range(1, 28):
                    ws_r1.cell(row=row, column=c).fill = fill
            
            row += 1
    
    # === HOJA REGISTRO_R2 (Físico - Formato igual a Conservación) ===
    ws_r2 = wb.create_sheet(title="REGISTRO_R2")
    
    # Headers R2 - Formato original con zonas y construcciones en columnas horizontales
    headers_r2 = [
        "DEPARTAMENTO", "MUNICIPIO", "NUMERO_DEL_PREDIO", "CODIGO_PREDIAL_NACIONAL",
        "TIPO_DE_REGISTRO", "NUMERO_DE_ORDEN", "TOTAL_REGISTROS", "MATRICULA_INMOBILIARIA",
        # Zona 1
        "ZONA_FISICA_1", "ZONA_ECONOMICA_1", "AREA_TERRENO_1",
        # Zona 2
        "ZONA_FISICA_2", "ZONA_ECONOMICA_2", "AREA_TERRENO_2",
        # Construcción 1
        "HABITACIONES_1", "BANOS_1", "LOCALES_1", "PISOS_1", "TIPIFICACION_1", "USO_1", "PUNTAJE_1", "AREA_CONSTRUIDA_1",
        # Construcción 2
        "HABITACIONES_2", "BANOS_2", "LOCALES_2", "PISOS_2", "TIPIFICACION_2", "USO_2", "PUNTAJE_2", "AREA_CONSTRUIDA_2",
        # Construcción 3
        "HABITACIONES_3", "BANOS_3", "LOCALES_3", "PISOS_3", "TIPIFICACION_3", "USO_3", "PUNTAJE_3", "AREA_CONSTRUIDA_3",
        "VIGENCIA", "ESTADO_VISITA", "TIPO_CAMBIO"
    ]
    
    for col, header in enumerate(headers_r2, 1):
        cell = ws_r2.cell(row=1, column=col, value=header)
        cell.font = header_font
        cell.fill = header_fill
        cell.border = thin_border
        cell.alignment = Alignment(horizontal='center')
    
    row = 2
    for predio in predios:
        tipo_cambio = predio.get('tipo_cambio', 'original')
        estado_visita = predio.get('estado_visita', 'pendiente')
        
        # Obtener código del predio para buscar propuestas aprobadas
        codigo_predio = predio.get('codigo_predial') or predio.get('codigo_predial_nacional') or predio.get('numero_predial')
        
        # Obtener datos de propuesta aprobada si existe
        datos_aprobados_r2 = {}
        if codigo_predio and codigo_predio in datos_propuestas:
            datos_aprobados_r2 = datos_propuestas[codigo_predio].get('datos', {})
        
        # Seleccionar color
        if tipo_cambio == 'predio_nuevo':
            fill = nuevo_fill
        elif tipo_cambio == 'mejora_nueva':
            fill = mejora_fill
        elif tipo_cambio == 'actualizado' or estado_visita == 'actualizado':
            fill = actualizado_fill
        elif estado_visita == 'visitado_firmado':
            fill = firmado_fill
        else:
            fill = None
        
        # Obtener datos R2 - buscar en múltiples fuentes, priorizando propuesta aprobada
        r2_registros = []
        
        # 1. Prioridad: datos de propuesta aprobada
        if datos_aprobados_r2:
            r2_prop = datos_aprobados_r2.get('r2_registros', [])
            if not r2_prop:
                # Buscar en r2 anidado
                r2_data = datos_aprobados_r2.get('r2', {})
                if isinstance(r2_data, dict):
                    r2_prop = r2_data.get('registros', [])
            if r2_prop:
                r2_registros = r2_prop
        
        # 2. Si no hay de propuesta, usar del predio
        if not r2_registros:
            r2_registros = predio.get('r2_registros', [])
        
        # Si no hay r2_registros, intentar construirlos desde zonas_fisicas o visita_data
        if not r2_registros:
            zonas_fisicas = predio.get('zonas_fisicas', [])
            visita_data = predio.get('visita_data', {})
            construcciones = predio.get('construcciones', visita_data.get('construcciones', []))
            
            # También buscar construcciones en datos aprobados
            if not construcciones and datos_aprobados_r2:
                construcciones = datos_aprobados_r2.get('construcciones', [])
            
            # Obtener matrícula priorizando propuesta aprobada
            matricula = ''
            if datos_aprobados_r2:
                matricula = datos_aprobados_r2.get('matricula_inmobiliaria', datos_aprobados_r2.get('matricula', ''))
            if not matricula:
                matricula = predio.get('matricula_inmobiliaria', predio.get('matricula', ''))
            
            # Combinar zonas y construcciones
            if zonas_fisicas or construcciones:
                zonas_combinadas = []
                max_items = max(len(zonas_fisicas), len(construcciones)) if zonas_fisicas or construcciones else 0
                for i in range(max_items):
                    zona_data = zonas_fisicas[i] if i < len(zonas_fisicas) else {}
                    const_data = construcciones[i] if i < len(construcciones) else {}
                    zonas_combinadas.append({
                        'zona_fisica': zona_data.get('zona_fisica', 0),
                        'zona_economica': zona_data.get('zona_economica', 0),
                        'area_terreno': zona_data.get('area_terreno', 0),
                        'habitaciones': const_data.get('habitaciones', const_data.get('total_habitaciones', 0)),
                        'banos': const_data.get('banos', const_data.get('total_banos', 0)),
                        'locales': const_data.get('locales', const_data.get('total_locales', 0)),
                        'pisos': const_data.get('pisos', const_data.get('num_pisos', const_data.get('total_pisos', 0))),
                        'tipificacion': const_data.get('tipificacion', ''),
                        'uso': const_data.get('uso', const_data.get('codigo_uso', '')),
                        'puntaje': const_data.get('puntaje', 0),
                        'area_construida': const_data.get('area_construida', const_data.get('area', 0))
                    })
                r2_registros = [{'matricula_inmobiliaria': matricula, 'zonas': zonas_combinadas}]
            else:
                # Crear registro mínimo
                r2_registros = [{'matricula_inmobiliaria': matricula, 'zonas': []}]
        
        # Calcular total de registros R2 (considerando que cada 3 zonas = 1 registro)
        total_r2 = len(r2_registros)
        for r2 in r2_registros:
            zonas = r2.get('zonas', [])
            if len(zonas) > 3:
                # Cada grupo de 3 zonas genera un registro adicional
                total_r2 += (len(zonas) - 1) // 3
        
        r2_idx_global = 0
        for r2 in r2_registros:
            zonas = r2.get('zonas', [])
            matricula = r2.get('matricula_inmobiliaria', '')
            
            # Si no hay zonas, escribir un registro vacío
            if not zonas:
                zonas = [{}]
            
            # Agrupar zonas de 3 en 3 (cada grupo genera una fila)
            for grupo_idx in range(0, len(zonas), 3):
                r2_idx_global += 1
                grupo_zonas = zonas[grupo_idx:grupo_idx + 3]
                
                # Datos básicos del predio
                ws_r2.cell(row=row, column=1, value=predio.get('departamento', proyecto.get('departamento', 'NORTE DE SANTANDER')))
                ws_r2.cell(row=row, column=2, value=predio.get('municipio', proyecto.get('municipio', '')))
                ws_r2.cell(row=row, column=3, value=predio.get('numero_predio', predio.get('numero_predial', '')))
                ws_r2.cell(row=row, column=4, value=predio.get('codigo_predial_nacional', predio.get('codigo_predial', predio.get('numero_predial', ''))))
                ws_r2.cell(row=row, column=5, value='2')
                ws_r2.cell(row=row, column=6, value=str(r2_idx_global).zfill(2))
                ws_r2.cell(row=row, column=7, value=str(total_r2).zfill(2))
                ws_r2.cell(row=row, column=8, value=matricula)
                
                # Zona 1 (columnas 9-11)
                z1 = grupo_zonas[0] if len(grupo_zonas) >= 1 else {}
                ws_r2.cell(row=row, column=9, value=z1.get('zona_fisica', 0) or 0)
                ws_r2.cell(row=row, column=10, value=z1.get('zona_economica', 0) or 0)
                ws_r2.cell(row=row, column=11, value=z1.get('area_terreno', 0) or 0)
                
                # Zona 2 (columnas 12-14)
                z2 = grupo_zonas[1] if len(grupo_zonas) >= 2 else {}
                ws_r2.cell(row=row, column=12, value=z2.get('zona_fisica', 0) or 0)
                ws_r2.cell(row=row, column=13, value=z2.get('zona_economica', 0) or 0)
                ws_r2.cell(row=row, column=14, value=z2.get('area_terreno', 0) or 0)
                
                # Construcción 1 (columnas 15-22)
                ws_r2.cell(row=row, column=15, value=z1.get('habitaciones', 0) or 0)
                ws_r2.cell(row=row, column=16, value=z1.get('banos', 0) or 0)
                ws_r2.cell(row=row, column=17, value=z1.get('locales', 0) or 0)
                ws_r2.cell(row=row, column=18, value=z1.get('pisos', 0) or 0)
                ws_r2.cell(row=row, column=19, value=z1.get('tipificacion', 0) or 0)
                ws_r2.cell(row=row, column=20, value=z1.get('uso', 0) or 0)
                ws_r2.cell(row=row, column=21, value=z1.get('puntaje', 0) or 0)
                ws_r2.cell(row=row, column=22, value=z1.get('area_construida', 0) or 0)
                
                # Construcción 2 (columnas 23-30)
                ws_r2.cell(row=row, column=23, value=z2.get('habitaciones', 0) or 0)
                ws_r2.cell(row=row, column=24, value=z2.get('banos', 0) or 0)
                ws_r2.cell(row=row, column=25, value=z2.get('locales', 0) or 0)
                ws_r2.cell(row=row, column=26, value=z2.get('pisos', 0) or 0)
                ws_r2.cell(row=row, column=27, value=z2.get('tipificacion', 0) or 0)
                ws_r2.cell(row=row, column=28, value=z2.get('uso', 0) or 0)
                ws_r2.cell(row=row, column=29, value=z2.get('puntaje', 0) or 0)
                ws_r2.cell(row=row, column=30, value=z2.get('area_construida', 0) or 0)
                
                # Construcción 3 (columnas 31-38)
                z3 = grupo_zonas[2] if len(grupo_zonas) >= 3 else {}
                ws_r2.cell(row=row, column=31, value=z3.get('habitaciones', 0) or 0)
                ws_r2.cell(row=row, column=32, value=z3.get('banos', 0) or 0)
                ws_r2.cell(row=row, column=33, value=z3.get('locales', 0) or 0)
                ws_r2.cell(row=row, column=34, value=z3.get('pisos', 0) or 0)
                ws_r2.cell(row=row, column=35, value=z3.get('tipificacion', 0) or 0)
                ws_r2.cell(row=row, column=36, value=z3.get('uso', 0) or 0)
                ws_r2.cell(row=row, column=37, value=z3.get('puntaje', 0) or 0)
                ws_r2.cell(row=row, column=38, value=z3.get('area_construida', 0) or 0)
                
                # Campos extra de actualización
                ws_r2.cell(row=row, column=39, value=predio.get('vigencia', datetime.now().year))
                ws_r2.cell(row=row, column=40, value=estado_visita)
                ws_r2.cell(row=row, column=41, value=tipo_cambio.upper())
                
                # Aplicar color
                if fill:
                    for c in range(1, 42):
                        ws_r2.cell(row=row, column=c).fill = fill
                
                row += 1
    
    # === HOJA RESUMEN ===
    ws_resumen = wb.create_sheet(title="RESUMEN")
    
    # Calcular estadísticas
    count_con_geometria = len([p for p in predios if p.get('tipo_cambio') == 'con_geometria'])
    count_original = len([p for p in predios if p.get('tipo_cambio') == 'original'])
    count_predio_nuevo = len([p for p in predios if p.get('tipo_cambio') == 'predio_nuevo'])
    count_mejora_nueva = len([p for p in predios if p.get('tipo_cambio') == 'mejora_nueva'])
    count_actualizado = len([p for p in predios if p.get('tipo_cambio') == 'actualizado' or p.get('estado_visita') == 'actualizado'])
    count_firmado = len([p for p in predios if p.get('estado_visita') == 'visitado_firmado'])
    count_visitado = len([p for p in predios if p.get('estado_visita') == 'visitado'])
    
    resumen_data = [
        ["RESUMEN DE EXPORTACIÓN R1/R2"],
        [""],
        ["Proyecto:", proyecto.get('nombre', '')],
        ["Municipio:", municipio],
        ["Fecha de exportación:", datetime.now().strftime('%Y-%m-%d %H:%M')],
        ["Exportado por:", current_user.get('full_name', '')],
        ["Modo:", "Solo actualizados/firmados" if solo_actualizados else "Completo (todos los predios)"],
        [""],
        ["ESTADÍSTICAS:"],
        ["Total predios exportados:", len(predios)],
        ["Predios con geometría GDB:", count_con_geometria],
        ["Predios originales (R1/R2):", count_original],
        ["Predios nuevos aprobados:", count_predio_nuevo],
        ["Mejoras nuevas aprobadas:", count_mejora_nueva],
        ["Predios con cambios aprobados:", count_actualizado],
        [""],
        ["ESTADOS DE VISITA:"],
        ["Visitas firmadas:", count_firmado],
        ["Visitas sin firmar:", count_visitado],
        ["Cancelaciones (excluidas):", len(codigos_cancelados)],
        [""],
        ["LEYENDA DE COLORES:"],
        ["Azul claro:", "Predio nuevo aprobado"],
        ["Indigo claro:", "Mejora nueva aprobada"],
        ["Amarillo:", "Predio actualizado / con cambios"],
        ["Verde claro:", "Visita firmada"],
        ["Sin color:", "Original (sin cambios)"],
    ]
    
    for row_idx, row_data in enumerate(resumen_data, 1):
        for col_idx, value in enumerate(row_data, 1):
            cell = ws_resumen.cell(row=row_idx, column=col_idx, value=value)
            if row_idx == 1:
                cell.font = Font(bold=True, size=14)
            elif row_idx == 9:  # ESTADÍSTICAS
                cell.font = Font(bold=True)
            elif row_idx == 17:  # ESTADOS DE VISITA
                cell.font = Font(bold=True)
            elif row_idx == 22:  # LEYENDA DE COLORES
                cell.font = Font(bold=True)
    
    ws_resumen.column_dimensions['A'].width = 30
    ws_resumen.column_dimensions['B'].width = 50
    
    # Ajustar anchos de columna para R1 y R2
    for ws in [ws_r1, ws_r2]:
        for col in ws.columns:
            max_length = 0
            column = col[0].column_letter
            for cell in col:
                try:
                    if len(str(cell.value)) > max_length:
                        max_length = len(str(cell.value))
                except:
                    pass
            adjusted_width = min(max_length + 2, 40)
            ws.column_dimensions[column].width = adjusted_width
    
    # Guardar en memoria
    output = BytesIO()
    wb.save(output)
    output.seek(0)
    
    filename = f"R1R2_Actualizacion_{municipio}_{datetime.now().strftime('%Y%m%d_%H%M')}.xlsx"
    
    return StreamingResponse(
        output,
        media_type="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        headers={"Content-Disposition": f"attachment; filename={filename}"}
    )


# ==================== PROPUESTAS DE CAMBIO ====================

@api_router.post("/actualizacion/proyectos/{proyecto_id}/predios/{codigo_predial}/propuesta")
async def crear_propuesta_cambio(
    proyecto_id: str,
    codigo_predial: str,
    data: dict,
    current_user: dict = Depends(get_current_user)
):
    """Crea una propuesta de cambio para un predio (solo si está visitado)"""
    if current_user['role'] not in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR, UserRole.GESTOR]:
        raise HTTPException(status_code=403, detail="No tiene permiso para crear propuestas")
    
    # Buscar el predio
    predio = await db.predios_actualizacion.find_one({
        "proyecto_id": proyecto_id,
        "$or": [
            {"codigo_predial": codigo_predial},
            {"numero_predial": codigo_predial}
        ]
    })
    
    if not predio:
        raise HTTPException(status_code=404, detail="Predio no encontrado")
    
    # Verificar que el predio esté visitado
    if predio.get('estado_visita') not in ['visitado', 'visitado_firmado', 'actualizado']:
        raise HTTPException(status_code=400, detail="El predio debe estar visitado antes de proponer cambios")
    
    # Verificar que tenga el formulario de visita completo
    formato_visita = predio.get('formato_visita')
    if not formato_visita:
        raise HTTPException(
            status_code=400, 
            detail="Debe completar el Formato de Visita antes de enviar a aprobación. Abra el predio y complete el formulario de visita."
        )
    
    # Validar campos mínimos requeridos del formato de visita
    campos_requeridos = ['fecha_visita', 'persona_atiende']
    campos_faltantes = [campo for campo in campos_requeridos if not formato_visita.get(campo)]
    if campos_faltantes:
        raise HTTPException(
            status_code=400,
            detail=f"El Formato de Visita está incompleto. Faltan los siguientes campos: {', '.join(campos_faltantes)}"
        )
    
    # Verificar que no haya una propuesta pendiente para este código
    propuesta_existente = await db.propuestas_cambio_actualizacion.find_one({
        "proyecto_id": proyecto_id,
        "codigo_predial": codigo_predial,
        "estado": {"$in": ["pendiente", "subsanacion", "reenviada"]}
    })
    
    if propuesta_existente:
        tipo_propuesta = propuesta_existente.get('tipo', 'cambio')
        if tipo_propuesta == 'cancelacion':
            raise HTTPException(
                status_code=400, 
                detail="Ya existe una solicitud de ELIMINACIÓN pendiente para este predio. Espere la respuesta del coordinador o cancele la solicitud anterior."
            )
        elif tipo_propuesta == 'predio_nuevo':
            raise HTTPException(
                status_code=400, 
                detail="Ya existe una solicitud de PREDIO NUEVO pendiente para este código."
            )
        else:
            raise HTTPException(
                status_code=400, 
                detail="Ya existe una solicitud de CAMBIO pendiente para este predio. Espere la respuesta del coordinador o cancele la solicitud anterior."
            )
    
    # Obtener proyecto para el municipio
    proyecto = await db.proyectos_actualizacion.find_one({"id": proyecto_id})
    municipio = proyecto.get('municipio', '') if proyecto else ''
    
    # Guardar snapshot completo de los datos existentes
    datos_existentes = {
        "direccion": predio.get('direccion', ''),
        "destino_economico": predio.get('destino_economico', ''),
        "area_terreno": predio.get('area_terreno', 0),
        "area_construida": predio.get('area_construida', 0),
        "avaluo": predio.get('avaluo', 0),
        "matricula": predio.get('matricula', ''),
        "estrato": predio.get('estrato', ''),
        "propietarios": predio.get('propietarios', []),
        "zonas_fisicas": predio.get('zonas_fisicas', [])
    }
    
    # Crear propuesta de cambio
    tipo_revision = data.get('tipo_revision', 'campo')  # campo, juridico, calidad
    
    # Nombres legibles para el tipo de revisión
    tipos_revision_nombres = {
        'campo': 'Revisión de Campo',
        'juridico': 'Revisión Jurídica',
        'calidad': 'Control de Calidad'
    }
    
    propuesta = {
        "id": str(uuid.uuid4()),
        "proyecto_id": proyecto_id,
        "codigo_predial": codigo_predial,
        "municipio": municipio,
        "datos_existentes": datos_existentes,
        "datos_propuestos": data.get('datos_propuestos', {}),
        "tipo_revision": tipo_revision,
        "tipo_revision_nombre": tipos_revision_nombres.get(tipo_revision, 'Revisión de Campo'),
        "justificacion": data.get('justificacion', ''),
        "estado": "pendiente",  # pendiente, aprobada, rechazada, subsanacion, reenviada, rechazada_definitiva
        "creado_por": current_user.get('email'),
        "creado_por_nombre": current_user.get('full_name', current_user.get('email')),
        "creado_en": datetime.now(COLOMBIA_TZ).isoformat(),
        "revisado_por": None,
        "revisado_en": None,
        "comentario_revision": None,
        "intentos_subsanacion": 0,
        "historial_revision": []
    }
    
    await db.propuestas_cambio_actualizacion.insert_one(propuesta)
    
    # Agregar al historial del predio con tipo de revisión
    await db.predios_actualizacion.update_one(
        {"_id": predio["_id"]},
        {
            "$push": {
                "historial_cambios": {
                    "fecha": datetime.now(COLOMBIA_TZ).isoformat(),
                    "usuario": current_user.get('email'),
                    "usuario_nombre": current_user.get('full_name', current_user.get('email')),
                    "tipo_revision": tipo_revision,
                    "tipo_revision_nombre": tipos_revision_nombres.get(tipo_revision, 'Revisión de Campo'),
                    "accion": "propuesta_creada",
                    "propuesta_id": propuesta["id"],
                    "campos_modificados": list(data.get('datos_propuestos', {}).keys())
                }
            }
        }
    )
    
    return {
        "message": "Propuesta de cambio creada exitosamente",
        "propuesta_id": propuesta["id"],
        "tipo_revision": tipo_revision
    }


@api_router.get("/actualizacion/proyectos/{proyecto_id}/propuestas")
async def listar_propuestas_proyecto(
    proyecto_id: str,
    estado: Optional[str] = None,
    current_user: dict = Depends(get_current_user)
):
    """Lista todas las propuestas de cambio de un proyecto"""
    if current_user['role'] not in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR, UserRole.GESTOR]:
        raise HTTPException(status_code=403, detail="No tiene permiso para ver propuestas")
    
    query = {"proyecto_id": proyecto_id}
    
    if estado:
        if estado == 'subsanacion':
            # Incluir tanto subsanacion como reenviada
            query["estado"] = {"$in": ["subsanacion", "reenviada"]}
        elif estado == 'pendiente':
            # Incluir pendiente y reenviada (ambas esperan acción del coordinador)
            query["estado"] = {"$in": ["pendiente", "reenviada"]}
        elif estado == 'rechazada':
            # Solo las rechazadas definitivas
            query["estado"] = {"$in": ["rechazada", "rechazada_definitiva"]}
        else:
            query["estado"] = estado
    
    # Obtener proyecto para agregar municipio
    proyecto = await db.proyectos_actualizacion.find_one({"id": proyecto_id}, {"_id": 0, "municipio": 1, "nombre": 1})
    
    propuestas = await db.propuestas_cambio_actualizacion.find(
        query, {"_id": 0}
    ).sort("creado_en", -1).to_list(1000)
    
    # Agregar municipio del proyecto a cada propuesta
    for prop in propuestas:
        if not prop.get('municipio') and proyecto:
            prop['municipio'] = proyecto.get('municipio', '')
    
    return {
        "propuestas": propuestas,
        "total": len(propuestas)
    }


@api_router.get("/actualizacion/proyectos/{proyecto_id}/predios/{codigo_predial}/propuestas")
async def listar_propuestas_predio(
    proyecto_id: str,
    codigo_predial: str,
    current_user: dict = Depends(get_current_user)
):
    """Lista las propuestas de cambio de un predio específico"""
    if current_user['role'] not in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR, UserRole.GESTOR]:
        raise HTTPException(status_code=403, detail="No tiene permiso para ver propuestas")
    
    propuestas = await db.propuestas_cambio_actualizacion.find(
        {"proyecto_id": proyecto_id, "codigo_predial": codigo_predial},
        {"_id": 0}
    ).sort("creado_en", -1).to_list(100)
    
    return {
        "propuestas": propuestas,
        "total": len(propuestas)
    }


# ==================== CANCELACIÓN DE PREDIOS EN ACTUALIZACIÓN ====================

@api_router.post("/actualizacion/proyectos/{proyecto_id}/predios/{codigo_predial}/proponer-cancelacion")
async def proponer_cancelacion_predio(
    proyecto_id: str,
    codigo_predial: str,
    data: dict,
    current_user: dict = Depends(get_current_user)
):
    """
    Propone la cancelación de un predio en actualización.
    - Gestores: Solo pueden PROPONER (requiere aprobación de coordinador)
    - Coordinadores/Admin: Pueden cancelar directamente
    """
    if current_user['role'] not in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR, UserRole.GESTOR]:
        raise HTTPException(status_code=403, detail="No tiene permiso para cancelar predios")
    
    # Buscar el predio
    predio = await db.predios_actualizacion.find_one({
        "proyecto_id": proyecto_id,
        "$or": [
            {"codigo_predial": codigo_predial},
            {"numero_predial": codigo_predial}
        ]
    })
    
    if not predio:
        raise HTTPException(status_code=404, detail="Predio no encontrado")
    
    # Verificar que no esté ya cancelado
    if predio.get('cancelado') or predio.get('deleted'):
        raise HTTPException(status_code=400, detail="El predio ya está cancelado")
    
    # Obtener proyecto para el municipio
    proyecto = await db.proyectos_actualizacion.find_one({"id": proyecto_id})
    municipio = proyecto.get('municipio', '') if proyecto else ''
    
    motivo = data.get('motivo', 'Sin motivo especificado')
    
    # Si es coordinador/admin, cancelar directamente
    if current_user['role'] in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR]:
        historial_entry = {
            "accion": "Predio cancelado",
            "motivo": motivo,
            "usuario": current_user['full_name'],
            "usuario_id": current_user['id'],
            "fecha": datetime.now(COLOMBIA_TZ).isoformat()
        }
        
        await db.predios_actualizacion.update_one(
            {"_id": predio["_id"]},
            {
                "$set": {
                    "cancelado": True,
                    "deleted": True,
                    "cancelado_en": datetime.now(COLOMBIA_TZ).isoformat(),
                    "cancelado_por": current_user['id'],
                    "cancelado_por_nombre": current_user['full_name'],
                    "motivo_cancelacion": motivo,
                    "estado_visita": "cancelado"
                },
                "$push": {"historial": historial_entry}
            }
        )
        
        return {
            "message": "Predio cancelado exitosamente",
            "cancelado_por": current_user['full_name']
        }
    
    # Si es gestor, verificar que no haya una propuesta pendiente para este código
    propuesta_existente = await db.propuestas_cambio_actualizacion.find_one({
        "proyecto_id": proyecto_id,
        "codigo_predial": codigo_predial,
        "estado": {"$in": ["pendiente", "subsanacion", "reenviada"]}
    })
    
    if propuesta_existente:
        tipo_propuesta = propuesta_existente.get('tipo', 'cambio')
        if tipo_propuesta == 'cancelacion':
            raise HTTPException(
                status_code=400, 
                detail="Ya existe una solicitud de ELIMINACIÓN pendiente para este predio. Espere la respuesta del coordinador."
            )
        elif tipo_propuesta == 'predio_nuevo':
            raise HTTPException(
                status_code=400, 
                detail="Ya existe una solicitud de PREDIO NUEVO pendiente para este código. Espere la respuesta del coordinador."
            )
        else:
            raise HTTPException(
                status_code=400, 
                detail="Ya existe una solicitud de CAMBIO pendiente para este predio. Espere la respuesta del coordinador."
            )
    
    # Verificar que el predio no tenga cancelación pendiente ya marcada
    if predio.get('cancelacion_pendiente'):
        raise HTTPException(
            status_code=400, 
            detail="Este predio ya tiene una solicitud de eliminación en proceso."
        )
    
    # Si es gestor, crear propuesta de cancelación
    propuesta = {
        "id": str(uuid.uuid4()),
        "proyecto_id": proyecto_id,
        "codigo_predial": codigo_predial,
        "municipio": municipio,
        "tipo": "cancelacion",  # Tipo de propuesta: cancelacion
        "motivo": motivo,
        "estado": "pendiente",
        "propuesto_por": current_user['id'],
        "propuesto_por_nombre": current_user['full_name'],
        "creado_en": datetime.now(COLOMBIA_TZ).isoformat(),
        "datos_predio": {
            "direccion": predio.get('direccion', ''),
            "propietarios": predio.get('propietarios', []),
            "area_terreno": predio.get('area_terreno', 0),
            "estado_visita": predio.get('estado_visita', '')
        }
    }
    
    await db.propuestas_cambio_actualizacion.insert_one(propuesta)
    
    # Marcar el predio como "pendiente cancelación"
    await db.predios_actualizacion.update_one(
        {"_id": predio["_id"]},
        {
            "$set": {"cancelacion_pendiente": True},
            "$push": {"historial": {
                "accion": "Cancelación propuesta",
                "motivo": motivo,
                "usuario": current_user['full_name'],
                "fecha": datetime.now(COLOMBIA_TZ).isoformat()
            }}
        }
    )
    
    return {
        "message": "Propuesta de cancelación enviada. El coordinador la revisará.",
        "propuesta_id": propuesta["id"]
    }


@api_router.delete("/actualizacion/proyectos/{proyecto_id}/predios/{codigo_predial}")
async def cancelar_predio_actualizacion(
    proyecto_id: str,
    codigo_predial: str,
    current_user: dict = Depends(get_current_user)
):
    """
    Cancela un predio directamente (solo coordinador/admin).
    Para gestores usar el endpoint de proponer-cancelacion.
    """
    if current_user['role'] not in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR]:
        raise HTTPException(status_code=403, detail="Solo coordinadores pueden cancelar predios directamente")
    
    # Buscar el predio
    predio = await db.predios_actualizacion.find_one({
        "proyecto_id": proyecto_id,
        "$or": [
            {"codigo_predial": codigo_predial},
            {"numero_predial": codigo_predial}
        ]
    })
    
    if not predio:
        raise HTTPException(status_code=404, detail="Predio no encontrado")
    
    if predio.get('cancelado') or predio.get('deleted'):
        raise HTTPException(status_code=400, detail="El predio ya está cancelado")
    
    historial_entry = {
        "accion": "Predio cancelado",
        "usuario": current_user['full_name'],
        "usuario_id": current_user['id'],
        "fecha": datetime.now(COLOMBIA_TZ).isoformat()
    }
    
    await db.predios_actualizacion.update_one(
        {"_id": predio["_id"]},
        {
            "$set": {
                "cancelado": True,
                "deleted": True,
                "cancelado_en": datetime.now(COLOMBIA_TZ).isoformat(),
                "cancelado_por": current_user['id'],
                "cancelado_por_nombre": current_user['full_name'],
                "estado_visita": "cancelado"
            },
            "$push": {"historial": historial_entry}
        }
    )
    
    return {"message": "Predio cancelado exitosamente"}


@api_router.patch("/actualizacion/propuestas/{propuesta_id}/aprobar")
async def aprobar_propuesta(
    propuesta_id: str,
    data: dict,
    current_user: dict = Depends(get_current_user)
):
    """Aprueba una propuesta de cambio o cancelación (solo coordinador/admin)"""
    if current_user['role'] not in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR]:
        raise HTTPException(status_code=403, detail="Solo coordinadores pueden aprobar propuestas")
    
    propuesta = await db.propuestas_cambio_actualizacion.find_one({"id": propuesta_id})
    if not propuesta:
        raise HTTPException(status_code=404, detail="Propuesta no encontrada")
    
    if propuesta.get('estado') != 'pendiente':
        raise HTTPException(status_code=400, detail="La propuesta ya fue revisada")
    
    # Actualizar propuesta
    await db.propuestas_cambio_actualizacion.update_one(
        {"id": propuesta_id},
        {
            "$set": {
                "estado": "aprobada",
                "revisado_por": current_user.get('email'),
                "revisado_en": datetime.now(COLOMBIA_TZ).isoformat(),
                "comentario_revision": data.get('comentario', '')
            }
        }
    )
    
    # Si es propuesta de CANCELACIÓN, aplicar la cancelación
    if propuesta.get('tipo') == 'cancelacion':
        historial_entry = {
            "accion": "Cancelación aprobada",
            "motivo": propuesta.get('motivo', ''),
            "propuesto_por": propuesta.get('propuesto_por_nombre'),
            "aprobado_por": current_user['full_name'],
            "fecha": datetime.now(COLOMBIA_TZ).isoformat()
        }
        
        await db.predios_actualizacion.update_one(
            {
                "proyecto_id": propuesta['proyecto_id'],
                "$or": [
                    {"codigo_predial": propuesta['codigo_predial']},
                    {"numero_predial": propuesta['codigo_predial']}
                ]
            },
            {
                "$set": {
                    "cancelado": True,
                    "deleted": True,
                    "cancelacion_pendiente": False,
                    "cancelado_en": datetime.now(COLOMBIA_TZ).isoformat(),
                    "cancelado_por": current_user['id'],
                    "cancelado_por_nombre": current_user['full_name'],
                    "motivo_cancelacion": propuesta.get('motivo', ''),
                    "estado_visita": "cancelado"
                },
                "$push": {"historial": historial_entry}
            }
        )
        
        return {"message": "Cancelación aprobada. Predio cancelado exitosamente."}
    
    # Si es propuesta de PREDIO NUEVO, crear el predio
    if propuesta.get('tipo') == 'predio_nuevo':
        datos_propuestos = propuesta.get('datos_propuestos', {})
        r1 = datos_propuestos.get('r1', {})
        r2 = datos_propuestos.get('r2', {})
        propietarios_data = datos_propuestos.get('propietarios', [])
        zonas_fisicas = datos_propuestos.get('zonas_fisicas', [])
        construcciones = datos_propuestos.get('construcciones', [])
        formato_visita = datos_propuestos.get('formato_visita', {})
        
        codigo_predial = propuesta.get('codigo_predial')
        municipio = propuesta.get('municipio')
        proyecto_id = propuesta.get('proyecto_id')
        
        # Asignar código homologado automáticamente
        codigo_homologado = await asignar_codigo_homologado(municipio, None)
        if not codigo_homologado:
            codigo_homologado, _ = await generate_codigo_homologado(municipio)
        
        # Crear el predio nuevo
        predio_id = str(uuid.uuid4())
        ahora = datetime.now(COLOMBIA_TZ).isoformat()
        
        es_mejora = propuesta.get('es_mejora', False)
        # Fallback: detectar mejora por dígito de condición si no viene en la propuesta
        if not es_mejora and codigo_predial and len(codigo_predial) >= 22:
            es_mejora = codigo_predial[21] != '0'

        predio_nuevo = {
            "id": predio_id,
            "proyecto_id": proyecto_id,
            "codigo_predial": codigo_predial,
            "codigo_homologado": codigo_homologado,
            "municipio": municipio,
            "es_nuevo": True,
            "es_mejora": es_mejora,

            # Datos R1
            "direccion": r1.get('direccion', ''),
            "destino_economico": r1.get('destino_economico', ''),
            "area_terreno": float(r1.get('area_terreno', 0)),
            "area_construida": float(r1.get('area_construida', 0)),
            "avaluo": float(r1.get('avaluo', 0)),
            "matricula_inmobiliaria": r2.get('matricula_inmobiliaria', ''),

            # Propietarios
            "propietarios": propietarios_data,

            # Zonas físicas y construcciones
            "zonas_fisicas": zonas_fisicas,
            "construcciones": construcciones,
            "r2": r2,

            # Formato de visita
            "formato_visita": formato_visita,
            "estado_visita": "visitado",

            # Metadatos
            "creado_por": propuesta.get('creado_por'),
            "creado_por_nombre": propuesta.get('creado_por_nombre'),
            "aprobado_por": current_user.get('email'),
            "aprobado_por_nombre": current_user.get('full_name'),
            "created_at": propuesta.get('created_at'),
            "updated_at": ahora,

            # Historial
            "historial_cambios": [
                {
                    "fecha": propuesta.get('created_at'),
                    "usuario": propuesta.get('creado_por'),
                    "accion": "propuesta_predio_nuevo_creada",
                    "descripcion": "Propuesta de predio nuevo enviada por gestor"
                },
                {
                    "fecha": ahora,
                    "usuario": current_user.get('email'),
                    "accion": "predio_nuevo_aprobado",
                    "descripcion": f"Predio nuevo aprobado por coordinador. Código homologado: {codigo_homologado}"
                }
            ]
        }

        await db.predios_actualizacion.insert_one(predio_nuevo)

        # IMPORTANTE: También insertar en la colección 'predios' para Gestión de Predios
        predio_para_gestion = {
            "id": predio_id,
            "codigo_predial_nacional": codigo_predial,
            "codigo_homologado": codigo_homologado,
            "municipio": municipio,
            "direccion": r1.get('direccion', ''),
            "destino_economico": r1.get('destino_economico', ''),
            "area_terreno": float(r1.get('area_terreno', 0)),
            "area_terreno_r1": float(r1.get('area_terreno', 0)),
            "area_construida": float(r1.get('area_construida', 0)),
            "area_construida_r1": float(r1.get('area_construida', 0)),
            "avaluo": float(r1.get('avaluo', 0)),
            "matricula_inmobiliaria": r2.get('matricula_inmobiliaria', ''),
            "propietarios": propietarios_data,
            "nombre_propietario": propietarios_data[0].get('nombre_propietario', '') if propietarios_data else '',
            "zonas_fisicas": zonas_fisicas,
            "construcciones": construcciones,
            "estado": "activo",
            "estado_flujo": "aprobado",
            "es_nuevo": True,
            "es_mejora": es_mejora,
            "origen": "propuesta_aprobada",
            "creado_por": propuesta.get('creado_por'),
            "creado_por_nombre": propuesta.get('creado_por_nombre'),
            "aprobado_por": current_user.get('email'),
            "aprobado_por_nombre": current_user.get('full_name'),
            "created_at": ahora,
            "updated_at": ahora
        }
        
        # Verificar si ya existe el predio en 'predios'
        predio_existente = await db.predios.find_one({"codigo_predial_nacional": codigo_predial})
        if not predio_existente:
            await db.predios.insert_one(predio_para_gestion)
            logger.info(f"Predio nuevo insertado en colección 'predios': {codigo_predial}")
        else:
            # Actualizar si ya existe
            await db.predios.update_one(
                {"codigo_predial_nacional": codigo_predial},
                {"$set": predio_para_gestion}
            )
            logger.info(f"Predio existente actualizado en 'predios': {codigo_predial}")
        
        # Actualizar contador del proyecto
        inc_fields = {"mejoras_nuevas_count": 1} if es_mejora else {"predios_nuevos_count": 1}
        await db.proyectos_actualizacion.update_one(
            {"id": proyecto_id},
            {"$inc": inc_fields}
        )

        logger.info(f"{'Mejora' if es_mejora else 'Predio'} nuevo aprobado por {current_user.get('email')}: {codigo_predial} -> {codigo_homologado}")
        
        return {
            "message": "Predio nuevo aprobado y creado exitosamente",
            "predio_id": predio_id,
            "codigo_predial": codigo_predial,
            "codigo_homologado": codigo_homologado
        }
    
    # Si es propuesta de CAMBIO, aplicar los cambios propuestos
    datos_propuestos = propuesta.get('datos_propuestos', {})
    
    # Preparar los datos a actualizar
    update_data = {
        **datos_propuestos,
        "estado_visita": "actualizado",  # Cambiar estado a actualizado
        "actualizado_por": current_user.get('email'),
        "actualizado_en": datetime.now(COLOMBIA_TZ).isoformat(),
        "updated_at": datetime.now(COLOMBIA_TZ)
    }
    
    await db.predios_actualizacion.update_one(
        {
            "proyecto_id": propuesta['proyecto_id'],
            "$or": [
                {"codigo_predial": propuesta['codigo_predial']},
                {"numero_predial": propuesta['codigo_predial']}
            ]
        },
        {
            "$set": update_data,
            "$push": {
                "historial_cambios": {
                    "fecha": datetime.now(COLOMBIA_TZ).isoformat(),
                    "usuario": current_user.get('email'),
                    "accion": "propuesta_aprobada_actualizado",
                    "propuesta_id": propuesta_id,
                    "cambios_aplicados": datos_propuestos
                }
            }
        }
    )
    
    return {"message": "Propuesta aprobada y cambios aplicados. Predio marcado como ACTUALIZADO"}


@api_router.patch("/actualizacion/propuestas/{propuesta_id}/rechazar")
async def rechazar_propuesta(
    propuesta_id: str,
    data: dict,
    current_user: dict = Depends(get_current_user)
):
    """Rechaza una propuesta de cambio y la envía a subsanación del gestor"""
    if current_user['role'] not in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR]:
        raise HTTPException(status_code=403, detail="Solo coordinadores pueden rechazar propuestas")
    
    propuesta = await db.propuestas_cambio_actualizacion.find_one({"id": propuesta_id})
    if not propuesta:
        raise HTTPException(status_code=404, detail="Propuesta no encontrada")
    
    if propuesta.get('estado') not in ['pendiente', 'reenviada']:
        raise HTTPException(status_code=400, detail="La propuesta ya fue revisada")
    
    intentos = propuesta.get('intentos_subsanacion', 0) + 1
    es_rechazo_definitivo = intentos >= 3
    
    # Actualizar propuesta
    update_data = {
        "estado": "rechazada_definitiva" if es_rechazo_definitivo else "subsanacion",
        "revisado_por": current_user.get('email'),
        "revisado_en": datetime.now(COLOMBIA_TZ).isoformat(),
        "comentario_revision": data.get('comentario', ''),
        "intentos_subsanacion": intentos
    }
    
    # Agregar al historial de la propuesta
    historial_entry = {
        "fecha": datetime.now(COLOMBIA_TZ).isoformat(),
        "accion": "rechazado_definitivo" if es_rechazo_definitivo else "rechazado_subsanacion",
        "usuario": current_user.get('email'),
        "comentario": data.get('comentario', ''),
        "intento": intentos
    }
    
    await db.propuestas_cambio_actualizacion.update_one(
        {"id": propuesta_id},
        {
            "$set": update_data,
            "$push": {"historial_revision": historial_entry}
        }
    )
    
    # Agregar al historial del predio
    await db.predios_actualizacion.update_one(
        {
            "proyecto_id": propuesta['proyecto_id'],
            "$or": [
                {"codigo_predial": propuesta['codigo_predial']},
                {"numero_predial": propuesta['codigo_predial']}
            ]
        },
        {
            "$push": {
                "historial_cambios": {
                    "fecha": datetime.now(COLOMBIA_TZ).isoformat(),
                    "usuario": current_user.get('email'),
                    "accion": "propuesta_rechazada_definitiva" if es_rechazo_definitivo else "propuesta_enviada_subsanacion",
                    "propuesta_id": propuesta_id,
                    "motivo": data.get('comentario', ''),
                    "intento": intentos
                }
            }
        }
    )
    
    # Notificar al gestor por correo
    gestor_email = propuesta.get('creado_por')
    if gestor_email and not es_rechazo_definitivo:
        try:
            # Obtener datos del proyecto
            proyecto = await db.proyectos_actualizacion.find_one({"id": propuesta['proyecto_id']})
            municipio = proyecto.get('municipio', 'N/A') if proyecto else 'N/A'
            
            asunto = "[Asomunicipios] Propuesta de Cambio Requiere Subsanación"
            cuerpo = f"""
            <html>
            <body style="font-family: Arial, sans-serif; line-height: 1.6;">
                <h2 style="color: #f59e0b;">Propuesta de Cambio Rechazada - Requiere Subsanación</h2>
                <p>Su propuesta de cambio ha sido rechazada y requiere subsanación:</p>
                <div style="background: #fef3c7; padding: 15px; border-radius: 8px; margin: 15px 0; border-left: 4px solid #f59e0b;">
                    <p><strong>Código Predial:</strong> {propuesta['codigo_predial']}</p>
                    <p><strong>Municipio:</strong> {municipio}</p>
                    <p><strong>Intento:</strong> {intentos}/3</p>
                </div>
                <div style="background: #fef2f2; padding: 15px; border-radius: 8px; border-left: 4px solid #dc2626;">
                    <p><strong>Motivo del Rechazo:</strong></p>
                    <p>{data.get('comentario', 'Sin comentario')}</p>
                    <p><strong>Rechazado por:</strong> {current_user.get('email')}</p>
                </div>
                <p style="margin-top: 20px;">Por favor, ingrese al Visor de Actualización para corregir y reenviar la propuesta.</p>
                <p style="color: #666; font-size: 12px; margin-top: 20px;">
                    Tiene <strong>{3 - intentos} intentos restantes</strong>. Después del tercer rechazo, la propuesta será descartada.
                </p>
            </body>
            </html>
            """
            await send_email(gestor_email, asunto, cuerpo)
        except Exception as e:
            logging.error(f"Error enviando notificación de subsanación: {e}")

    if es_rechazo_definitivo:
        return {"message": "Propuesta RECHAZADA DEFINITIVAMENTE (3 intentos agotados)", "definitivo": True}
    else:
        return {"message": f"Propuesta enviada a subsanación del gestor (intento {intentos}/3)", "definitivo": False}


@api_router.patch("/actualizacion/propuestas/{propuesta_id}/subsanar")
async def subsanar_propuesta(
    propuesta_id: str,
    data: dict,
    current_user: dict = Depends(get_current_user)
):
    """El gestor subsana y reenvía una propuesta rechazada"""
    propuesta = await db.propuestas_cambio_actualizacion.find_one({"id": propuesta_id})
    if not propuesta:
        raise HTTPException(status_code=404, detail="Propuesta no encontrada")
    
    if propuesta.get('estado') != 'subsanacion':
        raise HTTPException(status_code=400, detail="Esta propuesta no está en estado de subsanación")
    
    # Verificar que sea el gestor que la creó
    if current_user['role'] == UserRole.GESTOR and propuesta.get('creado_por') != current_user.get('email'):
        raise HTTPException(status_code=403, detail="Solo puede subsanar sus propias propuestas")
    
    # Actualizar datos propuestos
    nuevos_datos = data.get('datos_propuestos', propuesta.get('datos_propuestos', {}))
    justificacion = data.get('justificacion_subsanacion', '')
    
    historial_entry = {
        "fecha": datetime.now(COLOMBIA_TZ).isoformat(),
        "accion": "subsanado_reenviado",
        "usuario": current_user.get('email'),
        "justificacion": justificacion,
        "intento": propuesta.get('intentos_subsanacion', 1)
    }
    
    await db.propuestas_cambio_actualizacion.update_one(
        {"id": propuesta_id},
        {
            "$set": {
                "estado": "reenviada",
                "datos_propuestos": nuevos_datos,
                "justificacion_subsanacion": justificacion,
                "fecha_subsanacion": datetime.now(COLOMBIA_TZ).isoformat(),
                "subsanado_por": current_user.get('email')
            },
            "$push": {"historial_revision": historial_entry}
        }
    )
    
    # Notificar al coordinador que rechazó
    coordinador_email = propuesta.get('revisado_por')
    if coordinador_email:
        try:
            asunto = "[Asomunicipios] Propuesta Subsanada - Pendiente de Revisión"
            cuerpo = f"""
            <html>
            <body style="font-family: Arial, sans-serif;">
                <h2 style="color: #059669;">Propuesta Subsanada - Nueva Revisión Requerida</h2>
                <p>El gestor {current_user.get('email')} ha subsanado la propuesta:</p>
                <div style="background: #ecfdf5; padding: 15px; border-radius: 8px;">
                    <p><strong>Código Predial:</strong> {propuesta['codigo_predial']}</p>
                    <p><strong>Justificación:</strong> {justificacion}</p>
                </div>
            </body>
            </html>
            """
            await send_email(coordinador_email, asunto, cuerpo)
        except Exception as e:
            logging.error(f"Error enviando notificación: {e}")

    return {"message": "Propuesta subsanada y reenviada para revisión"}


@api_router.get("/actualizacion/propuestas/subsanacion-pendiente")
async def get_propuestas_subsanacion(
    current_user: dict = Depends(get_current_user)
):
    """Obtiene las propuestas pendientes de subsanación para el gestor actual"""
    query = {"estado": "subsanacion"}
    
    # Si es gestor, solo ver las suyas
    if current_user['role'] == UserRole.GESTOR:
        query["creado_por"] = current_user.get('email')
    
    propuestas = await db.propuestas_cambio_actualizacion.find(query, {"_id": 0}).sort("revisado_en", -1).to_list(500)
    
    return {
        "total": len(propuestas),
        "propuestas": propuestas
    }


@api_router.post("/actualizacion/proyectos/{proyecto_id}/propuestas/aprobar-masivo")
async def aprobar_propuestas_masivo(
    proyecto_id: str,
    data: dict,
    current_user: dict = Depends(get_current_user)
):
    """Aprueba múltiples propuestas de cambio (solo coordinador/admin)"""
    if current_user['role'] not in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR]:
        raise HTTPException(status_code=403, detail="Solo coordinadores pueden aprobar propuestas")
    
    propuesta_ids = data.get('propuesta_ids', [])
    if not propuesta_ids:
        raise HTTPException(status_code=400, detail="Debe proporcionar IDs de propuestas")
    
    aprobadas = 0
    errores = []
    
    for propuesta_id in propuesta_ids:
        try:
            propuesta = await db.propuestas_cambio_actualizacion.find_one({"id": propuesta_id, "proyecto_id": proyecto_id})
            if not propuesta:
                errores.append(f"{propuesta_id}: No encontrada")
                continue
            
            if propuesta.get('estado') != 'pendiente':
                errores.append(f"{propuesta_id}: Ya revisada")
                continue
            
            # Actualizar propuesta
            await db.propuestas_cambio_actualizacion.update_one(
                {"id": propuesta_id},
                {
                    "$set": {
                        "estado": "aprobada",
                        "revisado_por": current_user.get('email'),
                        "revisado_en": datetime.now(COLOMBIA_TZ).isoformat(),
                        "comentario_revision": data.get('comentario', 'Aprobación masiva')
                    }
                }
            )
            
            # Si es predio nuevo, crear el predio (igual que aprobación individual)
            if propuesta.get('tipo') == 'predio_nuevo':
                datos_propuestos = propuesta.get('datos_propuestos', {})
                r1 = datos_propuestos.get('r1', {})
                r2 = datos_propuestos.get('r2', {})
                propietarios_data = datos_propuestos.get('propietarios', [])
                zonas_fisicas = datos_propuestos.get('zonas_fisicas', [])
                construcciones = datos_propuestos.get('construcciones', [])
                formato_visita = datos_propuestos.get('formato_visita', {})

                codigo_predial = propuesta.get('codigo_predial')
                municipio = propuesta.get('municipio')

                # Asignar código homologado
                codigo_homologado = await asignar_codigo_homologado(municipio, None)
                if not codigo_homologado:
                    codigo_homologado, _ = await generate_codigo_homologado(municipio)

                predio_id = str(uuid.uuid4())
                ahora = datetime.now(COLOMBIA_TZ).isoformat()

                es_mejora = propuesta.get('es_mejora', False)
                if not es_mejora and codigo_predial and len(codigo_predial) >= 22:
                    es_mejora = codigo_predial[21] != '0'

                predio_nuevo = {
                    "id": predio_id,
                    "proyecto_id": proyecto_id,
                    "codigo_predial": codigo_predial,
                    "codigo_homologado": codigo_homologado,
                    "municipio": municipio,
                    "es_nuevo": True,
                    "es_mejora": es_mejora,
                    "direccion": r1.get('direccion', ''),
                    "destino_economico": r1.get('destino_economico', ''),
                    "area_terreno": float(r1.get('area_terreno', 0)),
                    "area_construida": float(r1.get('area_construida', 0)),
                    "avaluo": float(r1.get('avaluo', 0)),
                    "matricula_inmobiliaria": r2.get('matricula_inmobiliaria', ''),
                    "propietarios": propietarios_data,
                    "zonas_fisicas": zonas_fisicas,
                    "construcciones": construcciones,
                    "r2": r2,
                    "formato_visita": formato_visita,
                    "estado_visita": "visitado",
                    "creado_por": propuesta.get('creado_por'),
                    "creado_por_nombre": propuesta.get('creado_por_nombre'),
                    "aprobado_por": current_user.get('email'),
                    "aprobado_por_nombre": current_user.get('full_name'),
                    "created_at": propuesta.get('created_at'),
                    "updated_at": ahora,
                    "historial_cambios": [
                        {
                            "fecha": propuesta.get('created_at'),
                            "usuario": propuesta.get('creado_por'),
                            "accion": "propuesta_predio_nuevo_creada",
                            "descripcion": "Propuesta de predio nuevo enviada por gestor"
                        },
                        {
                            "fecha": ahora,
                            "usuario": current_user.get('email'),
                            "accion": "predio_nuevo_aprobado",
                            "descripcion": f"Predio nuevo aprobado (masivo). Código homologado: {codigo_homologado}"
                        }
                    ]
                }

                try:
                    await db.predios_actualizacion.insert_one(predio_nuevo)
                except Exception as e:
                    error_msg = str(e).lower()
                    if 'too large' in error_msg or 'bson' in error_msg or 'size' in error_msg:
                        errores.append(f"{propuesta_id}: Datos demasiado grandes")
                        continue
                    raise

                # Actualizar contador del proyecto
                inc_fields = {"mejoras_nuevas_count": 1} if es_mejora else {"predios_nuevos_count": 1}
                await db.proyectos_actualizacion.update_one(
                    {"id": proyecto_id},
                    {"$inc": inc_fields}
                )
            else:
                # Propuesta de cambio normal: aplicar update al predio existente
                datos_propuestos = propuesta.get('datos_propuestos', {})
                update_data = {
                    **datos_propuestos,
                    "estado_visita": "actualizado",
                    "actualizado_por": current_user.get('email'),
                    "actualizado_en": datetime.now(COLOMBIA_TZ).isoformat(),
                    "updated_at": datetime.now(COLOMBIA_TZ)
                }

                await db.predios_actualizacion.update_one(
                    {
                        "proyecto_id": propuesta['proyecto_id'],
                        "$or": [
                            {"codigo_predial": propuesta['codigo_predial']},
                            {"numero_predial": propuesta['codigo_predial']}
                        ]
                    },
                    {
                        "$set": update_data,
                        "$push": {
                            "historial_cambios": {
                                "fecha": datetime.now(COLOMBIA_TZ).isoformat(),
                                "usuario": current_user.get('email'),
                                "accion": "propuesta_aprobada_masivo_actualizado",
                                "propuesta_id": propuesta_id
                            }
                        }
                    }
                )

            aprobadas += 1
        except Exception as e:
            errores.append(f"{propuesta_id}: {str(e)}")
    
    return {
        "message": f"Aprobadas {aprobadas} de {len(propuesta_ids)} propuestas",
        "aprobadas": aprobadas,
        "errores": errores
    }


@api_router.get("/actualizacion/proyectos/{proyecto_id}/predios/{codigo_predial}/historial")
async def obtener_historial_predio(
    proyecto_id: str,
    codigo_predial: str,
    current_user: dict = Depends(get_current_user)
):
    """Obtiene el historial de cambios de un predio"""
    if current_user['role'] not in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR, UserRole.GESTOR]:
        raise HTTPException(status_code=403, detail="No tiene permiso para ver el historial")
    
    predio = await db.predios_actualizacion.find_one({
        "proyecto_id": proyecto_id,
        "$or": [
            {"codigo_predial": codigo_predial},
            {"numero_predial": codigo_predial}
        ]
    }, {"_id": 0, "historial_cambios": 1, "codigo_predial": 1})
    
    if not predio:
        raise HTTPException(status_code=404, detail="Predio no encontrado")
    
    return {
        "codigo_predial": predio.get('codigo_predial'),
        "historial": predio.get('historial_cambios', [])
    }


# ==================== GENERACIÓN DE PDF INFORME DE VISITA ====================

@api_router.post("/actualizacion/proyectos/{proyecto_id}/predios/{codigo_predial}/generar-pdf")
async def generar_pdf_informe_visita(
    proyecto_id: str,
    codigo_predial: str,
    current_user: dict = Depends(get_current_user)
):
    """Genera el PDF del informe de visita de un predio - VERSIÓN COMPLETA IGUAL AL FORMULARIO WEB"""
    if current_user['role'] not in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR, UserRole.GESTOR]:
        raise HTTPException(status_code=403, detail="No tiene permiso para generar PDF")
    
    import base64
    
    # Obtener proyecto
    proyecto = await db.proyectos_actualizacion.find_one({"id": proyecto_id}, {"_id": 0})
    if not proyecto:
        raise HTTPException(status_code=404, detail="Proyecto no encontrado")
    
    # Decodificar el código predial (puede venir URL encoded)
    from urllib.parse import unquote
    codigo_predial_decoded = unquote(codigo_predial)
    
    # Obtener predio
    predio = await db.predios_actualizacion.find_one({
        "proyecto_id": proyecto_id,
        "$or": [
            {"codigo_predial": codigo_predial_decoded},
            {"numero_predial": codigo_predial_decoded},
            {"codigo_predial": codigo_predial},
            {"numero_predial": codigo_predial}
        ]
    }, {"_id": 0})
    
    if not predio:
        raise HTTPException(status_code=404, detail=f"Predio no encontrado: {codigo_predial_decoded}")
    
    # BUGFIX: Obtener codigo_homologado desde la colección principal si no está en predios_actualizacion
    # El codigo_homologado se almacena en la colección 'predios' (principal) y puede no estar en 'predios_actualizacion'
    if not predio.get('codigo_homologado'):
        codigo_predial_para_buscar = predio.get('codigo_predial') or predio.get('numero_predial')
        if codigo_predial_para_buscar:
            predio_principal = await db.predios.find_one(
                {"codigo_predial_nacional": codigo_predial_para_buscar},
                {"_id": 0, "codigo_homologado": 1}
            )
            if predio_principal and predio_principal.get('codigo_homologado'):
                predio['codigo_homologado'] = predio_principal['codigo_homologado']
    
    # Verificar que tiene datos de visita
    # NOTA: Los datos de visita se guardan en 'formato_visita', no en 'visita'
    visita = predio.get('formato_visita', {}) or predio.get('visita', {})
    if not visita:
        # Verificar si el estado indica que fue visitado pero no tiene datos de visita
        estado = predio.get('estado_visita', 'pendiente')
        if estado in ['pendiente']:
            raise HTTPException(
                status_code=400, 
                detail="Este predio no tiene formulario de visita diligenciado. Debe registrar una visita primero."
            )
        # Si el estado es visitado pero no tiene visita, crear estructura vacía
        visita = {}
    
    # Propietarios y construcciones de la visita
    # Los datos pueden estar en formato_visita, en campos separados del predio, o en el predio original
    propietarios = (
        visita.get('propietarios_visita') or
        visita.get('propietarios') or
        predio.get('propietarios_visita') or
        predio.get('propietarios') or
        []
    )
    construcciones = (
        visita.get('construcciones_visita') or
        visita.get('construcciones') or
        predio.get('construcciones_visita') or
        predio.get('construcciones') or
        []
    )

    # BUGFIX: Obtener matrícula inmobiliaria de la colección principal si no está en predios_actualizacion
    if not predio.get('matricula_inmobiliaria'):
        codigo_para_buscar = predio.get('codigo_predial') or predio.get('numero_predial')
        if codigo_para_buscar:
            # Buscar en predios principal
            predio_principal = await db.predios.find_one(
                {"codigo_predial_nacional": codigo_para_buscar},
                {"_id": 0, "matricula_inmobiliaria": 1, "r2_registros": 1}
            )
            if predio_principal:
                # Intentar obtener de campo directo
                mat = predio_principal.get('matricula_inmobiliaria')
                # Si no, intentar de r2_registros
                if not mat:
                    r2 = predio_principal.get('r2_registros', [])
                    if r2 and len(r2) > 0:
                        mat = r2[0].get('matricula_inmobiliaria')
                if mat:
                    predio['matricula_inmobiliaria'] = mat
    
    # BUGFIX: Asegurar que visita tenga todos los campos necesarios desde el predio
    # El nombre del reconocedor puede estar en varios lugares
    if not visita.get('nombre_reconocedor'):
        visita['nombre_reconocedor'] = (
            predio.get('nombre_reconocedor') or 
            predio.get('visitado_por_nombre') or 
            predio.get('visitado_por', '')
        )
    
    # La matrícula puede estar en varios lugares
    if not visita.get('jur_matricula'):
        visita['jur_matricula'] = predio.get('matricula_inmobiliaria', '')
    
    # Las firmas pueden estar a nivel del predio o en formato_visita
    if not visita.get('firma_visitado_base64'):
        visita['firma_visitado_base64'] = predio.get('firma_visitado_base64')
    if not visita.get('firma_reconocedor_base64'):
        visita['firma_reconocedor_base64'] = predio.get('firma_reconocedor_base64')
    
    # El nombre del visitado
    if not visita.get('nombre_visitado'):
        visita['nombre_visitado'] = predio.get('nombre_visitado', '')
    
    # Las fotos pueden estar en varios lugares
    if not visita.get('fotos') or len(visita.get('fotos', [])) == 0:
        visita['fotos'] = predio.get('fotos_visita') or predio.get('fotos', [])
    
    # Generar PDF usando el nuevo módulo
    try:
        pdf_content = generar_pdf_visita_completo(
            proyecto=proyecto,
            predio=predio,
            visita=visita,
            propietarios=propietarios,
            construcciones=construcciones,
            current_user_email=current_user.get('email', ''),
            current_user_name=current_user.get('full_name', '')
        )
    except Exception as e:
        logger.error(f"Error generando PDF de visita para {codigo_predial_decoded}: {e}")
        import traceback
        logger.error(traceback.format_exc())
        raise HTTPException(status_code=500, detail=f"Error generando PDF: {str(e)}")
    
    # Guardar en disco (crear directorios padres si no existen)
    pdf_dir = PROYECTOS_ACTUALIZACION_PATH / proyecto_id / "pdfs"
    pdf_dir.mkdir(parents=True, exist_ok=True)
    # Sanitizar código predial para nombre de archivo
    codigo_safe = codigo_predial_decoded.replace('/', '_').replace('\\', '_')
    pdf_filename = f"informe_visita_{codigo_safe}_{datetime.now(COLOMBIA_TZ).strftime('%Y%m%d_%H%M%S')}.pdf"
    pdf_path = pdf_dir / pdf_filename

    with open(pdf_path, 'wb') as f:
        f.write(pdf_content)

    # Devolver como archivo descargable directamente
    return FileResponse(
        path=str(pdf_path),
        filename=pdf_filename,
        media_type="application/pdf"
    )


@api_router.post("/actualizacion/proyectos/{proyecto_id}/descargar-pdfs-visitas")
async def descargar_pdfs_visitas_masivo(
    proyecto_id: str,
    filtro: str = "todos",
    current_user: dict = Depends(get_current_user)
):
    """Descarga masiva de PDFs de visitas en un ZIP. filtro: 'todos' o 'hoy'"""
    if current_user['role'] not in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR]:
        raise HTTPException(status_code=403, detail="Solo coordinadores y administradores pueden descargar PDFs masivos")

    import zipfile
    import tempfile
    import base64

    proyecto = await db.proyectos_actualizacion.find_one({"id": proyecto_id}, {"_id": 0})
    if not proyecto:
        raise HTTPException(status_code=404, detail="Proyecto no encontrado")

    # Filtro base: predios con visita completada
    query = {
        "proyecto_id": proyecto_id,
        "estado_visita": {"$in": ["visitado", "visitado_firmado", "actualizado"]}
    }

    # Si filtro es "hoy", restringir por fecha
    if filtro == "hoy":
        hoy = datetime.now(COLOMBIA_TZ).replace(hour=0, minute=0, second=0, microsecond=0)
        manana = hoy + timedelta(days=1)
        query["visitado_en"] = {"$gte": hoy.isoformat(), "$lt": manana.isoformat()}

    predios = await db.predios_actualizacion.find(query, {"_id": 0}).to_list(length=None)

    if not predios:
        raise HTTPException(status_code=404, detail="No se encontraron predios visitados" + (" hoy" if filtro == "hoy" else ""))

    # Crear ZIP en archivo temporal
    with tempfile.NamedTemporaryFile(delete=False, suffix='.zip') as tmp:
        tmp_path = tmp.name

    try:
        with zipfile.ZipFile(tmp_path, 'w', zipfile.ZIP_DEFLATED) as zipf:
            generados = 0
            errores = []

            for predio in predios:
                codigo = predio.get('codigo_predial') or predio.get('numero_predial', 'sin_codigo')
                try:
                    # Preparar datos de visita (misma lógica que el endpoint individual)
                    visita = predio.get('formato_visita', {}) or predio.get('visita', {})
                    if not visita:
                        visita = {}

                    propietarios = (
                        visita.get('propietarios_visita') or
                        visita.get('propietarios') or
                        predio.get('propietarios_visita') or
                        predio.get('propietarios') or
                        []
                    )
                    construcciones = (
                        visita.get('construcciones_visita') or
                        visita.get('construcciones') or
                        predio.get('construcciones_visita') or
                        predio.get('construcciones') or
                        []
                    )

                    # Obtener codigo_homologado si falta
                    if not predio.get('codigo_homologado'):
                        codigo_para_buscar = predio.get('codigo_predial') or predio.get('numero_predial')
                        if codigo_para_buscar:
                            predio_principal = await db.predios.find_one(
                                {"codigo_predial_nacional": codigo_para_buscar},
                                {"_id": 0, "codigo_homologado": 1}
                            )
                            if predio_principal and predio_principal.get('codigo_homologado'):
                                predio['codigo_homologado'] = predio_principal['codigo_homologado']

                    # Obtener matrícula si falta
                    if not predio.get('matricula_inmobiliaria'):
                        codigo_para_buscar = predio.get('codigo_predial') or predio.get('numero_predial')
                        if codigo_para_buscar:
                            predio_principal = await db.predios.find_one(
                                {"codigo_predial_nacional": codigo_para_buscar},
                                {"_id": 0, "matricula_inmobiliaria": 1, "r2_registros": 1}
                            )
                            if predio_principal:
                                mat = predio_principal.get('matricula_inmobiliaria')
                                if not mat:
                                    r2 = predio_principal.get('r2_registros', [])
                                    if r2 and len(r2) > 0:
                                        mat = r2[0].get('matricula_inmobiliaria')
                                if mat:
                                    predio['matricula_inmobiliaria'] = mat

                    # Completar campos de visita
                    if not visita.get('nombre_reconocedor'):
                        visita['nombre_reconocedor'] = (
                            predio.get('nombre_reconocedor') or
                            predio.get('visitado_por_nombre') or
                            predio.get('visitado_por', '')
                        )
                    if not visita.get('jur_matricula'):
                        visita['jur_matricula'] = predio.get('matricula_inmobiliaria', '')
                    if not visita.get('firma_visitado_base64'):
                        visita['firma_visitado_base64'] = predio.get('firma_visitado_base64')
                    if not visita.get('firma_reconocedor_base64'):
                        visita['firma_reconocedor_base64'] = predio.get('firma_reconocedor_base64')
                    if not visita.get('nombre_visitado'):
                        visita['nombre_visitado'] = predio.get('nombre_visitado', '')
                    if not visita.get('fotos') or len(visita.get('fotos', [])) == 0:
                        visita['fotos'] = predio.get('fotos_visita') or predio.get('fotos', [])

                    pdf_content = generar_pdf_visita_completo(
                        proyecto=proyecto,
                        predio=predio,
                        visita=visita,
                        propietarios=propietarios,
                        construcciones=construcciones,
                        current_user_email=current_user.get('email', ''),
                        current_user_name=current_user.get('full_name', '')
                    )

                    codigo_safe = codigo.replace('/', '_').replace('\\', '_')
                    pdf_filename = f"informe_visita_{codigo_safe}.pdf"
                    zipf.writestr(pdf_filename, pdf_content)
                    generados += 1

                except Exception as e:
                    import traceback
                    logger.error(f"Error generando PDF para predio {codigo}: {e}\n{traceback.format_exc()}")
                    errores.append(codigo)

        fecha_str = datetime.now(COLOMBIA_TZ).strftime('%Y%m%d_%H%M%S')
        zip_filename = f"visitas_{proyecto.get('municipio', 'proyecto')}_{filtro}_{fecha_str}.zip"

        logger.info(f"ZIP de visitas generado: {generados} PDFs, {len(errores)} errores")

        from starlette.background import BackgroundTask
        cleanup = BackgroundTask(os.unlink, tmp_path)
        return FileResponse(
            path=tmp_path,
            filename=zip_filename,
            media_type="application/zip",
            headers={"X-Generados": str(generados), "X-Errores": str(len(errores))},
            background=cleanup
        )
    except Exception as e:
        if os.path.exists(tmp_path):
            os.unlink(tmp_path)
        raise HTTPException(status_code=500, detail=f"Error generando ZIP: {str(e)}")


@api_router.post("/actualizacion/proyectos/{proyecto_id}/upload-info-alfanumerica")
async def upload_info_alfanumerica_proyecto(
    proyecto_id: str,
    file: UploadFile = File(...),
    current_user: dict = Depends(get_current_user)
):
    """Sube un archivo de Información Alfanumérica (R1/R2 Excel) para un proyecto de actualización y lo procesa"""
    if current_user['role'] not in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR]:
        raise HTTPException(status_code=403, detail="No tiene permiso para cargar Información Alfanumérica")
    
    proyecto = await db.proyectos_actualizacion.find_one({"id": proyecto_id}, {"_id": 0})
    if not proyecto:
        raise HTTPException(status_code=404, detail="Proyecto no encontrado")
    
    if proyecto["estado"] == ProyectoActualizacionEstado.ARCHIVADO:
        raise HTTPException(status_code=400, detail="No se pueden cargar archivos a proyectos archivados")
    
    if not file.filename.endswith(('.xlsx', '.xls')):
        raise HTTPException(status_code=400, detail="El archivo debe ser un Excel (.xlsx o .xls)")
    
    proyecto_dir = PROYECTOS_ACTUALIZACION_PATH / proyecto_id
    proyecto_dir.mkdir(exist_ok=True)
    
    # Guardar archivo
    ext = Path(file.filename).suffix
    file_path = proyecto_dir / f"info_alfanumerica_{datetime.now(COLOMBIA_TZ).strftime('%Y%m%d_%H%M%S')}{ext}"
    
    try:
        with open(file_path, "wb") as buffer:
            content = await file.read()
            buffer.write(content)
        
        # Procesar Excel R1/R2
        registros_procesados = await procesar_r1r2_actualizacion(proyecto_id, str(file_path), proyecto["municipio"])
        
        return {
            "message": f"Información Alfanumérica cargada y procesada ({registros_procesados} registros)",
            "archivo": str(file_path),
            "nombre_archivo": file.filename,
            "registros_procesados": registros_procesados
        }
        
    except Exception as e:
        if file_path.exists():
            file_path.unlink()
        raise HTTPException(status_code=500, detail=f"Error al cargar el archivo: {str(e)}")


async def procesar_r1r2_actualizacion(proyecto_id: str, file_path: str, municipio: str):
    """Procesa el Excel R1/R2 y guarda los predios en la colección del proyecto.
    Usa upsert para preservar datos de trabajo de campo (visitas, fotos, GPS, historial)."""
    import pandas as pd

    # Leer Excel
    try:
        # Intentar leer con openpyxl (xlsx)
        df_r1 = pd.read_excel(file_path, sheet_name=0, engine='openpyxl')  # Primera hoja (R1)
        try:
            df_r2 = pd.read_excel(file_path, sheet_name=1, engine='openpyxl')  # Segunda hoja (R2)
        except:
            df_r2 = pd.DataFrame()  # R2 opcional
    except:
        # Fallback a xlrd (xls)
        df_r1 = pd.read_excel(file_path, sheet_name=0, engine='xlrd')
        try:
            df_r2 = pd.read_excel(file_path, sheet_name=1, engine='xlrd')
        except:
            df_r2 = pd.DataFrame()

    # Normalizar nombres de columnas
    df_r1.columns = [str(c).strip().upper() for c in df_r1.columns]
    if len(df_r2) > 0:
        df_r2.columns = [str(c).strip().upper() for c in df_r2.columns]

    # Campos de trabajo de campo que NUNCA deben sobrescribirse al recargar el Excel
    campos_campo = {
        'estado_visita', 'observaciones_campo', 'ubicacion_gps',
        'visitado_por', 'visitado_en', 'visitado_por_nombre',
        'visita', 'datos_notificacion', 'fotos', 'sin_cambios',
        'actualizado_por', 'actualizado_en', 'actualizado_por_nombre',
        'historial_cambios', 'zonas_fisicas', 'zonas_terreno', 'construcciones',
        'es_ph', 'datos_ph', 'datos_condominio'
    }

    # Recopilar códigos prediales existentes para saber cuáles preservar
    existing_codigos = set()
    cursor = db.predios_actualizacion.find(
        {"proyecto_id": proyecto_id},
        {"codigo_predial": 1, "_id": 0}
    )
    async for doc in cursor:
        if doc.get("codigo_predial"):
            existing_codigos.add(doc["codigo_predial"])

    registros = 0

    # Mapear columnas R1 a campos estándar (incluye variantes de nombres de columnas)
    col_mapping_r1 = {
        # Código predial
        'CODIGO_PREDIAL_NACIONAL': 'codigo_predial',
        'CODIGO PREDIAL NACIONAL': 'codigo_predial',
        'CODIGO_PREDIAL': 'codigo_predial',
        'CODIGO PREDIAL': 'codigo_predial',
        'CODIGO': 'codigo_predial',
        # Número predial
        'NUMERO_DEL_PREDIO': 'numero_predial',
        'NUMERO DEL PREDIO': 'numero_predial',
        'NUMERO_PREDIAL': 'numero_predial',
        'NUMERO PREDIAL': 'numero_predial',
        # Datos básicos
        'DIRECCION': 'direccion',
        'DESTINO_ECONOMICO': 'destino_economico',
        'DESTINO ECONOMICO': 'destino_economico',
        'AREA_TERRENO': 'area_terreno',
        'AREA TERRENO': 'area_terreno',
        'AREA_CONSTRUIDA': 'area_construida',
        'AREA CONSTRUIDA': 'area_construida',
        'AVALUO': 'avaluo_catastral',
        'AVALUO_CATASTRAL': 'avaluo_catastral',
        'AVALUO CATASTRAL': 'avaluo_catastral',
        'VIGENCIA': 'vigencia',
        'ESTRATO': 'estrato',
        'TIPO_PREDIO': 'tipo_predio',
        'TIPO PREDIO': 'tipo_predio',
        'COMUNA': 'comuna',
        # Código Homologado
        'CODIGO_HOMOLOGADO': 'codigo_homologado',
        'CODIGO HOMOLOGADO': 'codigo_homologado',
        # Matrícula inmobiliaria
        'MATRICULA_INMOBILIARIA': 'matricula_inmobiliaria',
        'MATRICULA INMOBILIARIA': 'matricula_inmobiliaria',
        'MATRICULA': 'matricula_inmobiliaria',
        # Propietario (del R1)
        'NOMBRE': 'propietario_nombre',
        'TIPO_DOCUMENTO': 'propietario_tipo_doc',
        'TIPO DOCUMENTO': 'propietario_tipo_doc',
        'NUMERO_DOCUMENTO': 'propietario_documento',
        'NUMERO DOCUMENTO': 'propietario_documento',
        'ESTADO_CIVIL': 'propietario_estado_civil',
        'ESTADO CIVIL': 'propietario_estado_civil'
    }

    # Agrupar propietarios por código predial
    predios_dict = {}

    # Procesar R1
    for _, row in df_r1.iterrows():
        predio_data = {
            "proyecto_id": proyecto_id,
            "municipio": municipio,
            "created_at": datetime.now(COLOMBIA_TZ),
            "propietarios": []
        }

        propietario = {}
        codigo_predial = None

        for col, field in col_mapping_r1.items():
            if col in df_r1.columns:
                val = row[col]
                if pd.notna(val):
                    if field in ['area_terreno', 'area_construida', 'avaluo_catastral']:
                        try:
                            predio_data[field] = float(val)
                        except:
                            predio_data[field] = None
                    elif field.startswith('propietario_'):
                        # Datos del propietario - usar nombres consistentes
                        if field == 'propietario_nombre':
                            propietario['nombre_propietario'] = str(val).strip()
                        elif field == 'propietario_tipo_doc':
                            propietario['tipo_documento'] = str(val).strip()
                        elif field == 'propietario_documento':
                            propietario['numero_documento'] = str(val).strip()
                        elif field == 'propietario_estado_civil':
                            propietario['estado_civil'] = str(val).strip()
                    elif field == 'codigo_predial':
                        codigo_predial = str(val).strip()
                        predio_data[field] = codigo_predial
                    else:
                        predio_data[field] = str(val).strip()

        # Solo procesar si tiene código predial
        if codigo_predial:
            if codigo_predial not in predios_dict:
                predios_dict[codigo_predial] = predio_data

            # Agregar propietario si tiene nombre
            if propietario.get('nombre_propietario'):
                predios_dict[codigo_predial]['propietarios'].append(propietario)

    # Códigos en el nuevo Excel
    codigos_nuevos = set(predios_dict.keys())

    # Guardar predios usando upsert para preservar datos de campo existentes
    for codigo, predio in predios_dict.items():
        # Solo actualizar campos alfanuméricos del Excel, nunca datos de campo
        campos_alfanumericos = {k: v for k, v in predio.items() if k not in campos_campo}
        campos_alfanumericos["updated_at"] = datetime.now(COLOMBIA_TZ)

        if codigo in existing_codigos:
            # Predio existente: actualizar solo datos alfanuméricos, preservar datos de campo
            await db.predios_actualizacion.update_one(
                {"proyecto_id": proyecto_id, "codigo_predial": codigo},
                {"$set": campos_alfanumericos}
            )
        else:
            # Predio nuevo: insertar completo
            await db.predios_actualizacion.insert_one(predio)
        registros += 1

    # Marcar predios que ya no están en el Excel (no eliminarlos para preservar trabajo de campo)
    codigos_eliminados = existing_codigos - codigos_nuevos
    if codigos_eliminados:
        await db.predios_actualizacion.update_many(
            {"proyecto_id": proyecto_id, "codigo_predial": {"$in": list(codigos_eliminados)}},
            {"$set": {
                "excluido_del_excel": True,
                "excluido_en": datetime.now(COLOMBIA_TZ),
                "updated_at": datetime.now(COLOMBIA_TZ)
            }}
        )
    
    # Actualizar proyecto
    await db.proyectos_actualizacion.update_one(
        {"id": proyecto_id},
        {"$set": {
            "info_alfanumerica_archivo": file_path,
            "info_alfanumerica_cargado_en": datetime.now(COLOMBIA_TZ),
            "info_alfanumerica_total_registros": registros,
            "updated_at": datetime.now(COLOMBIA_TZ)
        }}
    )
    
    return registros


@api_router.get("/actualizacion/proyectos/{proyecto_id}/descargar-base-grafica")
async def descargar_base_grafica_proyecto(
    proyecto_id: str,
    token: str = Query(None, description="JWT token para autenticación vía query param")
):
    """Descarga el archivo de Base Gráfica de un proyecto"""
    # Autenticación via query param para permitir window.open
    if not token:
        raise HTTPException(status_code=401, detail="Token requerido")
    
    try:
        payload = decode_token(token)
        current_user = await db.users.find_one({"id": payload["user_id"]}, {"_id": 0})
        if not current_user:
            raise HTTPException(status_code=401, detail="Usuario no encontrado")
    except Exception:
        raise HTTPException(status_code=401, detail="Token inválido")
    
    if current_user['role'] not in [UserRole.ADMINISTRADOR, UserRole.COORDINADOR, UserRole.GESTOR]:
        raise HTTPException(status_code=403, detail="No tiene permiso para descargar archivos")
    
    proyecto = await db.proyectos_actualizacion.find_one({"id": proyecto_id}, {"_id": 0})
    if not proyecto:
        raise HTTPException(status_code=404, detail="Proyecto no encontrado")
    
    if not proyecto.get("base_grafica_archivo"):
        raise HTTPException(status_code=404, detail="No hay Base Gráfica cargada")
    
    file_path = Path(proyecto["base_grafica_archivo"])
    if not file_path.exists():
        raise HTTPException(status_code=404, detail="Archivo no encontrado en el servidor")
    
    return FileResponse(
        file_path,
        media_type="application/zip",
        filename=file_path.name,
        headers={"Content-Disposition": f'attachment; filename="{file_path.name}"'}
    )

@api_router.get("/actualizacion/proyectos/{proyecto_id}/descargar-info-alfanumerica")
async def descargar_info_alfanumerica_proyecto(
    proyecto_id: str,
    token: str = Query(None, description="JWT token para autenticación vía query param")
):
    """Descarga el archivo de Información Alfanumérica (R1/R2) de un proyecto"""
