@api_router.put("/solicitudes-mutacion/{solicitud_id}")
async def actualizar_solicitud_mutacion(
    solicitud_id: str,
    data: SolicitudMutacionCreate,
    current_user: dict = Depends(get_current_user)
):
    """
    Actualiza una solicitud de mutación existente
    """
    try:
        solicitud = await db.solicitudes_mutacion.find_one({"id": solicitud_id})
        
        if not solicitud:
            raise HTTPException(status_code=404, detail="Solicitud no encontrada")
        
        # Solo se puede editar en estado borrador o devuelto
        if solicitud['estado'] not in [MutacionEstado.BORRADOR, MutacionEstado.DEVUELTO]:
            raise HTTPException(status_code=400, detail="No se puede editar una solicitud en este estado")
        
        update_data = {
            "subtipo": data.subtipo,
            "solicitante": data.solicitante,
            "predios_cancelados": data.predios_cancelados,
            "predios_inscritos": data.predios_inscritos,
            "observaciones": data.observaciones,
            "predio_id": data.predio_id,
            "propietarios_anteriores": [{**p, "numero_documento": formatear_documento(p.get("numero_documento", "")), "documento": formatear_documento(p.get("documento", p.get("numero_documento", "")))} for p in data.propietarios_anteriores] if data.propietarios_anteriores else data.propietarios_anteriores,
            "propietarios_nuevos": [{**p, "numero_documento": formatear_documento(p.get("numero_documento", "")), "documento": formatear_documento(p.get("documento", p.get("numero_documento", "")))} for p in data.propietarios_nuevos] if data.propietarios_nuevos else data.propietarios_nuevos,
            "updated_at": datetime.now(COLOMBIA_TZ).isoformat()
        }
        
        await db.solicitudes_mutacion.update_one(
            {"id": solicitud_id},
            {"$set": update_data}
        )
        
        return {
            "success": True,
            "mensaje": "Solicitud actualizada"
        }
        
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"Error actualizando solicitud: {str(e)}")
        raise HTTPException(status_code=500, detail=f"Error: {str(e)}")


@api_router.post("/solicitudes-mutacion/{solicitud_id}/accion")
async def ejecutar_accion_solicitud(
    solicitud_id: str,
    data: SolicitudMutacionAccion,
    current_user: dict = Depends(get_current_user)
):
    """
    Ejecuta una acción sobre una solicitud de mutación
    Acciones: asignar_apoyo, enviar_aprobacion, aprobar, devolver, rechazar, finalizar_cartografia
    """
    try:
        solicitud = await db.solicitudes_mutacion.find_one({"id": solicitud_id})
        
        if not solicitud:
            raise HTTPException(status_code=404, detail="Solicitud no encontrada")
        
        accion = data.accion
        nuevo_estado = solicitud['estado']
        historial_entry = {
            "fecha": datetime.now(COLOMBIA_TZ).isoformat(),
            "accion": accion,
            "usuario_id": current_user['id'],
            "usuario_nombre": current_user['full_name'],
            "observaciones": data.observaciones or ""
        }
        
        update_data = {}
        notificaciones = []
        
        # ===== ASIGNAR A APOYO =====
        if accion == "asignar_apoyo":
            if not data.gestor_apoyo_id:
                raise HTTPException(status_code=400, detail="Debe seleccionar un gestor de apoyo")
            
            # Obtener nombre del gestor de apoyo
            gestor_apoyo = await db.users.find_one({"id": data.gestor_apoyo_id})
            if not gestor_apoyo:
                raise HTTPException(status_code=404, detail="Gestor de apoyo no encontrado")
            
            nuevo_estado = MutacionEstado.PENDIENTE_CARTOGRAFIA
            update_data = {
                "gestor_apoyo_id": data.gestor_apoyo_id,
                "gestor_apoyo_nombre": gestor_apoyo['full_name'],
                "gestor_apoyo_completado": False
            }
            
            # Notificar al gestor de apoyo
            notificaciones.append({
                "usuario_id": data.gestor_apoyo_id,
                "titulo": "📋 Nueva asignación de cartografía",
                "mensaje": f"Te han asignado la cartografía para la solicitud {solicitud['tipo']} - {solicitud['radicado']}",
                "tipo": "info",
                "enlace": "/dashboard/pendientes?tab=mis-asignaciones"
            })
        
        # ===== FINALIZAR CARTOGRAFÍA (Gestor de apoyo) =====
        elif accion == "finalizar_cartografia":
            # Verificar que sea el gestor de apoyo asignado
            if solicitud.get('gestor_apoyo_id') != current_user['id']:
                raise HTTPException(status_code=403, detail="Solo el gestor de apoyo asignado puede finalizar")
            
            nuevo_estado = MutacionEstado.PENDIENTE_APROBACION
            update_data = {
                "gestor_apoyo_completado": True,
                "gestor_apoyo_fecha_completado": datetime.now(COLOMBIA_TZ).isoformat()
            }
            
            # Notificar a aprobadores
            aprobadores = await db.users.find({
                "$or": [
                    {"role": {"$in": [UserRole.COORDINADOR, UserRole.ADMINISTRADOR]}},
                    {"permissions": Permission.APPROVE_CHANGES}
                ]
            }).to_list(100)
            
            for aprobador in aprobadores:
                notificaciones.append({
                    "usuario_id": aprobador['id'],
                    "titulo": f"📋 Solicitud {solicitud['tipo']} lista para aprobación",
                    "mensaje": f"La solicitud {solicitud['radicado']} está lista para aprobar. Cartografía completada por {current_user['full_name']}.",
                    "tipo": "warning",
                    "enlace": "/dashboard/pendientes?tab=mutaciones"
                })
            
            # Notificar al gestor original
            notificaciones.append({
                "usuario_id": solicitud['creado_por_id'],
                "titulo": "📋 Cartografía completada",
                "mensaje": f"El gestor de apoyo {current_user['full_name']} ha completado la cartografía de tu solicitud {solicitud['radicado']}. Enviada a aprobación.",
                "tipo": "success",
                "enlace": "/dashboard/pendientes?tab=mutaciones"
            })
        
        # ===== ENVIAR A APROBACIÓN (sin gestor de apoyo) =====
        elif accion == "enviar_aprobacion":
            nuevo_estado = MutacionEstado.PENDIENTE_APROBACION
            
            # Notificar a aprobadores
            aprobadores = await db.users.find({
                "$or": [
                    {"role": {"$in": [UserRole.COORDINADOR, UserRole.ADMINISTRADOR]}},
                    {"permissions": Permission.APPROVE_CHANGES}
                ]
            }).to_list(100)
            
            for aprobador in aprobadores:
                notificaciones.append({
                    "usuario_id": aprobador['id'],
                    "titulo": f"📋 Nueva solicitud {solicitud['tipo']} pendiente",
                    "mensaje": f"La solicitud {solicitud['radicado']} requiere aprobación. Creada por {current_user['full_name']}.",
                    "tipo": "warning",
                    "enlace": "/dashboard/pendientes?tab=mutaciones"
                })
        
        # ===== APROBAR =====
        elif accion == "aprobar":
            # Verificar permisos
            puede_aprobar = (
                current_user['role'] in [UserRole.COORDINADOR, UserRole.ADMINISTRADOR] or
                Permission.APPROVE_CHANGES in current_user.get('permissions', [])
            )
            if not puede_aprobar:
                raise HTTPException(status_code=403, detail="No tiene permisos para aprobar")
            
            nuevo_estado = MutacionEstado.APROBADO
            update_data = {
                "aprobado_por_id": current_user['id'],
                "aprobado_por_nombre": current_user['full_name'],
                "fecha_aprobacion": datetime.now(COLOMBIA_TZ).isoformat()
            }
            
            # ========================================
            # GENERAR PDF Y APLICAR CAMBIOS SEGÚN TIPO
            # ========================================
            tipo_mutacion = solicitud.get('tipo', 'M1')
            pdf_result = None
            
            try:
                if tipo_mutacion == "M2":
                    # Generar resolución M2 (Desenglobe)
                    pdf_result = await _generar_resolucion_m2_interno(solicitud, current_user)
                    
                elif tipo_mutacion == "M3":
                    # Generar resolución M3 (Cambio destino / Incorporación construcción)
                    pdf_result = await _generar_resolucion_m3_interno(solicitud, current_user)
                
                elif tipo_mutacion == "M4":
                    # Generar resolución M4 (Revisión de Avalúo / Autoestimación)
                    pdf_result = await _generar_resolucion_m4_interno(solicitud, current_user)
                
                elif tipo_mutacion == "M5":
                    # Generar resolución M5 (Cancelación / Inscripción de predio)
                    pdf_result = await _generar_resolucion_m5_interno(solicitud, current_user)
                
                elif tipo_mutacion in ["M6", "RECTIFICACION_AREA"]:
                    # Generar resolución Rectificación de Área
                    pdf_result = await _generar_resolucion_m6_interno(solicitud, current_user)
                
                elif tipo_mutacion in ["COMP", "COMPLEMENTACION"]:
                    # Generar resolución Complementación de Información
                    pdf_result = await _generar_resolucion_complementacion_interno(solicitud, current_user)
                    
                else:
                    # M1 - usar lógica existente
                    # Crear documento de cambio compatible con generar_resolucion_final
                    cambio_doc = {
                        "id": solicitud['id'],
                        "tipo_cambio": "modificacion",
                        "predio_id": solicitud.get('predio_id'),
                        "datos_propuestos": {
                            "propietarios": solicitud.get('propietarios_nuevos', []),
                            "municipio": solicitud.get('municipio', ''),
                            "codigo_predial_nacional": solicitud.get('codigo_predial', ''),
                        },
                        "radicado": solicitud.get('radicado'),
                        "radicado_numero": solicitud.get('radicado'),
                        "justificacion": solicitud.get('observaciones'),
                        "propuesto_por": solicitud.get('creado_por_id'),
                        "texto_considerando": solicitud.get('texto_considerando', ''),
                    }
                    pdf_result = await generar_resolucion_final(cambio_doc, current_user)

                if pdf_result:
                    update_data["resolucion_id"] = pdf_result.get("id")
                    update_data["pdf_url"] = pdf_result.get("pdf_url") or pdf_result.get("pdf_path")
                    update_data["numero_resolucion"] = pdf_result.get("numero_resolucion")
                    # Trámite completado exitosamente → FINALIZADO
                    nuevo_estado = MutacionEstado.FINALIZADO
                    update_data["fecha_finalizacion"] = datetime.now(COLOMBIA_TZ).isoformat()

            except Exception as pdf_error:
                logging.error(f"Error generando PDF para {tipo_mutacion}: {str(pdf_error)}")
                # Si falla el PDF, queda en APROBADO (no FINALIZADO) para reintentar
                update_data["error_pdf"] = str(pdf_error)
            
            # Notificar al gestor original
            notificaciones.append({
                "usuario_id": solicitud['creado_por_id'],
                "titulo": f"✅ Solicitud {solicitud['tipo']} aprobada",
                "mensaje": f"Tu solicitud {solicitud['radicado']} ha sido aprobada por {current_user['full_name']}.",
                "tipo": "success",
                "enlace": "/dashboard/mutaciones"
            })
        
        # ===== DEVOLVER =====
        elif accion == "devolver":
            puede_aprobar = (
                current_user['role'] in [UserRole.COORDINADOR, UserRole.ADMINISTRADOR] or
                Permission.APPROVE_CHANGES in current_user.get('permissions', [])
            )
            if not puede_aprobar:
                raise HTTPException(status_code=403, detail="No tiene permisos para devolver")
            
            nuevo_estado = MutacionEstado.DEVUELTO
            
            # Notificar al gestor original
            notificaciones.append({
                "usuario_id": solicitud['creado_por_id'],
                "titulo": f"⚠️ Solicitud {solicitud['tipo']} devuelta",
                "mensaje": f"Tu solicitud {solicitud['radicado']} ha sido devuelta para correcciones. Observaciones: {data.observaciones or 'Sin observaciones'}",
                "tipo": "warning",
                "enlace": "/dashboard/mutaciones"
            })
        
        # ===== RECHAZAR =====
        elif accion == "rechazar":
            puede_aprobar = (
                current_user['role'] in [UserRole.COORDINADOR, UserRole.ADMINISTRADOR] or
                Permission.APPROVE_CHANGES in current_user.get('permissions', [])
            )
            if not puede_aprobar:
                raise HTTPException(status_code=403, detail="No tiene permisos para rechazar")
            
            nuevo_estado = MutacionEstado.RECHAZADO
            
            # Notificar al gestor original
            notificaciones.append({
                "usuario_id": solicitud['creado_por_id'],
                "titulo": f"❌ Solicitud {solicitud['tipo']} rechazada",
                "mensaje": f"Tu solicitud {solicitud['radicado']} ha sido rechazada. Motivo: {data.observaciones or 'Sin motivo especificado'}",
                "tipo": "error",
                "enlace": "/dashboard/mutaciones"
            })
        
        else:
            raise HTTPException(status_code=400, detail=f"Acción no válida: {accion}")
        
        # Actualizar solicitud
        update_data["estado"] = nuevo_estado
        await db.solicitudes_mutacion.update_one(
            {"id": solicitud_id},
            {
                "$set": update_data,
                "$push": {"historial": historial_entry}
            }
        )
        
        # Crear notificaciones
        for notif in notificaciones:
            await crear_notificacion(
                usuario_id=notif['usuario_id'],
                titulo=notif['titulo'],
                mensaje=notif['mensaje'],
                tipo=notif['tipo'],
                enlace=notif['enlace'],
                enviar_email=False
            )
        
        # Construir respuesta
        response = {
            "success": True,
            "nuevo_estado": nuevo_estado,
            "mensaje": f"Acción '{accion}' ejecutada exitosamente"
        }
        
        # Agregar información del PDF si fue aprobación
        if accion == "aprobar" and update_data.get("pdf_url"):
            response["pdf_url"] = update_data.get("pdf_url")
            response["numero_resolucion"] = update_data.get("numero_resolucion")
        
        return response
        
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"Error ejecutando acción: {str(e)}")
        import traceback
        traceback.print_exc()
        raise HTTPException(status_code=500, detail=f"Error: {str(e)}")


# ============================================================
# RADICADOS MÚLTIPLES - Agrupar varias mutaciones en un radicado
# ============================================================

@api_router.get("/radicados-multiples")
async def listar_radicados_multiples(
    municipio: Optional[str] = None,
    estado: Optional[str] = None,
    limit: int = 50,
    skip: int = 0,
    current_user: dict = Depends(get_current_user)
):
    """
    Lista radicados con múltiples mutaciones
    """
    try:
        query = {}
        
        if municipio:
            query["municipio"] = municipio
        if estado:
            query["estado"] = estado
            
        # Si es usuario empresa, filtrar por municipios asignados
        if current_user['role'] == UserRole.EMPRESA:
            municipios_asignados = current_user.get('municipios_asignados', [])
            if municipios_asignados:
                query["municipio"] = {"$in": municipios_asignados}
        
        radicados = await db.radicados_multiples.find(
            query,
            {"_id": 0}
        ).sort("fecha_creacion", -1).skip(skip).limit(limit).to_list(limit)
        
        total = await db.radicados_multiples.count_documents(query)
        
        return {
            "success": True,
            "radicados": radicados,
            "total": total
        }
        
    except Exception as e:
        logging.error(f"Error listando radicados múltiples: {str(e)}")
        raise HTTPException(status_code=500, detail=f"Error: {str(e)}")


@api_router.post("/radicados-multiples")
async def crear_radicado_multiple(
    data: RadicadoMultipleCreate,
    current_user: dict = Depends(get_current_user)
):
    """
    Crea un nuevo radicado para agrupar múltiples mutaciones
    """
    try:
        # Generar número de radicado
        anio = datetime.now().year
        count = await db.radicados_multiples.count_documents({}) + 1
        numero_radicado = f"MULT-{data.municipio}-{count:05d}-{anio}"
        
        radicado_id = str(uuid.uuid4())
        
        radicado = {
            "id": radicado_id,
            "numero": numero_radicado,
            "municipio": data.municipio,
            "solicitante": data.solicitante,
            "estado": "EN_PROCESO",
            "mutaciones": [],
            "fecha_creacion": datetime.now(COLOMBIA_TZ).isoformat(),
            "creado_por_id": current_user['id'],
            "creado_por_nombre": current_user['full_name'],
            "historial": [{
                "fecha": datetime.now(COLOMBIA_TZ).isoformat(),
                "accion": "creado",
                "usuario_id": current_user['id'],
                "usuario_nombre": current_user['full_name']
            }]
        }
        
        await db.radicados_multiples.insert_one(radicado)
        
        # Quitar _id antes de retornar
        radicado.pop('_id', None)
        
        return {
            "success": True,
            "radicado": radicado,
            "message": f"Radicado {numero_radicado} creado exitosamente"
        }
        
    except Exception as e:
        logging.error(f"Error creando radicado múltiple: {str(e)}")
        raise HTTPException(status_code=500, detail=f"Error: {str(e)}")


